import Link from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _not_found = {title: "Unknown", jsx: <><h2 id="magic-wondrous-not_found-error">Error</h2>
<p>Unable to find the requested wondrous item.</p>
</>};
const _anacondas_coils = {title: "Anaconda's Coils", jsx: <><h2 id="magic-wondrous-anacondas_coils-anacondas-coils">Anaconda's Coils</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 208</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 18,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This snakeskin belt's buckle is shaped like a serpent's head. The wearer gains a +2 enhancement bonus to Strength and a +2 competence bonus on <Link to="/rule/grapple">grapple</Link> combat maneuver checks. Treat the enhancement bonus to Strength as <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn. In addition, the belt grants the wearer the <Link to="/umr/constrict">constrict</Link> ability for 1d6 points of damage plus the wearer's Strength modifier.</p>
<h3 id="magic-wondrous-anacondas_coils-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 9,250 gp</p>
</>};
const _anchoring_belt = {title: "Anchoring Belt", jsx: <><h2 id="magic-wondrous-anchoring_belt-anchoring-belt">Anchoring Belt</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 147</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> belt; <strong>Price</strong> 60,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This belt looks like nothing more than iron chains connecting large pieces of slate. It grants its wearer a +5 inherent bonus to <Link to="/rule/combat_maneuver">combat maneuver</Link> defense against bull rush, drag, grapple, overrun, reposition, and trip combat maneuvers and a +5 inherent bonus on saving throws against any effect that attempts to move the wearer with physical force or energy. Furthermore, if the wearer is a mythic creature and targeted by an effect that would teleport her, she can choose whether or not she wishes to be teleported.</p>
<p>As a standard action, the wearer can expend one use of mythic power to create a 30-foot-radius aura that affects all enemy creatures within it as though they were subject to a <em>dimensional anchor</em> spell. This aura lasts for a number of rounds equal to the wearer's mythic tier.</p>
<h3 id="magic-wondrous-anchoring_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>; <strong>Cost</strong> 30,000 gp</p>
</>};
const _aquatic_cummerbund = {title: "Aquatic Cummerbund", jsx: <><h2 id="magic-wondrous-aquatic_cummerbund-aquatic-cummerbund">Aquatic Cummerbund</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 208</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 2,600 gp; <strong>Weight</strong> -</p>
<p>Long believed to have been <Link to="/race/gnome">gnome</Link> in origin, this stately cummerbund features a number of dancing dolphins embroidered on its deep blue material. The cummerbund grants its wearer a +4 competence bonus on <Link to="/skill/swim">Swim</Link> checks, and allows her to take 10 on such checks even if distracted or endangered.</p>
<h3 id="magic-wondrous-aquatic_cummerbund-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/touch_of_the_sea">touch of the sea</Link>; <strong>Cost</strong> 1,300 gp</p>
</>};
const _belt_of_dwarvenkind = {title: "Belt of Dwarvenkind", jsx: <><h2 id="magic-wondrous-belt_of_dwarvenkind-belt-of-dwarvenkind">Belt of Dwarvenkind</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 208</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 501</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 12th<br/><strong>Slot</strong> belt; <strong>Price</strong> 14,900 gp; <strong>Weight</strong> 1 lb.</p>
<p>This belt gives the wearer a +4 competence bonus on Charisma checks and Charisma-based skill checks as they relate to dealing with dwarves, a +2 competence bonus on similar checks when dealing with gnomes and halflings, and a -2 competence penalty on similar checks when dealing with anyone else. The wearer can understand, speak, and read Dwarven. If the wearer is not a <Link to="/race/dwarf">dwarf</Link>, he gains 60-foot darkvision, dwarven stonecunning, a +2 enhancement bonus to Constitution, and a +2 resistance bonus on saves against poison, spells, and spell-like effects.</p>
<h3 id="magic-wondrous-belt_of_dwarvenkind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/tongues">tongues</Link>, creator must be a dwarf; <strong>Cost</strong> 7,450 gp</p>
</>};
const _belt_of_equilibrium = {title: "Belt of Equilibrium", jsx: <><h2 id="magic-wondrous-belt_of_equilibrium-belt-of-equilibrium">Belt of Equilibrium</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 208</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> belt; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>As long as this belt's wearer doesn't move more than 5 feet during her turn, she ignores the penalties for being <Link to="/misc/fatigued">fatigued</Link>, <Link to="/misc/shaken">shaken</Link>, or <Link to="/misc/sickened">sickened</Link> until the end of her next turn or until she moves more than 5 feet, whichever occurs first. While she does not take any of the penalties of those conditions, she is considered to be under the effect of those conditions until they end or are removed.</p>
<h3 id="magic-wondrous-belt_of_equilibrium-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _belt_of_fallen_heroes = {title: "Belt of Fallen Heroes", jsx: <><h2 id="magic-wondrous-belt_of_fallen_heroes-belt-of-fallen-heroes">Belt of Fallen Heroes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 208</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> belt; <strong>Price</strong> 21,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This large brass belt has three panels depicting scenes of battle. Once per day on command, the wearer can summon the spirit of a hero of one of the depicted battles. This spirit acts as a <em>spiritual ally,</em> though unlike the force created by that spell, the summoned hero is not entirely mindless. Whether or not the summoned hero is active, it attempts to guide its wearer to victory via telepathic warning and advice, granting its user a +1 insight bonus on all saving throws.</p>
<h3 id="magic-wondrous-belt_of_fallen_heroes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divine_favor">divine favor</Link>, <Link to="/spell/spiritual_ally">spiritual ally</Link>; <strong>Cost</strong> 10,500 gp</p>
</>};
const _belt_of_foraging = {title: "Belt of Foraging", jsx: <><h2 id="magic-wondrous-belt_of_foraging-belt-of-foraging">Belt of Foraging</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 208</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 78</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> belt; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This belt allows its wearer to easily forage while in the wilderness. As long as the wearer of this belt has at least 1 rank in <Link to="/skill/survival">Survival</Link>, she need not make a check to get along in the wild; she always succeeds at that Survival check as long as she moves at half her overland speed. She can still choose to make that check to provide food and water for one other creature for every 2 points by which her result exceeds DC 10. Furthermore, she can instead make a DC 20 Survival check to get along in the wild while moving at full speed instead of half speed. While doing so, she can provide food and water for one other creature for every 2 points by which his check result exceeds 20.</p>
<h3 id="magic-wondrous-belt_of_foraging-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_animals_or_plants">detect animals or plants</Link>, creator must have 1 rank in Survival; <strong>Cost</strong> 3,000 gp</p>
</>};
const _belt_of_giant_strength = {title: "Belt of Giant Strength", jsx: <><h2 id="magic-wondrous-belt_of_giant_strength-belt-of-giant-strength">Belt of Giant Strength</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 208</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 502</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 4,000 gp (+2), 16,000 gp (+4), 36,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This belt is a thick leather affair, often decorated with huge metal buckles. The belt grants the wearer an enhancement bonus to Strength of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-belt_of_giant_strength-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 2,000 gp (+2), 8,000 gp (+4), 18,000 gp (+6)</p>
</>};
const _belt_of_impossible_action_vudrani = {title: "Belt of Impossible Action (Vudrani)", jsx: <><h2 id="magic-wondrous-belt_of_impossible_action_vudrani-belt-of-impossible-action-vudrani">Belt of Impossible Action (Vudrani)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 229</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> waist; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This gem-studded belt is woven of several different colors of silk. The wearer can perform <Link to="/rule/combat_maneuvers">combat maneuvers</Link> against foes that would normally be immune due to being too large for the wearer to affect. In addition, a Vudrani wearer can move and charge normally through <Link to="/rule/difficult_terrain">difficult terrain</Link> that would otherwise cost 2 squares of movement to enter as if it were normal terrain.</p>
<h3 id="magic-wondrous-belt_of_impossible_action_vudrani-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>, creator must be a Vudrani; <strong>Cost</strong> 8,000 gp</p>
</>};
const _belt_of_incredible_dexterity = {title: "Belt of Incredible Dexterity", jsx: <><h2 id="magic-wondrous-belt_of_incredible_dexterity-belt-of-incredible-dexterity">Belt of Incredible Dexterity</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 209</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 502</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 4,000 gp (+2), 16,000 gp (+4), 36,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This belt has a large silver buckle, usually depicting the image of a tiger. The belt grants the wearer an enhancement bonus to Dexterity of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-belt_of_incredible_dexterity-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 2,000 gp (+2), 8,000 gp (+4), 18,000 gp (+6)</p>
</>};
const _belt_of_mighty_constitution = {title: "Belt of Mighty Constitution", jsx: <><h2 id="magic-wondrous-belt_of_mighty_constitution-belt-of-mighty-constitution">Belt of Mighty Constitution</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 209</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 502</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 4,000 gp (+2), 16,000 gp (+4), 36,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This belt's golden buckle depicts a bear's head. The belt grants the wearer an enhancement bonus to Constitution of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-belt_of_mighty_constitution-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>; <strong>Cost</strong> 2,000 gp (+2), 8,000 gp (+4), 18,000 gp (+6)</p>
</>};
const _belt_of_mighty_hurling_lesser = {title: "Belt of Mighty Hurling (Lesser)", jsx: <><h2 id="magic-wondrous-belt_of_mighty_hurling_lesser-belt-of-mighty-hurling-lesser">Belt of Mighty Hurling (Lesser)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 209-210</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th (lesser), 12th (greater)<br/><strong>Slot</strong> belt; <strong>Price</strong> 14,000 gp (lesser), 42,000 (greater); <strong>Weight</strong> 1 lb.</p>
<p>This thick leather belt is buckled with a bright bronze clasp in the shape of a fist. When worn, it grants its wearer an enhancement bonus to Strength and allows him to apply his Strength modifier as a bonus on attack rolls instead of his Dexterity modifier when making ranged attacks with thrown weapons. Also, the range increment of any weapon thrown by the wearer gains a +10-foot bonus. Treat this Strength bonus as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<p><strong className="hl">Belt of Mighty Hurling (Greater):</strong> This item functions as the lesser belt of mighty hurling, except it grants a +4 enhancement bonus to Strength and any thrown weapons its wearer hurls are treated as though they had the <Link to="/magic-enh/returning">returning</Link> quality. This does not apply to improvised ranged weapons, splash weapons, or weapons the wearer lacks proficiency with. Treat the bonus to Strength as a temporary ability bonus for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-belt_of_mighty_hurling_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/longshot">longshot</Link>, <Link to="/spell/returning_weapon">returning weapon</Link> (greater belt of mighty hurling only); <strong>Cost</strong> 7,000 gp (lesser), 21,000 gp (greater)</p>
</>};
const _belt_of_physical_might = {title: "Belt of Physical Might", jsx: <><h2 id="magic-wondrous-belt_of_physical_might-belt-of-physical-might">Belt of Physical Might</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 210</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 502</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> belt; <strong>Price</strong> 10,000 gp (+2), 40,000 gp (+4), 90,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This belt grants the wearer an enhancement bonus to two physical ability scores (Strength, Dexterity, or Constitution) of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn. These bonuses are chosen when the belt is created and cannot be changed.</p>
<h3 id="magic-wondrous-belt_of_physical_might-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, and/or <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 5,000 gp (+2), 20,000 gp (+4), 45,000 gp (+6)</p>
</>};
const _belt_of_physical_perfection = {title: "Belt of Physical Perfection", jsx: <><h2 id="magic-wondrous-belt_of_physical_perfection-belt-of-physical-perfection">Belt of Physical Perfection</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 210</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 502</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 16th<br/><strong>Slot</strong> belt; <strong>Price</strong> 16,000 gp (+2), 64,000 gp (+4), 144,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This belt has a large platinum buckle and grants the wearer an enhancement bonus to all physical ability scores (Strength, Dexterity, and Constitution) of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-belt_of_physical_perfection-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 8,000 gp (+2), 32,000 gp (+4), 77,000 gp (+6)</p>
</>};
const _belt_of_spirit_vines = {title: "Belt of Spirit Vines", jsx: <><h2 id="magic-wondrous-belt_of_spirit_vines-belt-of-spirit-vines">Belt of Spirit Vines</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 250</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This belt is constructed from woven vines. Its wearer can touch a willing creature and cause a ghostly vine to grow from the belt, connecting the wearer to the target creature. While connected to another creature, when the wearer casts a druid, ranger, shaman, or witch spell with a range of touch on herself, both the wearer and the connected creature gain the benefits of the spell for half the spell's duration (rounded down); this has no effect on instantaneous or permanent spells. The spell's effects on the connected creature end if the vine's range is exceeded.</p>
<p>The vine can grow up to a length of 30 feet, and it vanishes if the wearer or connected creature moves beyond its maximum range. The vine can remain connected indefinitely, but the connection is broken if the wearer <Link to="/misc/dismiss">dismisses</Link> it or connects the vine to another creature.</p>
<h3 id="magic-wondrous-belt_of_spirit_vines-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/plant_growth">plant growth</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _belt_of_stoneskin = {title: "Belt of Stoneskin", jsx: <><h2 id="magic-wondrous-belt_of_stoneskin-belt-of-stoneskin">Belt of Stoneskin</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 210</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 148</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> belt; <strong>Price</strong> 60,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>Every 24 hours, this belt's wearer gains DR 10/adamantine until the belt absorbs 100 points of damage, at which point the belt becomes useless for the remainder of the 24-hour period. When first worn, or after each time this belt is taken off, it must worn for 24 consecutive hours in order for its magic to take effect again.</p>
<h3 id="magic-wondrous-belt_of_stoneskin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/stoneskin">stoneskin</Link>, creator must be an <Link to="/race/oread">oread</Link> or a creature with the earth subtype; <strong>Cost</strong> 30,000 gp</p>
</>};
const _belt_of_superior_maneuvers = {title: "Belt of Superior Maneuvers", jsx: <><h2 id="magic-wondrous-belt_of_superior_maneuvers-belt-of-superior-maneuvers">Belt of Superior Maneuvers</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 226</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 2,000 gp (+1), 8,000 gp (+2), 18,000 gp (+3), 32,000 gp (+4), 50,000 gp (+5); <strong>Weight</strong> -</p>
<p>This thin, black canvas belt is typically tied loosely about the waist to secure a robe, kimono, or martial artist's dobok. Three times per day as a free action, the wearer can select a <Link to="/rule/combat_maneuver">combat maneuver</Link> and receive an enhancement bonus of +1 to +5 on combat maneuver checks for this combat maneuver and a +1 to +5 bonus to CMD when defending against this maneuver for 1 round. Additionally, when worn by a <Link to="/class/brawler">brawler</Link>, the belt grants one additional use of her martial flexibility class feature each day.</p>
<h3 id="magic-wondrous-belt_of_superior_maneuvers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divine_favor">divine favor</Link>, creator's caster level must be at least triple the belt's bonus; <strong>Cost</strong> 1,000 gp (+1), 4,000 gp (+2), 9,000 gp (+3), 16,000 gp (+4), 25,000 gp (+5)</p>
</>};
const _belt_of_teeth = {title: "Belt of Teeth", jsx: <><h2 id="magic-wondrous-belt_of_teeth-belt-of-teeth">Belt of Teeth</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 210</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> belt; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>The brass buckle on this stout leather belt is fashioned to resemble three demonic faces. Once each round, this belt's buckle can animate, lashing out at a creature that provokes an attack of opportunity within 5 feet. This attack uses its wearer's base attack bonus and Strength modifier, with a +4 competence bonus. It deals damage as a bite attack made by a creature of its wearer's size (1d6 for a Medium wearer; see <Link to="/umr/natural_attacks">Table 3-1: Natural Attacks by Size</Link>) plus the wearer's Strength modifier. This belt does not add to the normal number of attacks the wearer can make in a round; it offers another way in which to make attacks of opportunity.</p>
<h3 id="magic-wondrous-belt_of_teeth-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_fang">magic fang</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _belt_of_the_snake_king = {title: "Belt of the Snake King", jsx: <><h2 id="magic-wondrous-belt_of_the_snake_king-belt-of-the-snake-king">Belt of the Snake King</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 260</Link>, <Link to="/source/pathfinder_42_sanctum_of_the_serpent_god">Pathfinder #42: Sanctum of the Serpent God pg. 28</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 54</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 2,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This belt writhes like a living snake, and even hisses and blinks its red eyes. It clasps by holding its tail in its mouth. The wearer gains a +1 enhancement bonus to natural armor.</p>
<p>If the serpentfolk god <Link to="/faith/ydersius">Ydersius</Link> is the wearer's patron, once per day, the wearer can use <em>magic fang</em> on one of his own natural weapons.</p>
<h3 id="magic-wondrous-belt_of_the_snake_king-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/barkskin">barkskin</Link>, <Link to="/spell/magic_fang">magic fang</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>; <strong>Cost</strong> 1,300 gp</p>
</>};
const _belt_of_the_weasel = {title: "Belt of the Weasel", jsx: <><h2 id="magic-wondrous-belt_of_the_weasel-belt-of-the-weasel">Belt of the Weasel</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 210</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> belt; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This surprisingly soft belt has an absurdly large buckle, made even more absurd by the fact that it's crafted in the shape of a smiling weasel's face. It grants its wearer a +2 enhancement bonus to Dexterity, and the ability to move at half normal speed while <Link to="/rule/prone">prone</Link>. Treat the enhancement bonus to Dexterity as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn. The wearer does not take a penalty on melee attack rolls or to AC against melee attacks while prone. Additionally, the wearer gains the <Link to="/umr/compression">compression</Link> ability.</p>
<h3 id="magic-wondrous-belt_of_the_weasel-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _belt_of_thunderous_charging = {title: "Belt of Thunderous Charging", jsx: <><h2 id="magic-wondrous-belt_of_thunderous_charging-belt-of-thunderous-charging">Belt of Thunderous Charging</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 211</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>An engraving of a charging rhinoceros decorates this thick leather belt. The belt grants its wearer a +2 enhancement bonus to Strength. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<p>The belt magnifies the wearer's momentum whenever she charges, granting her a +2 bonus on <Link to="/rule/bull_rush">bull rush</Link> and <Link to="/rule/overrun">overrun</Link> maneuvers. Furthermore, when the wearer makes a <Link to="/rule/charge">charge</Link> attack, her melee weapons and natural weapons deal damage as if they were <Link to="/misc/one_size_category_larger">one size category larger</Link> than they actually are.</p>
<h3 id="magic-wondrous-belt_of_thunderous_charging-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/lead_blades">lead blades</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _belt_of_trelmarixian = {title: "Belt of Trelmarixian", jsx: <><h2 id="magic-wondrous-belt_of_trelmarixian-belt-of-trelmarixian">Belt of Trelmarixian</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_spiral_of_bones_5">Pathfinder Spiral of Bones #5 pg. 29</Link><br/><strong>Aura</strong> faint conjuration and necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Often created by those who venerate <Link to="/faith/trelmarixian">Trelmarixian</Link>, the Horseman of Famine, this dark leather belt has a piece of a cracked soul gem in its plain brass buckle. the wearer of a belt of Trelmarixian doesn't need to eat and is immune to the effects of starvation, though she begins to take on an emaciated appearance after several days. Three times per day, the wearer can touch a creature (requiring a successful touch melee attack) to affect it with incredibly painful pangs of hunger. If the target fails a DC 15 Fortitude save, it takes 2d6 points of nonlethal damage and is <Link to="/misc/fatigued">fatigued</Link>. Creatures that don't need to eat or are immune to nonlethal damage are immune to this ability.</p>
<h3 id="magic-wondrous-belt_of_trelmarixian-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_food_and_water">create food and water</Link>, <Link to="/spell/touch_of_fatigue">touch of fatigue</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _belt_of_tumbling = {title: "Belt of Tumbling", jsx: <><h2 id="magic-wondrous-belt_of_tumbling-belt-of-tumbling">Belt of Tumbling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 211</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> belt; <strong>Price</strong> 800 gp; <strong>Weight</strong> 1 lb.</p>
<p>This thin and flexible cotton cord is meant to be wrapped several times around wearer's waist. The belt's wearer gains a +4 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks made to move through a threatened square or through an enemy's space.</p>
<h3 id="magic-wondrous-belt_of_tumbling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 400 gp</p>
</>};
const _belt_of_weakness = {title: "Belt of Weakness", jsx: <><h2 id="magic-wondrous-belt_of_weakness-belt-of-weakness">Belt of Weakness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 343</Link></p>
<p><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Weight</strong> 1 lb.</p>
<p>Appearing to be a wide leather belt that functions as a <em>belt of mighty constitution +4,</em> this belt in fact saps the wearer's health rather than supplement it. A belt of weakness confers a -4 penalty to its wearer's Constitution score. Furthermore, when the wearer rolls a natural 1 on any Fortitude save, the belt constricts, dealing 2d8 points of damage.</p>
<h3 id="magic-wondrous-belt_of_weakness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/belt_of_mighty_constitution_4">belt of mighty constitution (any)</Link>; <strong>Cost</strong> -</p>
</>};
const _beneficial_bandolier = {title: "Beneficial Bandolier", jsx: <><h2 id="magic-wondrous-beneficial_bandolier-beneficial-bandolier">Beneficial Bandolier</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 211</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> belt; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This bandolier is made of finely tanned leather. It has slots for up to 200 rounds of ammunition. Pellets and black powder are kept in tiny individual pouches, and bullets in small loops. The bandolier alters itself as needed to accommodate both. There are also places on the beneficial bandolier for a <Link to="/eq-misc/gunsmiths_kit">gunsmith's kit</Link> and a <Link to="/eq-misc/powder_horn">powder horn</Link>. Regardless of what quantities of these items are placed within the beneficial bandolier, its weight does not change.</p>
<p>As a swift action, the wearer can command a single round of ammunition from the beneficial bandolier to teleport into a firearm of the appropriate type that he is wielding.</p>
<h3 id="magic-wondrous-beneficial_bandolier-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _bladed_belt = {title: "Bladed Belt", jsx: <><h2 id="magic-wondrous-bladed_belt-bladed-belt">Bladed Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 211</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> belt; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Rather than being made of one continuous line of material, this belt consists of many bits of tanned leather joined together by thick metal studs. On command, the belt's wearer can transform the belt into a single <Link to="/rule/masterwork_w">masterwork</Link> slashing and/or piercing melee weapon of her choice. As long as she is holding the weapon, she can also revert it back to belt form with a command. Furthermore, the belt can be enchanted like a piercing and slashing melee weapon, using the cost of the belt as the cost of the masterwork item.</p>
<h3 id="magic-wondrous-bladed_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_weapon">magic weapon</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _blinkback_belt = {title: "Blinkback Belt", jsx: <><h2 id="magic-wondrous-blinkback_belt-blinkback-belt">Blinkback Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 211</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> belt; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A set of clips is attached to this segmented belt constructed of metallic links. Up to two one-handed melee weapons or up to four light melee weapons can be hung from the belt in straps or sheaths. When the wearer draws a weapon attached to this belt and throws it before the end of her next turn, the weapon teleports back to its strap or sheath immediately after the attack is resolved.</p>
<h3 id="magic-wondrous-blinkback_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/teleport_object">teleport object</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _broken_chain_of_the_beast = {title: "Broken Chain of the Beast", jsx: <><h2 id="magic-wondrous-broken_chain_of_the_beast-broken-chain-of-the-beast">Broken Chain of the Beast</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 261</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 55</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This 8-foot length of corroded, broken chain is threaded with a leather strap to hold it together; it is worn like a belt and must be tied in place, as it lacks a buckle. Once per day, the wearer can call upon its power to summon an evil creature from the summon monster I list; the creature attacks the wearer's enemies if any are present, but it is not under the wearer's control and attacks the wearer or the wearer's allies if there are no more enemies to kill.</p>
<p>If <Link to="/faith/rovagug">Rovagug</Link> is the wearer's patron, the wearer can gain the benefits of a <em>rage</em> spell once per day by speaking the god's name. If the wearer is ever bound, shackled, or otherwise rendered helpless while still conscious, this <em>rage</em> ability automatically activates if the wearer hasn't already used it that day.</p>
<h3 id="magic-wondrous-broken_chain_of_the_beast-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/rage">rage</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _canopic_wrap = {title: "Canopic Wrap", jsx: <><h2 id="magic-wondrous-canopic_wrap-canopic-wrap">Canopic Wrap</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 58</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> belt; <strong>Price</strong> 10,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>Tattered and yellowed, this belt is made up of dozens of interwoven linen wraps bound together by a simple stone buckle at the front. Crafted from mummified wrappings, these belts are commonly used by explorers in the vast deserts of what was once Ancient Osirion. While worn, the belt grants a +4 resistance bonus on saving throws against disease, including supernatural diseases such as <Link to="/curse/mummy_rot">mummy rot</Link>.</p>
<p>A canopic wrap also causes strange internal shifts in key organs, moving them randomly within the body. Because of this odd effect, the wearer gains the benefits of the <Link to="/magic-enh/light_fortification">light fortification</Link> armor special ability. This effect also plays havoc on trained healers, however, increasing the DC of any Heal check used on the wearer by 5.</p>
<h3 id="magic-wondrous-canopic_wrap-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/greater_infernal_healing">greater infernal healing</Link>; <strong>Cost</strong> 5,250 gp</p>
</>};
const _channel_thieving_belt = {title: "Channel-Thieving Belt", jsx: <><h2 id="magic-wondrous-channel_thieving_belt-channel-thieving-belt">Channel-Thieving Belt</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 219</Link><br/><strong>Aura</strong> faint conjuration and necromancy (normal), moderate conjuration and necromancy (greater); <strong>CL</strong> 3rd (normal), 7th (greater)<br/><strong>Slot</strong> belt; <strong>Price</strong> 2,000 gp (normal), 9,200 gp (greater); <strong>Weight</strong> 2 lbs.</p>
<p>This wide black leather belt is inlaid with spiraling copper runes. If the wearer is a living creature, she heals each time she is within the area of a <Link to="/misc/burst">burst</Link> of <Link to="/ability/channel_positive_energy">channeled positive energy</Link> used to deal damage to undead creatures. If the wearer is an undead creature, it heals each time it is within the area of a burst of channeled negative energy used to deal damage to living creatures. The wearer regains 1 hit point for each 1d6 points of energy channeled. The belt has no effect if its wearer is the one channeling energy.</p>
<p><strong className="hl">Greater Channel-Thieving Belt:</strong> This belt functions as a normal channel-thieving belt, except the amount of healing is equal to 1/2 the amount of damage healed or dealt by the creature channeling energy.</p>
<h3 id="magic-wondrous-channel_thieving_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link> and <Link to="/spell/inflict_light_wounds">inflict light wounds</Link> (normal belt), <Link to="/spell/cure_serious_wounds">cure serious wounds</Link> and <Link to="/spell/inflict_serious_wounds">inflict serious wounds</Link> (greater belt); <strong>Cost</strong> 1,000 gp (normal), 4,600 gp (greater belt)</p>
</>};
const _cord_of_stubborn_resolve = {title: "Cord of Stubborn Resolve", jsx: <><h2 id="magic-wondrous-cord_of_stubborn_resolve-cord-of-stubborn-resolve">Cord of Stubborn Resolve</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 211</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>When fastened about the waist, this stout length of rope grants a +2 enhancement bonus to Constitution along with prodigious stamina. Treat the enhancement bonus to Constitution as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<p>Any effect which would cause the wearer to become <Link to="/misc/fatigued">fatigued</Link> deals an additional 1d6 points of nonlethal damage instead. Any effect that would cause <Link to="/misc/exhaustion">exhaustion</Link> likewise causes 1d6 points of nonlethal damage, and leaves the wearer fatigued instead of exhausted.</p>
<h3 id="magic-wondrous-cord_of_stubborn_resolve-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _coven_charm = {title: "Coven Charm", jsx: <><h2 id="magic-wondrous-coven_charm-coven-charm">Coven Charm</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven pg. 30</Link><br/><strong>Aura</strong> strong evocation and necromancy; <strong>CL</strong> 15th<br/><strong>Slot</strong> belt; <strong>Price</strong> 75,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This grisly bag is worn by a member of a coven and binds its sisters together even across vast distances. The coven charm can be charged by placing a sizable chunk of flesh - at least the size of a finger, toe, or tongue - from a member of the coven into the bag as a full-round action. Removing an appropriate offering from her own body deals 1d6 points of damage to the respective coven member, as well as a permanent <Link to="/rule/negative_level">negative level</Link> that cannot be regained until the charge in the bag is expended. Each body part placed within the bag generates 1 charge, and a coven charm can hold up to 3 charges.</p>
<p>As a full-round action, the coven charm's wearer can spend charges from the bag to cast a spell that normally requires the presence or her entire coven to cast. Expending 1 charge allows the wearer to cast a spell of up to 4th level. Expending 2 charges allows the wearer to cast a spell of up to 6th level. Expending 3 charges allows the wearer to cast a spell of up to 8th level. These spells must be selected from those bonus spells normally available to her collected coven.</p>
<p>If any member of the coven is slain, the bag loses all remaining charges. Once a coven charm is drained of all charges, it cannot be refilled for 24 hours, and it must be completely drained of all charges before it can be refilled.</p>
<h3 id="magic-wondrous-coven_charm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be a <Link to="/race/changeling">changeling</Link> or <Link to="/family/hag">hag</Link>; <strong>Cost</strong> 37,500 gp</p>
</>};
const _crusaders_scabbard = {title: "Crusader's Scabbard", jsx: <><h2 id="magic-wondrous-crusaders_scabbard-crusaders-scabbard">Crusader's Scabbard</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 16</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> belt; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This scabbard of vigor prominently bears the symbol of <Link to="/faith/iomedae">Iomedae</Link>. Three times per day, the scabbard can cast <em>bless weapon</em> on any weapon sheathed within, but does so reluctantly on any weapon other than a <Link to="/eq-weapon/longsword">longsword</Link>. While the user is in combat, the scabbard hurls threats of righteous retribution in a loud, clear voice as it attempts to demoralize opponents (<Link to="/skill/intimidate">Intimidate</Link> bonus of +7). The consciousness within the crusader's scabbard is valorous and stridently condemns displays of cowardice or dishonesty.</p>
<h3 id="magic-wondrous-crusaders_scabbard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bless_weapon">bless weapon</Link>, <Link to="/spell/greater_magic_weapon">greater magic weapon</Link>; <strong>Price</strong> 4,250 gp</p>
<h3 id="magic-wondrous-crusaders_scabbard-statistics">Statistics</h3>
<p><strong>Alignment</strong> lawful good; <strong>Ego</strong> 6<br/><strong>Senses</strong> 60 ft.<br/><strong>Int</strong> 10, <strong>Wis</strong> 12, <strong>Cha</strong> 14<br/><strong>Communication</strong> speech (Common)</p>
</>};
const _dawnflower_sash = {title: "Dawnflower Sash", jsx: <><h2 id="magic-wondrous-dawnflower_sash-dawnflower-sash">Dawnflower Sash</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 262</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 56</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt or head; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>This long strip of red Qadiran fabric is wrapped around the wearer's waist or head several times and held in place by an ankh-shaped clasp of red gold. The wearer is protected as if by <em>endure elements,</em> but only in warm environments. If the wearer unwraps the sash to its full length and holds the clasp in her hand, she can use <em>feather fall</em> once per day, briefly leaving behind a trail of pleasant red-gold light as bright as a <Link to="/eq-misc/torch">torch</Link> that lasts for 1 round.</p>
<p>If <Link to="/faith/sarenrae">Sarenrae</Link> is the wearer's patron, the wearer can use the sash to cast <em>cure light wounds</em> once per day on command. The wearer can trigger this ability as an immediate action if reduced to -1 hit points or fewer, though thereafter the sash must be recharged by placing it in strong sunlight for 8 continuous hours. As a swift action, the wearer can cause the clasp to shine as brightly as a torch or cease this illumination; the light is warm, feels like sunlight, and is bright enough to make sun-fearing creatures slightly uncomfortable but not so bright as to cause them harm.</p>
<h3 id="magic-wondrous-dawnflower_sash-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/light">light</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _diminishing_sash = {title: "Diminishing Sash", jsx: <><h2 id="magic-wondrous-diminishing_sash-diminishing-sash">Diminishing Sash</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 14</Link><br/><strong>Aura</strong> faint universal; <strong>CL</strong> 3rd<br/><strong>Slot</strong> belt; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>At first glance, there is nothing at all unique about this length of woven brown wool; however, in the hands of a spellcaster it can be a devious resource. The wearer of a diminishing sash can tear off a piece of the item and use it as a substitute for spell components worth up to 50 gp. Each piece torn from a diminishing sash (an action subsumed in the casting of a spell) provides components for one spell, and multiple pieces cannot be combined to provide more expensive components. After providing the components for 50 spells, a diminishing sash becomes a nonmagical piece of cloth.</p>
<p>If the sash is used to generate material components for a spell that normally uses no components or components that cost 1 gp or less, the wearer casts the spell at +1 caster level.</p>
<h3 id="magic-wondrous-diminishing_sash-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/eschew_materials">Eschew Materials</Link>, creator must have 3 ranks in Knowledge (arcana) and Spellcraft; <strong>Cost</strong> 2,500 gp</p>
</>};
const _elemental_earth_belt = {title: "Elemental Earth Belt", jsx: <><h2 id="magic-wondrous-elemental_earth_belt-elemental-earth-belt">Elemental Earth Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 211</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> belt; <strong>Price</strong> 24,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This belt is constructed of flat pieces of slate connected with strong leather straps. This belt grants its wearer a +4 enhancement bonus to Constitution, and the wearer is immune to effects that would push, pull, or forcefully move the wearer. This offers no protection from teleportation effects. Furthermore, once per day on command, the wearer can take the form of a <Link to="/monster/large_earth_elemental">Large earth elemental</Link>, as though subject to the <em>elemental body III</em> spell.</p>
<p>Treat the enhancement bonus to Constitution as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-elemental_earth_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/elemental_body_iii">elemental body III</Link>; <strong>Cost</strong> 12,000 gp</p>
</>};
const _equestrian_belt = {title: "Equestrian Belt", jsx: <><h2 id="magic-wondrous-equestrian_belt-equestrian-belt">Equestrian Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 211</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> belt; <strong>Price</strong> 3,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>This belt is worked with images of horses stampeding across a barren, windswept plain. The belt's wearer automatically succeeds at any check to guide with the knees, stay in the saddle, fight with a combat-trained mount, control a mount in battle, or make a fast mount or dismount, as long as the belt's wearer is wearing medium, light, or no armor. Furthermore, the belt grants a +4 competence bonus on all other <Link to="/skill/ride">Ride</Link> checks, including ones made while the wearer is in heavy armor.</p>
<h3 id="magic-wondrous-equestrian_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 1,600 gp</p>
</>};
const _fellers_belt = {title: "Feller's Belt", jsx: <><h2 id="magic-wondrous-fellers_belt-fellers-belt">Feller's Belt</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 28</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> belt; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The secret weapons of the Lumber Consortium's enforcers throughout Andoran, these belts nominally appear as expensive but effective aids for felling trees, but are instead used by the Consortium's enforcers. A creature wearing a feller's belt gains +4 bonus on combat maneuver checks to <Link to="/rule/sunder">sunder</Link> wooden objects, ignores any hardness possessed by wooden objects, and bypasses the damage reduction of any creatures of the plant or fey type. A creature wearing a feller's belt for over 24 hours doubles the critical threat range of any held axe, as though that weapon possessed the <Link to="/magic-enh/keen">keen</Link> weapon special ability. This benefit lasts for as long as the belt is worn, and doesn't stack with any other effects that expand the critical threat range of a weapon (such as <em>keen edge</em> or the <Link to="/feat/improved_critical">Improved Critical</Link> feat).</p>
<h3 id="magic-wondrous-fellers_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/keen_edge">keen edge</Link>, <Link to="/spell/warp_wood">warp wood</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ghoulbane_belt = {title: "Ghoulbane Belt", jsx: <><h2 id="magic-wondrous-ghoulbane_belt-ghoulbane-belt">Ghoulbane Belt</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 30</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> belt; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Due to the toxic nature of many environments found within the Darklands, this belt is designed to protect its wearer from exotic diseases, paralyzing attacks, and poisonous molds. The wearer gains a +2 bonus on saving throws to resist disease, paralysis, and poison. This bonus increases to +4 on saving throws to resist such effects caused by molds or slimes. Additionally, the wearer can cast a single spell from the following list as a spell-like ability once per day: <em>neutralize poison, remove disease,</em> or <em>remove paralysis.</em> Activating this ability is a purely mental action that can be taken even while <Link to="/rule/paralyzed">paralyzed</Link> or otherwise <Link to="/misc/helpless">helpless</Link>. The chosen spell affects only the belt's wearer.</p>
<h3 id="magic-wondrous-ghoulbane_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/remove_disease">remove disease</Link>, <Link to="/spell/remove_paralysis">remove paralysis</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _girdle_of_opposite_gender = {title: "Girdle of Opposite Gender", jsx: <><h2 id="magic-wondrous-girdle_of_opposite_gender-girdle-of-opposite-gender">Girdle of Opposite Gender</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 346</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> belt; <strong>Weight</strong> 1 lb.</p>
<p>When this magical belt is put on, the wearer must immediately make a DC 20 Fortitude saving throw or be transformed into a person of the opposite gender. The character's abilities, mind, and spirit remain unaffected; only the character's sex changes. If the character's saving throw is a natural 1, the item actually removes all gender from the wearer, giving him an androgynous, neutered appearance. The change is permanent unless undone with curse-removing magic. Once its magic takes effect, the belt can be removed without effort. A creature can only be affected by a particular girdle once, though other girdles of this type can cause further transformations.</p>
<h3 id="magic-wondrous-girdle_of_opposite_gender-construction">Construction</h3>
<p><strong>Requirements</strong> any belt; <strong>Cost</strong> -</p>
</>};
const _gorgon_belt = {title: "Gorgon Belt", jsx: <><h2 id="magic-wondrous-gorgon_belt-gorgon-belt">Gorgon Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 212</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> belt; <strong>Price</strong> 23,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This belt grants its wearer a +4 enhancement bonus to Strength, and the ability to ignore <Link to="/rule/difficult_terrain">difficult terrain</Link> while <Link to="/rule/charging">charging</Link> or making an <Link to="/rule/overrun">overrun</Link>, <Link to="/rule/bull_rush">bull rush</Link>, or <Link to="/umr/trample">trample</Link> attempt. Furthermore, once per day on command, its wearer can spew a 60-foot cone of poisonous green gas as a breath weapon. Any creature caught in the area of the gas can attempt a DC 18 saving throw to resist its effect, but if the creature fails the saving throw, it is <Link to="/rule/paralyzed">paralyzed</Link> for 1d4 rounds. At the end of its turn, a creature petrified by this breath weapon can attempt a new save to end the paralysis effect. Treat the enhancement bonus to Strength as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-gorgon_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/feather_step">feather step</Link>, <Link to="/spell/poison">poison</Link>; <strong>Cost</strong> 11,500 gp</p>
</>};
const _gutbite_belt = {title: "Gutbite Belt", jsx: <><h2 id="magic-wondrous-gutbite_belt-gutbite-belt">Gutbite Belt</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 265</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This heavy leather belt is reinforced with metal and detailed to resemble a gut wound that has sprouted teeth. In addition to functioning as a <Link to="/magic-wondrous/belt_of_mighty_constitution_2">belt of mighty constitution +2</Link>, the mouth on the belt animates whenever the wearer gains the <Link to="/rule/grappled">grappled</Link> condition, damaging the wearer's opponent as if it were <Link to="/eq-armorenh/armor_spikes">armor spikes</Link> (1d6 points of damage for a Medium wearer, 1d4 for Small). Similar to armor spikes, the mouth can be made into a magic weapon in its own right; it can also be temporarily enhanced with magic such as <Link to="/spell/magic_weapon">magic weapon</Link>. The wearer can use the mouth to eat meat, gaining nutrition from it as if he had eaten with his own mouth (the mouth refuses any food other than meat).</p>
<h3 id="magic-wondrous-gutbite_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _heavyload_belt = {title: "Heavyload Belt", jsx: <><h2 id="magic-wondrous-heavyload_belt-heavyload-belt">Heavyload Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 212</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> belt; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This wide leather is held together with two strands of oxen skin threaded through holes on each end. The belt's wearer is affected as though subject to a permanent <em>ant haul</em> spell.</p>
<h3 id="magic-wondrous-heavyload_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ant_haul">ant haul</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _infernal_cord = {title: "Infernal Cord", jsx: <><h2 id="magic-wondrous-infernal_cord-infernal-cord">Infernal Cord</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 60</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 5,000 gp (Normal), 31,000 gp (Greater); <strong>Weight</strong> 1 lb.</p>
<p>The entirety of this thick hide belt is scarred with impressions of fiendish visages, each shifting between a scowl and a smile. Commonly used by the servants of <Link to="/faith/asmodeus">Asmodeus</Link> in Cheliax, this belt grants its wearer a +2 enhancement bonus to Constitution. Treat this Constitution bonus as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<p>Whenever an enemy scores a critical hit against the wearer, the wearer gains <Link to="/umr/fast_healing">fast healing</Link> 1 for 1 minute. This ability doesn't trigger if the critical hit deals only nonlethal damage. Damage caused by silver weapons, good-aligned weapons, or spells or effects with the good descriptor doesn't trigger the fast healing, and suppresses the fast healing for 1 round if it's already active.</p>
<p>The wearer of an infernal cord can be detected as though she were an evil creature, and can sense the item's evil while wearing it. This belt imparts 1 <Link to="/rule/negative_level">negative level</Link> to any nonevil creature that wears it until the belt is removed.</p>
<p><strong className="hl">Greater Infernal Cord:</strong> This item functions as an infernal cord, but it grants a +4 enhancement bonus to Constitution, and the fast healing effect increases to fast healing 4. Treat the Constitution bonus as a temporary ability bonus for the first 24 hours the belt is worn.</p>
<p>The wearer can be detected as though she were an evil <Link to="/class/cleric">cleric</Link>, not just an evil creature.</p>
<h3 id="magic-wondrous-infernal_cord-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/infernal_healing">infernal healing</Link>; <strong>Cost</strong> 2,500 gp (Normal), 15,500 gp (Greater)</p>
</>};
const _khangarad_scabbard = {title: "Khangarad Scabbard", jsx: <><h2 id="magic-wondrous-khangarad_scabbard-khangarad-scabbard">Khangarad Scabbard</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 24</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> belt; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This belt-and-scabbard set is decorated with golden depictions of <Link to="/monster/garuda">garudas</Link>. The scabbard automatically reshapes itself to fit the weapon that the wielder is currently using. If the wielder is not using a weapon that would fit into a scabbard, as a free action the wielder can command the khangarad scabbard to take the shape of any weapon with which she has proficiency.</p>
<p>Once per day as a standard action, the wielder can speak the scabbard's command word to blast nearby creatures with gale-force winds. As part of activating the scabbard, the wielder can attempt a special <Link to="/rule/trip">trip</Link> combat maneuver check against all creatures within 10 feet using her normal CMB; this does not provoke attacks of opportunity. Creatures whose CMD is lower than the result are tripped. The wielder is not knocked down if the trip attempt fails by 10 or more.</p>
<h3 id="magic-wondrous-khangarad_scabbard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gust_of_wind">gust of wind</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _merform_belt = {title: "Merform Belt", jsx: <><h2 id="magic-wondrous-merform_belt-merform-belt">Merform Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 212</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> belt; <strong>Price</strong> 32,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Once per day, the wearer of this belt can command it to transform her into the form of a merfolk. While in this form, the wearer can breathe water and transform her lower body into a merfolk fishtail. Her new form provides a +2 natural armor bonus and a swim speed of 30 feet, though while the wearer is in this form her land speed is reduced to 5 feet. The wearer can take this form for up to 12 hours, and can end the effect at any time with a command.</p>
<h3 id="magic-wondrous-merform_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Cost</strong> 16,000 gp</p>
</>};
const _meridian_belt = {title: "Meridian Belt", jsx: <><h2 id="magic-wondrous-meridian_belt-meridian-belt">Meridian Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 212</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 207</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> belt; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This narrow cloth belt has a silver buckle in the shape of four rings. The belt allows a creature to wear a magic ring on each foot in addition to the ring on each hand, though only two rings function at any given time. As a swift action, the wearer can change which of his rings are active (both hands, both feet, left hand and right foot, and so on). For example, a creature could wear a ring of protection, ring of energy resistance, ring of swimming, and ring of counterspells, switching between any two of them as a swift action each round as it desires.</p>
<p>The belt does not change the type of action required to activate a ring (for example, activating a ring of invisibility is still a standard action), but allows the wearer to easily switch between the constant powers of several worn rings. While the belt is worn, wearing a ring on a foot counts toward the attunement process of certain rings (such as a <Link to="/magic-ring/ring_of_sustenance">ring of sustenance</Link>) even if the belt isn't used to make that ring active during that attunement period.</p>
<h3 id="magic-wondrous-meridian_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph">polymorph</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _minotaur_belt = {title: "Minotaur Belt", jsx: <><h2 id="magic-wondrous-minotaur_belt-minotaur-belt">Minotaur Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 212</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> belt; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This belt grants its wearer a +2 enhancement bonus to Strength, and the ability to ignore difficult terrain while charging or making an <Link to="/rule/overrun">overrun</Link>, <Link to="/rule/bull_rush">bull rush</Link>, or <Link to="/umr/trample">trample</Link> attempt. Treat the enhancement bonus to Strength as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-minotaur_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/feather_step">feather step</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _mirroring_belt = {title: "Mirroring Belt", jsx: <><h2 id="magic-wondrous-mirroring_belt-mirroring-belt">Mirroring Belt</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 154</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 6th<br/><strong>Slot</strong> belt; <strong>Price</strong> 36,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This broad belt is constructed of steel plates polished to a gleaming finish. The belt grants its wearer a +2 enhancement bonus to Dexterity. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<p>Three times per day, the wearer can use <em>mirror image</em> to bring forth illusory duplicates that persist for 6 minutes or until destroyed. These function as normal images from that spell, except any ranged attack (including ranged touch spells) that strikes and destroys an image rebounds onto the attacker, using the attacker's original result to determine whether the attack hits.</p>
<p>If the wearer expends one use of mythic power to activate the belt, the mirror images replenish when the wearer is hit. This functions as above, except each time an attack hits the wearer instead of an image, the belt creates a new image, up to the spell's limit of eight images. Unlike mirror image, the effect doesn't end when the images are gone. If there are no more images, the belt continues to create new images for the effect's full duration.</p>
<h3 id="magic-wondrous-mirroring_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/mirror_image">mirror image</Link>; <strong>Cost</strong> 18,000 gp</p>
</>};
const _monkey_belt = {title: "Monkey Belt", jsx: <><h2 id="magic-wondrous-monkey_belt-monkey-belt">Monkey Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 212</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 9,400 gp (normal), 18,000 gp (greater); <strong>Weight</strong> 1 lb.</p>
<p>This furry brown belt resembles the tail of a monkey. The belt grants the wearer a +2 enhancement bonus to Dexterity. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn. The wearer does not lose his Dexterity bonus to AC while climbing, and does not take a -5 penalty on <Link to="/skill/climb">Climb</Link> checks when climbing at half his speed. As a swift action the wearer can command the belt to animate, transforming it into a prehensile tail under the wearer's control. The tail does not grant the wearer any additional attacks or actions per round, nor can it wield weapons, but it can make unarmed attacks and hold or manipulate objects about as well as the wearer's normal limbs (though any activity requiring fingers is beyond the tail's capabilities). The belt can function as a tail for 5 minutes per day. These minutes do not need to be consecutive.</p>
<p><strong className="hl">Monkey Belt (Greater):</strong> This belt functions as a monkey belt, except it grants the wearer a +2 enhancement bonus to Strength and Dexterity. Treat this as a temporary ability bonus for the first 24 hours the belt is worn.</p>
<p>When the wearer speaks the command word to transform the belt into a prehensile tail, a greater monkey belt also gives the wearer a +5 circumstance bonus on Climb checks.</p>
<h3 id="magic-wondrous-monkey_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/bulls_strength">bull's strength</Link> (greater monkey belt only); <strong>Cost</strong> 4,700 gp (normal), 9,000 gp (greater)</p>
</>};
const _mountainshapers_girdle = {title: "Mountainshaper's Girdle", jsx: <><h2 id="magic-wondrous-mountainshapers_girdle-mountainshapers-girdle">Mountainshaper's Girdle</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 107</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This wide belt grants the wearer a +4 enhancement bonus to Strength. In addition, the wearer can spend 1 ki point to use <em>stone shape.</em> When he uses this ability, he can instead choose to shape metal, but he can affect only one-tenth as much material. To shape a usable weapon out of metal or stone, the wearer must succeed at a <Link to="/skill/craft">Craft (weapons)</Link> check. Items created in this way can never be of masterwork quality.</p>
<h3 id="magic-wondrous-mountainshapers_girdle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/stone_shape">stone shape</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _plague_rat_belt = {title: "Plague Rat Belt", jsx: <><h2 id="magic-wondrous-plague_rat_belt-plague-rat-belt">Plague Rat Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 213</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> belt; <strong>Price</strong> 5,200 gp (normal), 11,200 gp (greater); <strong>Weight</strong> 1 lb.</p>
<p>This belt grants its wearer a +2 enhancement bonus to Constitution. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn. Also, as an immediate action three times per day, the wearer can call upon the belt to reroll a saving throw made to resist a disease or poison. The wearer must use the second roll, even if it is worse.</p>
<p><strong className="hl">Plague Rat Belt (Greater):</strong> This belt functions as a plague rat belt, except it grants the wearer a +2 enhancement bonus to Dexterity and Constitution. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn.</p>
<h3 id="magic-wondrous-plague_rat_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/remove_disease">remove disease</Link>, <Link to="/spell/cats_grace">cat's grace</Link> (greater plague rat belt only); <strong>Cost</strong> 2,600 gp (normal), 5,600 gp (greater)</p>
</>};
const _sash_of_flowing_water = {title: "Sash of Flowing Water", jsx: <><h2 id="magic-wondrous-sash_of_flowing_water-sash-of-flowing-water">Sash of Flowing Water</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 213</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> belt; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>If this belt's wearer has at least one hand free (holding nothing), he can attempt to deflect a successful melee attack with an immediate action. To do so, he rolls an unarmed strike against the opponent, including any applicable modifiers such as a <Link to="/ability/favored_enemy">favored enemy</Link> bonus or the penalty for <Link to="/feat/power_attack">Power Attack</Link>. If his attack roll is greater than the opponent's attack roll, the attack is negated without effect. The unarmed strike itself causes no damage and does not count as a successful attack against the opponent. The opponent does not need to be within the wearer's reach to use this ability. Whether the attack succeeds or not, the wearer takes a -4 penalty on attack rolls until the end of his next turn.</p>
<h3 id="magic-wondrous-sash_of_flowing_water-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _scarf_of_the_suggestive_dance = {title: "Scarf of the Suggestive Dance", jsx: <><h2 id="magic-wondrous-scarf_of_the_suggestive_dance-scarf-of-the-suggestive-dance">Scarf of the Suggestive Dance</h2>
<p><strong>Sources</strong> <Link to="/source/murders_mark">Murder's Mark pg. 17</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 1st<br/><strong>Slot</strong> belt; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This silk scarf is embroidered with all the colors of a flame and tasseled in tiny beads. When wrapped around the hips, it grants the wearer a +5 competence bonus on <Link to="/skill/perform">Perform (dance)</Link> checks. The scarf adds +1 to the saving throw DC of the wearer's <Link to="/performance/fascinate">fascinate</Link> and <Link to="/performance/suggestion">suggestion</Link> bardic performances.</p>
<h3 id="magic-wondrous-scarf_of_the_suggestive_dance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hypnotism">hypnotism</Link>; <strong>Cost</strong> 950 gp</p>
</>};
const _security_belt = {title: "Security Belt", jsx: <><h2 id="magic-wondrous-security_belt-security-belt">Security Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 213</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 12,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>A security belt increases the DC of <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks made against the wearer and checks to locate items or weapons hidden on the wearer's person by 5. The wearer also gets a +5 bonus to CMD against the <Link to="/rule/steal">steal</Link> maneuver. Once per day on command, the wearer can touch a single item of up to 10 cubic feet and shrink it into a tiny cloth duplicate as the <em>shrink item</em> spell. With a move action, the wearer can draw one of these items from one of the belt's pockets and return it to normal size. It is difficult to detect a security belt and any items in the pockets as magic. They are affected as though a constant <em>magic aura</em> spell were making them appear nonmagical.</p>
<h3 id="magic-wondrous-security_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_aura">magic aura</Link>, <Link to="/spell/shrink_item">shrink item</Link>; <strong>Cost</strong> 6,250 gp</p>
</>};
const _serpent_belt = {title: "Serpent Belt", jsx: <><h2 id="magic-wondrous-serpent_belt-serpent-belt">Serpent Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 213</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 9,000 gp (normal), 20,000 gp (greater); <strong>Weight</strong> 1 lb.</p>
<p>This belt's wearer gains a +4 bonus on saves against poisons and a +2 bonus on <Link to="/skill/escape_artist">Escape Artist</Link> checks. In addition, once per day on command, the belt can be animated as a <Link to="/monster/venomous_snake">venomous snake</Link> or <Link to="/monster/constrictor_snake">constrictor snake</Link> that obeys the animator's spoken commands for up to an hour. If the animated snake is slain or moves 100 feet away from the animator, the snake reverts into belt form.</p>
<p><strong className="hl">Serpent Belt (Greater):</strong> This belt functions as a serpent belt, except it grants the wearer a +2 enhancement bonus to Strength and Dexterity. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn. When the wearer animates the belt as a venomous or constrictor snake, she may speak a second command word to give the snake the <Link to="/template/advanced">advanced</Link>, <Link to="/template/celestial">celestial</Link>, <Link to="/template/entropic">entropic</Link>, <Link to="/template/fiendish">fiendish</Link>, or <Link to="/template/resolute">resolute</Link> simple template. Adding a planar template changes the snake's alignment to that of the corresponding planes.</p>
<h3 id="magic-wondrous-serpent_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/summon_natures_ally_ii">summon nature's ally II</Link> (normal); Craft Wondrous Item, <em>beast shape I, neutralize poison,</em> <Link to="/spell/summon_monster_ii">summon monster II</Link> or <em>summon nature's ally II,</em> <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/cats_grace">cat's grace</Link> (greater); <strong>Cost</strong> 4,500 gp (normal), 10,000 gp (greater)</p>
</>};
const _serpentform_belt = {title: "Serpentform Belt", jsx: <><h2 id="magic-wondrous-serpentform_belt-serpentform-belt">Serpentform Belt</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This snakeskin belt is crafted from the hides of brightly hued serpents. When buckled, it immediately binds tightly to the wearer's waist. Once per day, the wearer can command the serpentform belt to transform her lower half into that of a serpent. While in this form, the wearer gains a +4 bonus on combat maneuver checks to <Link to="/rule/grapple">grapple or pin</Link> a foe. Once a foe is grappled, the wearer can <Link to="/umr/constrict">constrict</Link> the opponent with any successful subsequent grapple checks, dealing an amount of bludgeoning damage equal to 1d8 + her Strength modifier, if Medium (1d6 if Small). The snake form lasts until another command is given, or for a maximum of 10 minutes, whichever is shorter.</p>
<h3 id="magic-wondrous-serpentform_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _shadowform_belt = {title: "Shadowform Belt", jsx: <><h2 id="magic-wondrous-shadowform_belt-shadowform-belt">Shadowform Belt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 213</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> belt; <strong>Price</strong> 110,000 gp; <strong>Weight</strong> -</p>
<p>When wrapped around a wearer's waist, this belt grants a +6 enhancement bonus to Dexterity. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the belt is worn. Furthermore, as a swift action, its wearer can become incorporeal. While incorporeal, he does not gain a deflection bonus to AC based on his Charisma, but his natural armor bonus is converted to deflection bonus. The wearer can remain incorporeal for up to 10 rounds per day. The rounds need not be consecutive.</p>
<h3 id="magic-wondrous-shadowform_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/etherealness">etherealness</Link>; <strong>Cost</strong> 55,000 gp</p>
</>};
const _silver_soul_cord = {title: "Silver Soul Cord", jsx: <><h2 id="magic-wondrous-silver_soul_cord-silver-soul-cord">Silver Soul Cord</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook pg. 30</Link><br/><strong>Aura</strong> moderate abjuration and necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> belt; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This shimmering metallic belt is composed of dozens of looped silver cords tied together in elaborate braids and knots. As a standard action, the wearer can touch his <Link to="/sidekick/animal_companion">animal companion</Link> to attach an invisible, incorporeal cord to it that, if it can be seen by anyone, appears to be superficially tied to the silver soul cord. This forms a deeper bond between the wearer and the animal companion. It can be attached to only one animal companion at a time. If the animal companion is killed or the link is broken while the cord is attached in this manner (though very few things can destroy the incorporeal cord), the wearer and the animal companion each gain a <Link to="/rule/negative_level">negative level</Link> and the silver soul cord cannot be reattached to any creature for 24 hours. The cord can extend for a length of up to 1 mile, but if the attached animal companion moves farther away from the wearer than this, the cord automatically detaches and the bond ends, though it is not considered to be broken and therefore does impart any negative levels. The wearer can remove the cord as a standard action. While the silver cord is attached, the wearer gains an empathic link with an animal companion as if it were a <Link to="/sidekick/familiar">familiar</Link> (per the wizard arcane bond class feature). Additionally, as a standard action, the wearer can sacrifice his own hit points to heal the animal companion through this bond. The creature regains 1 hit point for every 1 hit point the wearer sacrifices. The wearer can sacrifice a maximum number of hit points per turn equal to his Hit Dice, and can't sacrifice hit points if doing so would reduce him to 0 hit points or fewer.</p>
<h3 id="magic-wondrous-silver_soul_cord-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield_other">shield other</Link>, <Link to="/spell/vampiric_touch">vampiric touch</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _tightfit_belt = {title: "Tightfit Belt", jsx: <><h2 id="magic-wondrous-tightfit_belt-tightfit-belt">Tightfit Belt</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 25</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> belt; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>As a free action, the wearer of this brown leather belt can compress himself to fit through tight spaces as though affected by a <em>squeeze spell</em> for up to 10 rounds per day. When using the belt's squeezing ability, the wearer gains a +5 circumstance bonus on <Link to="/skill/escape_artist">Escape Artist</Link> checks. Once per day as a move action, the wearer can reduce his size by one step, as the <em>reduce person</em> spell, for 1 round. These effects can be used simultaneously.</p>
<h3 id="magic-wondrous-tightfit_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/grease">grease</Link>, <Link to="/spell/reduce_person">reduce person</Link>, <Link to="/spell/squeeze">squeeze</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _victors_belt = {title: "Victor's Belt", jsx: <><h2 id="magic-wondrous-victors_belt-victors-belt">Victor's Belt</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_92_the_hill_giants_pledge">Pathfinder #92: The Hill Giant's Pledge pg. 13</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This thick leather belt is adorned with several oversized iron plates and disks depicting images of orc gladiators in battle. The wearer of a victor's belt gains a +2 morale bonus on all <Link to="/rule/combat_maneuver">combat maneuver</Link> checks and to Combat Maneuver Defense. In addition, the wearer can enter a rage (as the <em>rage</em> spell) as a standard action once per day. Whenever the wearer takes an amount of damage equal to at least half his current hit points in a single round, there is a 50% chance that the belt activates its <em>rage</em> ability automatically as an immediate action, provided the power has not already been activated that day and the wearer is not already raging. Regardless of how the rage is activated, it lasts for 5 rounds.</p>
<h3 id="magic-wondrous-victors_belt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/rage">rage</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _war_kilt_of_sarenrae = {title: "War-Kilt of Sarenrae", jsx: <><h2 id="magic-wondrous-war_kilt_of_sarenrae-war-kilt-of-sarenrae">War-Kilt of Sarenrae</h2>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East pg. 23</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> waist; <strong>Price</strong> 13,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A favored item among the dervishes of <Link to="/faith/sarenrae">Sarenrae</Link>, this skirt of overlapping, brightly colored silk is magically reinforced, granting you increased durability and mobility. You gain a +2 natural armor bonus to AC and a +2 competence bonus on Acrobatics and Perform (dance) checks.</p>
<p>Once per day, when an adjacent foe attempts to take a 5-foot step away from you, you may make a 5-foot step as an immediate action so long as you end up adjacent to that foe. If you take this step, you cannot take a 5-foot step during your next turn. If you take an action to move during your next turn, subtract 5 feet from your total movement.</p>
<h3 id="magic-wondrous-war_kilt_of_sarenrae-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>, <Link to="/spell/barkskin">barkskin</Link> or <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Cost</strong> 6,500 gp</p>
</>};
const _war_saddle = {title: "War Saddle", jsx: <><h2 id="magic-wondrous-war_saddle-war-saddle">War Saddle</h2>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea pg. 31</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This military saddle is made of cured hide, with numerous straps and hooks to allow it to be easily configured to fit different sizes of animals and saddlebags. Any creature of the animal or magical beast type of an appropriate shape to wear a saddle (creatures with unusual anatomies may be affected with GM discretion) can wear the war saddle, which magically changes size and shape as necessary. The saddle allows the creature wearing it to act as if it were <Link to="/skill/handle_animal">combat trained</Link>, and gives the rider a +5 competence bonus on <Link to="/skill/ride">Ride</Link> checks made while mounted upon the creature.</p>
<h3 id="magic-wondrous-war_saddle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, creator must have 5 ranks in the Ride skill; <strong>Cost</strong> 2,500 gp</p>
</>};
const _windwave_kilt = {title: "Windwave Kilt", jsx: <><h2 id="magic-wondrous-windwave_kilt-windwave-kilt">Windwave Kilt</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 271</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 61</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> belt; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This kilt is made of thick woven strips of sea-green and sky-blue cloth decorated with tiny pearls and bits of coral along the beltline. The wearer gains a +3 competence bonus on Swim checks. When not worn, a windwave kilt floats on water like a dry log, automatically buoying upward any creature that weighs 100 pounds or less and aiding in flotation for heavier creatures.</p>
<p>If <Link to="/faith/gozreh">Gozreh</Link> is the wearer's patron, once per day the wearer can use <em>gaseous form.</em> In this form, the wearer does not need to breathe and can enter water or other liquid, appearing as a mass of fine bubbles and gaining the ability to swim at a speed of 10 feet. The wearer can also drink salt water as if it were fresh water.</p>
<h3 id="magic-wondrous-windwave_kilt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_water">create water</Link>, <Link to="/spell/gaseous_form">gaseous form</Link>, <Link to="/spell/levitate">levitate</Link> or <Link to="/spell/water_walk">water walk</Link>, creator must have 5 ranks in Swim; <strong>Cost</strong> 3,500 gp</p>
</>};
const _alabaster_trapping = {title: "Alabaster Trapping", jsx: <><h2 id="magic-wondrous-alabaster_trapping-alabaster-trapping">Alabaster Trapping</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 18</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> body; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>Sewn in the traditional style of the Kalistocracy, this white robe bears several golden embellishments. The robe is under a constant <em>prestidigitation</em> spell that removes any dirt or stains while preventing wrinkles. Once per day as an immediate action, the wearer can repel one creature physically touching her (such as a creature targeting her with a touch spell or a combat maneuver). The target of this effect takes 5d4 points of force damage and is pushed 10 feet in a direction specified by the wearer.</p>
<h3 id="magic-wondrous-alabaster_trapping-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/force_punch">force punch</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _anaphexis_robe = {title: "Anaphexis Robe", jsx: <><h2 id="magic-wondrous-anaphexis_robe-anaphexis-robe">Anaphexis Robe</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 28</Link><br/><strong>Aura</strong> moderate divination and necromancy; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Sewn from deep purple fabric, an Anaphexis robe appears to be a plain version of <Link to="/faith/pharasma">Pharasmin</Link> holy vestments. A creature wearing this robe can speak directly into the minds of other creatures wearing Anaphexis robes or carrying an unholy symbol of <Link to="/faith/norgorber">Norgorber</Link> within 100 feet, as long as they share a common language. The robes grant a +10 circumstance bonus on <Link to="/skill/disguise">Disguise</Link> checks to appear as a monk of Pharasma and a +10 circumstance bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to conceal weapons. Once per day, a wearer with the death attack class ability can reduce the number of rounds required to study a target for a death attack by 1.</p>
<h3 id="magic-wondrous-anaphexis_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/message">message</Link>, <Link to="/spell/slay_living">slay living</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _bestial_rags = {title: "Bestial Rags", jsx: <><h2 id="magic-wondrous-bestial_rags-bestial-rags">Bestial Rags</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 251</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These tattered and ragged garments extend the duration of a <Link to="/class/shifter">shifter's</Link> bestial transformations, allowing her to shift into her aspects' minor forms for 5 additional minutes per day. Each set of bestial rags is also tied to a specific aspect, typically being made of the hide of that creature and embossed with crude pictograms of it, allowing a shifter to assume that aspect's minor and major form, as appropriate for her level. If the shifter already has the ability to shift into that form, that aspect's major form functions as if she were 2 levels higher.</p>
<h3 id="magic-wondrous-bestial_rags-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _blazing_robe = {title: "Blazing Robe", jsx: <><h2 id="magic-wondrous-blazing_robe-blazing-robe">Blazing Robe</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 214</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 8th<br/><strong>Slot</strong> body; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This red and orange silk robe gives viewers the impression of a flame roiling just below the fabric's slick surface. The robe grants the wearer fire resistance 5 and increases the wearer's caster level for all spells with the fire descriptor by +1. Once per day on command, the wearer of the robe can emit a 20-foot-radius <Link to="/misc/burst">burst</Link> of fire. Creatures other than the wearer within the area take 2d6 points of fire damage (Reflex DC 16 half).</p>
<h3 id="magic-wondrous-blazing_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/fireball">fireball</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _bodywrap_of_mighty_strikes = {title: "Bodywrap of Mighty Strikes", jsx: <><h2 id="magic-wondrous-bodywrap_of_mighty_strikes-bodywrap-of-mighty-strikes">Bodywrap of Mighty Strikes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 214</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> body; <strong>Price</strong> 3,000 gp (+1), 12,000 gp (+2), 27,000 gp (+3), 48,000 gp (+4), 75,000 gp (+5), 108,000 gp (+6), 147,000 gp (+7); <strong>Weight</strong> 1 lb.</p>
<p>This long cloth is wrapped around the chest multiple times like a bandage. Once per round, the wearer may add an enhancement bonus of +1 to +5 on one attack and damage roll for an unarmed strike or natural attack (for one specific attack, not all attacks made with an unarmed strike that round). The wearer may use this item an additional time per round when his BAB reaches +6, +11, and +16.</p>
<p>Choosing to enhance an unarmed strike is not an action and may occur when it is not the wearer's turn (such as when making an attack of opportunity). The wearer must decide to use the item before the attack roll is made, but does not have to expend all uses at the same time. For example, if the wearer can use the item twice per round, he can use it once on his turn when making an attack and save the second for the possibility of making an attack of opportunity.</p>
<p>Additionally, the bodywrap can grant <Link to="/main/magic_enhancements">melee weapon special abilities</Link> to a creature's unarmed attacks, so long as those special abilities to be added apply to unarmed attacks. Special abilities count as additional bonuses for determining the market value of the item, but do not modify attack or damage bonuses. Any special abilities are set at the time of creation. A bodywrap of mighty strikes cannot have a modified bonus (enhancement bonus plus special ability bonus equivalents) higher than +7. Unlike an <Link to="/magic-wondrous/amulet_of_mighty_fists">amulet of mighty fists</Link>, a bodywrap needs to have a +1 enhancement bonus to grant a melee weapon special ability.</p>
<h3 id="magic-wondrous-bodywrap_of_mighty_strikes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_magic_fang">greater magic fang</Link>, creator's caster level must be at least three times the bodywrap's bonus, plus any requirements of the melee weapon special abilities; <strong>Cost</strong> 1,500 gp (+1), 6,000 gp (+2), 13,500 gp (+3), 24,000 gp (+4), 37,500 gp (+5), 54,000 gp (+6), 73,500 gp (+7)</p>
</>};
const _cassock_of_the_black_monk = {title: "Cassock of the Black Monk", jsx: <><h2 id="magic-wondrous-cassock_of_the_black_monk-cassock-of-the-black-monk">Cassock of the Black Monk</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_71_rasputin_must_die">Pathfinder #71: Rasputin Must Die! pg. 60</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> body; <strong>Price</strong> 34,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This ankle-length black robe, cut in the style favored by Orthodox priests, bears little outward ornamentation beyond its gold buttons, though subtle occult symbols embroidered in black thread decorate the skirt's hem. The cassock of the Black Monk grants a +4 luck bonus to the wearer's touch AC. In addition, while wearing the cassock, an <Link to="/class/oracle">oracle</Link> of the <Link to="/mystery/occult">occult</Link> mystery gains access to the <em>spectral spells</em> revelation and may use it as if he had it as a normal class feature. If the wearer already has that revelation, he can use that ability one additional time per day. This ability has no effect if worn by a non-oracle. If the wearer is an oracle but does not have the occult mystery, once per day he can cast a spell with the <Link to="/feat/ectoplasmic_spell">Ectoplasmic Spell</Link> feat as a standard action that does not increase the level of the spell. This ability has no effect if the wearer is a non-oracle.</p>
<h3 id="magic-wondrous-cassock_of_the_black_monk-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divine_favor">divine favor</Link>, <Link to="/spell/ghostbane_dirge">ghostbane dirge</Link>; <strong>Cost</strong> 17,000 gp</p>
</>};
const _cassock_of_the_clergy = {title: "Cassock of the Clergy", jsx: <><h2 id="magic-wondrous-cassock_of_the_clergy-cassock-of-the-clergy">Cassock of the Clergy</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 214</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> body; <strong>Price</strong> 4,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>The cut and color of this solemn vestment varies from religion to religion, but its properties are the same. The wearer may command the cassock of the clergy to display the holy symbol of her deity or hide this symbol. At the most basic level, the garment functions as a divine focus. Additionally, the wearer gains a +3 competence bonus on Charisma-based checks to influence creatures that match her alignment or that of her patron deity. Also, the wearer may use <em>bless</em> and <em>sanctuary</em> (DC 11) each once per day, and may prepare one additional orison each day. If the wearer is a spontaneous divine caster, once per day she may spend 1 hour in prayer to gain an orison of her choice as a spell known for the next 24 hours.</p>
<h3 id="magic-wondrous-cassock_of_the_clergy-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bless">bless</Link>, <Link to="/spell/sanctuary">sanctuary</Link>, creator must be a divine spellcaster; <strong>Cost</strong> 2,300 gp</p>
</>};
const _charlatans_cope = {title: "Charlatan's Cope", jsx: <><h2 id="magic-wondrous-charlatans_cope-charlatans-cope">Charlatan's Cope</h2>
<p><strong>Sources</strong> <Link to="/source/disciples_doctrine">Disciple's Doctrine pg. 28</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 4,800 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This plush hooded robe is finely trimmed with gold accents. When the wearer casts a spell, the robe scintillates with color and produces ostentatious magical effects, such as bright lights and loud hums, increasing the DC of <Link to="/skill/spellcraft">Spellcraft</Link> checks to identify the spell by 10. In addition, once per day as a move action, the wearer can trigger these effects with a dramatic flourish; each creature within 30 feet that can see the wearer must succeed at a DC 13 Will save or be <Link to="/misc/blinded">blinded</Link> for 1d4+1 rounds.</p>
<h3 id="magic-wondrous-charlatans_cope-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ghost_sound">ghost sound</Link>, <Link to="/spell/pyrotechnics">pyrotechnics</Link>, <Link to="/spell/silent_image">silent image</Link>; <strong>Cost</strong> 2,400 gp</p>
</>};
const _coldfire_wrappings = {title: "Coldfire Wrappings", jsx: <><h2 id="magic-wondrous-coldfire_wrappings-coldfire-wrappings">Coldfire Wrappings</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_48_shadows_of_gallowspire">Pathfinder #48: Shadows of Gallowspire pg. 29</Link><br/><strong>Aura</strong> moderate evocation [cold]; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>When carefully wrapped around the body of a Medium-sized creature (a process that takes 10 minutes), these magical linen wrappings protect the wearer from fire and provide defense against physical attacks. As an immediate action, the wearer can immolate herself in wispy blue flames that protect the wearer as the chill shield version of <em>fire shield</em> and deal 1d6+10 points of cold damage to attackers. This protection lasts for 10 rounds before the wrappings crumble away into fine ash.</p>
<h3 id="magic-wondrous-coldfire_wrappings-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fire_shield">fire shield</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _corset_of_dire_witchcraft = {title: "Corset of Dire Witchcraft", jsx: <><h2 id="magic-wondrous-corset_of_dire_witchcraft-corset-of-dire-witchcraft">Corset of Dire Witchcraft</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 214</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> body; <strong>Price</strong> 22,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This slimming garment is fastened with laces, buckles, and buttons and reinforced with ribs of leather or bone. A corset of dire witchcraft grants a +4 armor bonus to AC. If the wearer is a <Link to="/class/witch">witch</Link>, each day when she communes with her familiar to prepare spells, she may enhance one hex she knows, increasing its caster level by +2 for 24 hours. This enhancement ends if the corset is removed or if she uses it to enhance a different hex.</p>
<h3 id="magic-wondrous-corset_of_dire_witchcraft-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mage_armor">mage armor</Link>, creator must be a witch; <strong>Cost</strong> 11,000 gp</p>
</>};
const _corset_of_the_vishkanya = {title: "Corset of the Vishkanya", jsx: <><h2 id="magic-wondrous-corset_of_the_vishkanya-corset-of-the-vishkanya">Corset of the Vishkanya</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 214</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 209</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black corset fits neatly beneath armor. As a free action, the wearer can compress herself to fit through tight spaces as though affected by a <em>squeeze</em> spell for up to 10 rounds per day. While using the corset's magic, she gains a +5 bonus on <Link to="/skill/escape_artist">Escape Artist</Link> checks.</p>
<h3 id="magic-wondrous-corset_of_the_vishkanya-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/grease">grease</Link>, <Link to="/spell/squeeze">squeeze</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _crusaders_tabard = {title: "Crusader's Tabard", jsx: <><h2 id="magic-wondrous-crusaders_tabard-crusaders-tabard">Crusader's Tabard</h2>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea pg. 31</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> body; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A crusader's tabard is a sturdy cloth vestment worn over armor and other clothing. It is normally decorated with the symbol or heraldic device of the owner, and may be trimmed with expensive and delicate materials (such as silk, fur, or cloth of gold). Once per day, the wearer of the tabard may say its command word (often a family motto); thereafter, the wearer can spend a standard action (instead of a full-round action) to move up to his speed and make a single <Link to="/rule/charge">charge</Link> attack. This ability lasts until used or for 1 minute, whichever duration is shorter.</p>
<h3 id="magic-wondrous-crusaders_tabard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _dhoti_of_style_mastery = {title: "Dhoti of Style Mastery", jsx: <><h2 id="magic-wondrous-dhoti_of_style_mastery-dhoti-of-style-mastery">Dhoti of Style Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 107</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>When the wearer enters a stance from a <Link to="/main/style_feat">style feat</Link> while wearing a dhoti of style mastery, he gains 1d8+3 <Link to="/rule/temporary_hit_points">temporary hit points</Link> plus an additional 1d8 temporary hit points for each feat he has that lists that style feat as a prerequisite (maximum 3d8+3 temporary hit points). These temporary hit points last as long as the wearer maintains the stance during that combat, but vanish when the combat concludes. The wearer cannot gain temporary hit points in this way more than once per day.</p>
<h3 id="magic-wondrous-dhoti_of_style_mastery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, any <Link to="/main/style_feat">style feat</Link>, <Link to="/spell/false_life">false life</Link>; <strong>Cost</strong> 2,700 gp</p>
</>};
const _druids_vestment = {title: "Druid's Vestment", jsx: <><h2 id="magic-wondrous-druids_vestment-druids-vestment">Druid's Vestment</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 215</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 532</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 3,750 gp; <strong>Weight</strong> -</p>
<p>This light garment is worn over normal clothing or armor. Most such vestments are green, embroidered with elaborate plant or animal motifs. When this item is worn by a character with the wild shape ability, the character can use that ability one additional time each day.</p>
<h3 id="magic-wondrous-druids_vestment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph">polymorph</Link> or wild shape ability; <strong>Cost</strong> 1,375 gp</p>
</>};
const _eidolon_anchoring_harness = {title: "Eidolon Anchoring Harness", jsx: <><h2 id="magic-wondrous-eidolon_anchoring_harness-eidolon-anchoring-harness">Eidolon Anchoring Harness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 215</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> body; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Loadstone studs line the straps of this ornate leather harness. When worn by an <Link to="/sidekick/eidolon">eidolon</Link>, the bindings act as a dimensional safety harness, anchoring the outsider to its current plane. Any time the eidolon would be forced to return to its home plane (such as when it's reduced to negative hit points equal to its Constitution score or when its master is rendered unconscious), it can expend one use of its summoner's <em>summon monster</em> spell-like ability as a free action to remain on the Material Plane for 1 round. The summoner does not need to be conscious for the eidolon to use this ability, but he must be within 100 feet. If the summoner is conscious, he can refuse to allow this expenditure (which means the eidolon is forced back to its home plane).</p>
<p>If the condition that would have sent the eidolon back to its home plane is still in effect after 1 round has passed, the eidolon may expend another use of its master's <em>summon monster</em> spell-like ability; otherwise it immediately returns to its home plane.</p>
<h3 id="magic-wondrous-eidolon_anchoring_harness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _false_flag_tabard = {title: "False Flag Tabard", jsx: <><h2 id="magic-wondrous-false_flag_tabard-false-flag-tabard">False Flag Tabard</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 23</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> body; <strong>Price</strong> 5,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This sleeveless cotton tabard has a large but innocuous image such as a checkered field or mailed fist emblazoned on its front panel. As a swift action, a wearer devoted to a particular deity or religion can transform the image into her faith's holy symbol or transform the holy symbol back to the innocuous image. The wearer can use the holy symbol image as an actual holy symbol while it is displayed.</p>
<p>Once per day as a standard action, the wearer can cause a false flag tabard to flare with protective energy. All worshipers of the wearer's deity within a 60-foot-radius <Link to="/misc/burst">burst</Link> (including the wearer) gain a +2 sacred bonus to AC and CMD for 5 minutes. If the wearer is evil, this is a profane bonus rather than a sacred bonus.</p>
<h3 id="magic-wondrous-false_flag_tabard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>; <strong>Cost</strong> 2,750 gp</p>
</>};
const _festival_garment = {title: "Festival Garment", jsx: <><h2 id="magic-wondrous-festival_garment-festival-garment">Festival Garment</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 29</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 1st<br/><strong>Slot</strong> body; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These magical sets of clothing can take many forms. In Segada, notable examples range from the ornate costumes of the Festival of Flowers to the flamboyant, bird-like costumes of the Waning Light Festival. When a wearer of a festival garment dances, he can get onlookers into a festive, celebratory mood. A wearer of a festival garment can attempt a <Link to="/skill/perform">Perform (dance)</Link> check instead of a Diplomacy check to influence the attitude of a humanoid creature, but only if the creature's initial attitude is unfriendly or better. In addition, if the wearer is at a festival or celebration, he gains a +5 competence bonus on Perform (dance) checks.</p>
<h3 id="magic-wondrous-festival_garment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_person">charm person</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _glorious_tabard_lesser = {title: "Glorious Tabard (Lesser)", jsx: <><h2 id="magic-wondrous-glorious_tabard_lesser-glorious-tabard">Glorious Tabard</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_108_hell_comes_to_westcrown">Pathfinder #108: Hell Comes to Westcrown pg. 7</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 400 gp (Lesser), 3,250 gp (Greater); <strong>Weight</strong> 2 lbs.</p>
<p>This sleeveless white tabard, worn over armor or other clothing, prominently bears the symbol of the Glorious Reclamation and can be used as a divine focus by members of the Glorious Reclamation who are followers of <Link to="/faith/iomedae">Iomedae</Link>. Once per day, the wearer of a lesser glorious tabard can activate the tabard to gain a +2 sacred bonus to her AC and on saving throws for 10 minutes. Both bonuses apply only against attacks made or effects created by outsiders with the evil subtype or creatures with an evil aura.</p>
<p>A <strong className="hl">greater glorious tabard</strong> bears the symbol of the Glorious Reclamation in gold. It has all the powers of a lesser glorious tabard but can be used twice per day. In addition, whenever a greater glorious tabard is activated, all <Link to="/eq-weapon/longsword">longswords</Link> within 20 feet shed light as per a <Link to="/eq-misc/torch">torch</Link> and ignore the DR of evil creatures (except DR/epic) for 3 rounds. When a greater glorious tabard is used as a divine focus to cast a spell, the wearer does not need any material components that cost more than 5 gp.</p>
<p>A glorious tabard functions only for wearers who are both members of the Glorious Reclamation and followers of Iomedae.</p>
<h3 id="magic-wondrous-glorious_tabard_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/veil_of_heaven">veil of heaven</Link>, <Link to="/spell/weapons_against_evil">weapons against evil</Link> (greater glorious tabard only), creator must be a member of Glorious Reclamation and follower of Iomedae; <strong>Cost</strong> 200 gp (Lesser), 1,625 gp (Greater)</p>
</>};
const _gown_of_graceful_petiteness = {title: "Gown of Graceful Petiteness", jsx: <><h2 id="magic-wondrous-gown_of_graceful_petiteness-gown-of-graceful-petiteness">Gown of Graceful Petiteness</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 12</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> body; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These fine dresses are delicately woven with magically preserved and layered leaves. The dresses were originally commissioned for elven diplomats who often interacted with gnomes and other members of Small races, but their use has spread across Avistan. A Medium humanoid who takes 1 interrupted minute to don a gown of graceful petitenes is, at the end of that time, immediately reduced to Small size. This acts as <em>reduce person,</em> except that it does not grant a size bonus to Dexterity or resize items on the wearer's person other than the gown itself. Taking off the gown also requires 1 interrupted minute and returns the gown and its wearer to their original sizes.</p>
<h3 id="magic-wondrous-gown_of_graceful_petiteness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/reduce_person">reduce person</Link>, creator must be an elf; <strong>Cost</strong> 1,750 gp</p>
</>};
const _gunmans_duster = {title: "Gunman's Duster", jsx: <><h2 id="magic-wondrous-gunmans_duster-gunmans-duster">Gunman's Duster</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 215</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 12th<br/><strong>Slot</strong> body; <strong>Price</strong> 36,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This long, loose-fitting coat grants a +4 armor bonus to AC and a +2 luck bonus to the wearer's touch AC against firearm attacks. If the wearer is a <Link to="/class/gunslinger">gunslinger</Link> or has the <Link to="/feat/amateur_gunslinger">Amateur Gunslinger</Link> feat, she begins each day with 1 additional grit point. This extra point does not increase her maximum grit total. When the wearer uses the <Link to="/deed/gunslingers_dodge">gunslinger's dodge</Link> deed, the deed's dodge bonuses to AC increase by +1. If the wearer is not a gunslinger, she may use the gunslinger's dodge deed once per day.</p>
<h3 id="magic-wondrous-gunmans_duster-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, Amateur Gunslinger or creator must be a gunslinger, <Link to="/spell/bullet_shield">bullet shield</Link>; <strong>Cost</strong> 18,000 gp</p>
</>};
const _habit_of_the_winter_explorer = {title: "Habit of the Winter Explorer", jsx: <><h2 id="magic-wondrous-habit_of_the_winter_explorer-habit-of-the-winter-explorer">Habit of the Winter Explorer</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_70_the_frozen_stars">Pathfinder #70: The Frozen Stars pg. 62</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 13,380 gp; <strong>Weight</strong> 7 lbs.</p>
<p>This warm outfit consists of a woolen coat and pants, boots, gloves, and a heavy fur cloak with a leather hood. The habit of the winter explorer provides a constant <Link to="/spell/endure_elements">endure elements</Link> effect in cold weather (it has no effect in warm weather), and the wearer gains a +2 bonus on saving throws against magic cold effects and spells with the cold descriptor.</p>
<p>When the hood of the habit is drawn up around the head, the wearer's eyes turn a piercing sky blue color. The wearer becomes immune to <Link to="/rule/snow_blindness">snow blindness</Link> and gains the ability to see through natural or magical fog, sleet, snow, and other similar weather conditions with a range of 60 feet.</p>
<p>The habit of the winter explorer also grants its wearer a +4 competence bonus on Stealth checks made in cold weather (temperatures below 40 F). In addition, once per day in cold weather, the wearer may turn invisible for 3 rounds as the <em>vanish</em> spell.</p>
<p>All pieces of the habit of the winter explorer must be worn for the item to function.</p>
<h3 id="magic-wondrous-habit_of_the_winter_explorer-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/vanish">vanish</Link>; <strong>Cost</strong> 6,690 gp</p>
</>};
const _hags_shabble = {title: "Hag's Shabble", jsx: <><h2 id="magic-wondrous-hags_shabble-hags-shabble">Hag's Shabble</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 265</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 57</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 3,400 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This unkempt black smock is loose-fitting and stained from travel. In the River Kingdoms, the wearer is assumed to be a follower of <Link to="/faith/gyronna">Gyronna</Link> because of the garment's association with her faith. The wearer gains a +2 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> and <Link to="/skill/intimidate">Intimidate</Link> checks.</p>
<p>If Gyronna is the wearer's patron, once per day the wearer can use <em>detect thoughts.</em></p>
<h3 id="magic-wondrous-hags_shabble-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, creator must have 5 ranks of Diplomacy and Intimidate; <strong>Cost</strong> 1,700 gp</p>
</>};
const _hamatulatsu_robe = {title: "Hamatulatsu Robe", jsx: <><h2 id="magic-wondrous-hamatulatsu_robe-hamatulatsu-robe">Hamatulatsu Robe</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 59</Link><br/><strong>Aura</strong> moderate evocation and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Made of exquisite crimson silk, this variant <Link to="/magic-wondrous/monks_robe">monk's robe</Link> is embroidered with golden pentagrams and other fiendish symbols. If the wearer is evil and has levels in monk, her AC bonus and unarmed damage are treated as if she were a <Link to="/class/monk">monk</Link> of 5 levels higher (maximum 20).</p>
<p>If the wearer is evil but not a monk, she gains the AC bonus and unarmed damage of a 5th-level monk (although she doesn't add her Wisdom bonus to her AC). This AC bonus otherwise functions just like the monk's AC bonus.</p>
<p>If the robe is donned by a character with the Hamatulatsu feat, the duration of the <Link to="/misc/sickened">sickened</Link> effect increases to 2 rounds. If the wearer doesn't have the Hamatulatsu feat, she gains this feat while wearing the robes, but gains no further benefits to that ability.</p>
<h3 id="magic-wondrous-hamatulatsu_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/hamatulatsu">Hamatulatsu</Link>, <Link to="/spell/righteous_might">righteous might</Link> or <Link to="/spell/transformation">transformation</Link>, <Link to="/spell/unholy_blight">unholy blight</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _harness_of_grabbing_vines = {title: "Harness of Grabbing Vines", jsx: <><h2 id="magic-wondrous-harness_of_grabbing_vines-harness-of-grabbing-vines">Harness of Grabbing Vines</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 13</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> body; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This ivy harness allows the wearer's wings to manipulate objects or grab on to handholds, as if they were extra arms, as long as the wearer isn't flying. They do not grant additional attacks, but they can be used to hold items or perform <Link to="/rule/combat_maneuvers">combat maneuvers</Link> without requiring the wearer's hands. On command, the harness grows roots that anchor the wearer in place much like anchored step. When thus anchored, the wearer can climb using only legs and wings with a climb speed equal to the wearer's reduced base speed. The benefits of anchored step apply while the wearer is climbing with the roots.</p>
<h3 id="magic-wondrous-harness_of_grabbing_vines-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/anchored_step">anchored step</Link>, <Link to="/spell/spider_climb">spider climb</Link>; <strong>Cost</strong> 20,000 gp</p>
</>};
const _harness_of_hovering = {title: "Harness of Hovering", jsx: <><h2 id="magic-wondrous-harness_of_hovering-harness-of-hovering">Harness of Hovering</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 13</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This harness of leather with silver fixtures allows the wearer to hang in midair without the use of wings. Pulling on the harness as a swift action activates or dismisses a <em>levitate</em> effect on the wearer. The <em>levitate</em> effect cannot move the wearer upward or downward.</p>
<h3 id="magic-wondrous-harness_of_hovering-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/levitate">levitate</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _hyperboreal_robe = {title: "Hyperboreal Robe", jsx: <><h2 id="magic-wondrous-hyperboreal_robe-hyperboreal-robe">Hyperboreal Robe</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_68_the_shackled_hut">Pathfinder #68: The Shackled Hut pg. 60</Link><br/><strong>Aura</strong> moderate abjuration and necromancy; <strong>CL</strong> 6th<br/><strong>Slot</strong> body; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This beautiful robe is fashioned from fine blue silk embroidered with silver thread, and trimmed with owl feathers and tiny shards of crystal. The robe grants its wearer a +2 resistance bonus on all saving throws. In addition, the flesh of the robe's wearer becomes searing cold to the touch. Anyone who strikes the wearer with an unarmed strike, a touch attack, or a natural weapon takes 1d6 points of cold damage. The wearer can activate or deactivate this ability as a free action.</p>
<h3 id="magic-wondrous-hyperboreal_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/chill_touch">chill touch</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _liars_robe = {title: "Liar's Robe", jsx: <><h2 id="magic-wondrous-liars_robe-liars-robe">Liar's Robe</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> body; <strong>Price</strong> 4,180 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This hole-ridden burlap robe would appear completely worthless if not for the immaculate red velvet lining its interior. When worn inside out, a liar's robe enshrouds the wearer in a continually shifting array of colors, features, and faces that obscure his entire appearance and make physical recognition all but impossible. This effect lasts for 1 hour, during which time the wearer can go back and forth between wearing the robe inside out (disguising himself) and right side out (revealing his true form) any number of times. Witnesses to a creature wearing a liar's robe must use <Link to="/spell/true_seeing">true seeing</Link> or a similar effect in order to pierce through this disguise; otherwise, they see the wearer only as a continually shifting humanoid form. The wearer's voice, scent, and other tangible cues are also continually altered and distorted, though indirect magical means of identification (such as <Link to="/spell/detect_thoughts">detect thoughts</Link> or <Link to="/spell/locate_creature">locate creature</Link>) may still be used to recognize the individual. Since even the most magically disinclined individuals can clearly tell that the wearer is enshrouded in an illusion, a liar's robe is typically used in circumstances when it's appropriate to protect the wearer's anonymity without the wearer feigning another identity or hiding her presence.</p>
<h3 id="magic-wondrous-liars_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>; <strong>Cost</strong> 2,090 gp</p>
</>};
const _living_garments = {title: "Living Garments", jsx: <><h2 id="magic-wondrous-living_garments-living-garments">Living Garments</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 106</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These sheer and silky robes, many of which are made of spider silk, are of the finest quality. On command, a living garment can make a number of subtle adjustments to itself, including coloring, fit, and basic design, accommodating and accentuating whatever mood the wearer wishes to convey. It always remains clean, and automatically repairs damage to itself at a rate of 1 hit point per round (hardness 0, 4 hit points). It also grants the wearer a +5 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> checks.</p>
<h3 id="magic-wondrous-living_garments-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/mending">mending</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>, creator must be a drow; <strong>Cost</strong> 2,500 gp</p>
</>};
const _lupine_robe = {title: "Lupine Robe", jsx: <><h2 id="magic-wondrous-lupine_robe-lupine-robe">Lupine Robe</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 232</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 6,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This silk robe is covered in exquisitely detailed embroidery depicting foxes frolicking in a pristine meadow. Four times per day, the wearer can add 1d6 to the result of a Dexterity-, Intelligence-, or Charisma-based skill check as a free action. The wearer can do this only once per check, and the wearer can't benefit from both the lupine robe and the inspiration class feature on the same check.</p>
<p>If the wearer is a <Link to="/race/kitsune">kitsune</Link>, he can spend two of the robe's daily uses to add 1d10 on a skill check instead of 1d6.</p>
<h3 id="magic-wondrous-lupine_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, creator must be a kitsune; <strong>Cost</strong> 3,400 gp</p>
</>};
const _mnemonic_vestment = {title: "Mnemonic Vestment", jsx: <><h2 id="magic-wondrous-mnemonic_vestment-mnemonic-vestment">Mnemonic Vestment</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 216</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> body; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The surface of this delicate-looking blue silk robe is adorned with tiny embossed runes across its entire surface. If the wearer is a spontaneous caster, once per day she may use a spell slot to cast a spell from a written source (such as a scroll or spellbook) as if she knew that spell. The spell must be on her spell list, the same spell level or lower than the expended spell slot, and the same type of spell (arcane or divine) as the spell slot expended. The caster must also understand the written source (such as using <Link to="/skill/linguistics">Linguistics</Link> or <Link to="/spell/read_magic">read magic</Link>) and be carrying it. Activating the robe is not an action, but casting the spell otherwise works as normal, including casting time, providing components or foci, and so on. Using a mnemonic vestment's properties does not consume the written source. A mnemonic vestment must be worn for 24 consecutive hours before using its effects.</p>
<h3 id="magic-wondrous-mnemonic_vestment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mnemonic_enhancer">mnemonic enhancer</Link>, creator must be able to spontaneously cast spells; <strong>Cost</strong> 2,500 gp</p>
</>};
const _monks_robe = {title: "Monk's Robe", jsx: <><h2 id="magic-wondrous-monks_robe-monks-robe">Monk's Robe</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 216</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 528</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 13,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>When worn, this simple brown robe confers great ability in unarmed combat. If the wearer has levels in monk, her AC and unarmed damage are treated as a monk of 5 levels higher. If donned by a character with the <Link to="/feat/stunning_fist">Stunning Fist</Link> feat, the robe lets her make one additional stunning attack per day. If the character is not a monk, she gains the AC and unarmed damage of a 5th-level <Link to="/class/monk">monk</Link> (although she does not add her Wisdom bonus to her AC). This AC bonus functions just like the monk's AC bonus.</p>
<h3 id="magic-wondrous-monks_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/righteous_might">righteous might</Link> or <Link to="/spell/transformation">transformation</Link>; <strong>Cost</strong> 6,500 gp</p>
</>};
const _neili_robes = {title: "Neili Robes", jsx: <><h2 id="magic-wondrous-neili_robes-neili-robes">Neili Robes</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 10</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> body; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black-and-white robe is specially crafted to help the wearer regulate the flow of ki in his body, allowing for the generation of internal strength. Once per round when the wearer spends a ki point, he gains a +1 natural armor bonus to AC and a +1 enhancement bonus to Strength for 1 round. If the wearer spends another ki point before the end of his next turn, the duration is extended by 1 round and the natural armor and enhancement bonuses are increased by 1 (to a maximum of +4). The bonuses to AC and Strength last for only 1 round following the expenditure of the last ki point.</p>
<h3 id="magic-wondrous-neili_robes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have a ki pool; <strong>Cost</strong> 5,000 gp</p>
</>};
const _otherworldly_kimono = {title: "Otherworldly Kimono", jsx: <><h2 id="magic-wondrous-otherworldly_kimono-otherworldly-kimono">Otherworldly Kimono</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 216</Link>, <Link to="/source/pathfinder_54_the_empty_throne">Pathfinder #54: The Empty Throne pg. 60</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> body; <strong>Price</strong> 67,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Embroidered images of cherry blossoms and cranes in flight adorn this blue silk kimono. The wearer can move and reposition these images on the kimono at will. The kimono grants its wearer a +4 resistance bonus on all saving throws and a +4 bonus on all caster level checks.</p>
<p>Once per day, the wearer can capture a single creature within 60 feet within the kimono (no save), shunting the victim into an extradimensional space similar to that created by a <em>maze</em> spell. Inside this otherworldly prison, the maze appears as an endless cherry orchard filled with "walls" of windblown cherry blossoms and cranes flying overhead. Each round on its turn, the victim inside the kimono may attempt a DC 20 Intelligence check to escape the kimono as a full-round action. If the victim doesn't escape, it is released after 10 minutes, returning to where it had been before the kimono drew it in. If this location is occupied by another creature or a solid object, the subject appears in the nearest open space.</p>
<p>Whenever a creature is drawn inside the kimono, the victim's image temporarily manifests as another embroidered design among the kimono's other images. While a victim is trapped inside, the kimono's bonuses on saving throws and caster level checks are increased by 2 (to +6). The kimono's increased bonuses return to normal when the victim is freed or released.</p>
<h3 id="magic-wondrous-otherworldly_kimono-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/maze">maze</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 33,500 gp</p>
</>};
const _pathfinder_greatcoat = {title: "Pathfinder Greatcoat", jsx: <><h2 id="magic-wondrous-pathfinder_greatcoat-pathfinder-greatcoat">Pathfinder Greatcoat</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 25</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> body; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This long, double-breasted jacket is sewn from durable, dun-colored canvas with a removable liner to keep its wearer comfortable in a wide range of temperatures. Anyone wearing the coat notes many small cloth patches of various shapes. Only the wearer of the robe can see these patches, recognize them for the items they become, and detach them. One patch can be detached each round. Detaching a patch causes it to become an actual item, as indicated below. A Pathfinder greatcoat has each of the following patches (unless noted otherwise, the coat has only one of each patch):</p>
<ul>
<li>10 days of <Link to="/eq-misc/trail_rations">trail rations</Link> and five full <Link to="/eq-misc/waterskin">waterskins</Link></li>
<li>A case containing five <Link to="/eq-material/adamantine">adamantine</Link> <Link to="/eq-weapon/bolt">bolts</Link>, five <Link to="/eq-material/cold_iron">cold iron</Link> bolts, and two silver bolts</li>
<li>A large <Link to="/eq-misc/scroll_case">scroll case</Link> containing a 2-foot-by-10-foot <Link to="/eq-misc/paper">roll of paper</Link> and two sticks of <Link to="/eq-misc/charcoal">charcoal</Link></li>
<li>A quiver containing five adamantine <Link to="/eq-weapon/arrow">arrows</Link>, five cold iron arrows, and two silver arrows</li>
<li>A 10-square-yard roll of <Link to="/eq-misc/canvas">canvas</Link> containing 10 <Link to="/eq-misc/piton">pitons</Link> and a small <Link to="/eq-misc/hammer">hammer</Link></li>
<li>A silver <Link to="/rule/aspis_consortium">Aspis Consortium</Link> badge and three bronze Aspis Consortium badges</li>
<li><Link to="/eq-misc/bullseye_lantern">Bullseye lanterns</Link> (2; full and lit)</li>
<li><Link to="/eq-weapon/dagger">Daggers</Link> (2)</li>
<li><Link to="/eq-misc/disguise_kit">Disguise kit</Link></li>
<li><Link to="/eq-misc/healers_kit">Healer's kit</Link></li>
<li><Link to="/eq-misc/hemp_rope">Hemp ropes</Link> (2; 50-foot coil)</li>
<li><Link to="/eq-misc/light_combat_trained_horse">Light combat-trained horse</Link> with a <Link to="/eq-misc/military_saddle">military saddle</Link></li>
<li><Link to="/eq-misc/mirror">Mirrors</Link> (2; highly polished 2-foot-by-4-foot steel mirrors)</li>
<li><Link to="/eq-misc/nobles_outfit">Noble's outfit</Link> with jewelry worth 200 gold pieces</li>
<li>Oil of <Link to="/spell/bless_weapon">bless weapon</Link></li>
<li>Oil of <Link to="/spell/daylight">daylight</Link></li>
<li><Link to="/eq-misc/pole">Poles</Link> (2; 10-foot length)</li>
<li>Potion of <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link></li>
<li><Link to="/eq-misc/sack">Sacks</Link> (2)</li>
<li><Link to="/magic-wondrous/universal_solvent">Universal solvent</Link></li>
<li>Wand of <Link to="/spell/prestidigitation">prestidigitation</Link> (CL 1st, 5 charges)</li>
</ul>
<h3 id="magic-wondrous-pathfinder_greatcoat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fabricate">fabricate</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _paupers_robes = {title: "Pauper's Robes", jsx: <><h2 id="magic-wondrous-paupers_robes-paupers-robes">Pauper's Robes</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 15</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> 4 lbs.</p>
<p>Dirt and grime from city streets cling to these dirty brown robes, covering them in an ever-present film of filth. A set of pauper's robes surrounds its wearer in mystery, making it difficult for creatures to remember details about him. Creatures that attempt to remember details of their interactions with the wearer of a set of pauper's robes must make a successful Will save to do so: recalling general details about the wearer (such as gender or race) requires a successful DC 13 Will save, and recalling more specific information (such as name, distinguishing features, or mannerisms) requires a successful DC 16 Will save. If the wearer of the robes takes any action that counts as an attack (as defined by the <Link to="/spell/invisibility">invisibility</Link> spell), creatures witnessing that action are immune to the memory-fogging influence of the pauper's robes for all interactions with the wearer over the next 24 hours.</p>
<p>As a standard action, the wearer of a set of pauper's robes can cause the garment to tarnish and dirty any valuables he carries, making jewelry appear to be little more than beads and twine or a magical sword look rusted and dull. Anyone who examines or interacts with such an object can see through the guise with a successful DC 13 Will save. This effect ends immediately once the object leaves the wearer's possession.</p>
<h3 id="magic-wondrous-paupers_robes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/memory_lapse">memory lapse</Link>; <strong>Cost</strong> 1,200 gp</p>
</>};
const _penitents_robes = {title: "Penitent's Robes", jsx: <><h2 id="magic-wondrous-penitents_robes-penitents-robes">Penitent's Robes</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 155</Link><br/><strong>Aura</strong> strong varied; <strong>CL</strong> 16th<br/><strong>Slot</strong> body; <strong>Price</strong> 95,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This humble, threadbare robe grants a +1 resistance bonus on all saving throws. A mythic wearer can unlock additional powers by upholding vows. The wearer selects up to five vows, but no more than she has mythic tiers. For each vow taken, the wearer must expend one use of mythic power. This use can't be regained as long as the vow is kept and the wearer retains the robe. After 24 hours adhering to one or more vows, the wearer gains additional benefits from the robe.</p>
<ul>
<li>1 vow: +2 resistance bonus on all saving throws, +1 competence bonus on all skill checks</li>
<li>2 vows: +3 resistance bonus on all saving throws, +4 armor bonus to AC</li>
<li>3 vows: +4 resistance bonus on all saving throws, +2 competence bonus on all skill checks</li>
<li>4 vows: +5 resistance bonus on all saving throws, +6 armor bonus to AC</li>
<li>5 vows: +8 armor bonus to AC, and all save DCs for the wearer's spells increase by 1</li>
</ul>
<p>The wearer receives the bonuses from lower levels as well. For example, with 3 vows, the wearer receives a +4 resistance bonus on saving throws, a +2 competence bonus on all skill checks, and a +4 armor bonus to AC. The armor bonus provided by the robe can be further improved by <Link to="/spell/magic_vestment">magic vestment</Link> and similar spells. The wearer can select from the following vows.</p>
<ul>
<li>Abstain from consuming meat and touching dead creatures.</li>
<li>Abstain from consuming liquor, drugs, and similar substances, including any magic item that takes effect through eating or drinking.</li>
<li>Carry nothing made of metal.</li>
<li>Refrain from dealing lethal damage.</li>
<li>Refrain from speaking.</li>
<li>Refrain from touching others, including touching them with or through clothing.</li>
<li>Speak and write only the truth.</li>
</ul>
<p>If a vow is broken, the robe's benefits immediately drop to those granted by the number of vows still kept. Broken vows can be regained only by way of an <Link to="/spell/atonement">atonement</Link> spell.</p>
<h3 id="magic-wondrous-penitents_robes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/magic_vestment">magic vestment</Link>, <Link to="/spell/prayer">prayer</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 47,500 gp</p>
</>};
const _pressure_suit = {title: "Pressure Suit", jsx: <><h2 id="magic-wondrous-pressure_suit-pressure-suit">Pressure Suit</h2>
<p><strong>Sources</strong> <Link to="/source/distant_worlds">Distant Worlds pg. 55</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> body and helm (see text); <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This magical full-body suit completely protects the wearer from temperature extremes (as if by <em>endure elements</em>) and pressure dangers of hard vacuum and all worlds in the system (save the sun), though it only carries enough air for 3 days before it must be recharged in breathable atmosphere (such as that inside a ship). If the suit's seal is broken - such as the helmet being removed to eat or drink - all the air escapes in 2d6 rounds. A suit with a broken seal confers only the benefits of <em>endure elements.</em> The suit automatically repairs small holes, but if it is struck by a critical hit from a piercing or slashing weapon, the wearer of the pressure suit must succeed at a Reflex save (DC equal to the opponent's confirmation roll) or the seal breaks. A suit with a broken seal can be repaired with a DC 18 <Link to="/skill/craft">Craft (armor)</Link> check or a <Link to="/spell/make_whole">make whole</Link> spell. The suit does not compensate for changes in gravity. Wearing a pressure suit imposes a -1 armor check penalty; this penalty stacks with those provided by other equipment (such as armor). Since it takes up both the body and helm slots, armor can be worn over a pressure suit, but robes and helms cannot.</p>
<h3 id="magic-wondrous-pressure_suit-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/gust_of_wind">gust of wind</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _resplendent_robe_of_the_thespian = {title: "Resplendent Robe of the Thespian", jsx: <><h2 id="magic-wondrous-resplendent_robe_of_the_thespian-resplendent-robe-of-the-thespian">Resplendent Robe of the Thespian</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 216</Link><br/><strong>Aura</strong> strong varied; <strong>CL</strong> 16th<br/><strong>Slot</strong> body; <strong>Price</strong> 75,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These magnificent vestments disguise the presence of armor as normal clothing (as the <Link to="/magic-enh/glamered">glamered</Link> armor property). When worn by a <Link to="/class/bard">bard</Link>, the robe grants the wearer the following powers:</p>
<ul>
<li>Spell resistance 18</li>
<li>+4 resistance bonus on all saving throws</li>
<li>+2 enhancement bonus on caster level checks made to overcome spell resistance</li>
</ul>
<p>Bards and those who fancy themselves actors or performers commission versions of these robes using only the finest fabric.</p>
<h3 id="magic-wondrous-resplendent_robe_of_the_thespian-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/antimagic_field">antimagic field</Link>, <Link to="/spell/break_enchantment">break enchantment</Link>, <Link to="/spell/greater_heroism">greater heroism</Link>, <Link to="/spell/veil">veil</Link>; <strong>Cost</strong> 37,500 gp</p>
</>};
const _robe_of_arcane_heritage = {title: "Robe of Arcane Heritage", jsx: <><h2 id="magic-wondrous-robe_of_arcane_heritage-robe-of-arcane-heritage">Robe of Arcane Heritage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 216</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 308</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> body; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These elegant, dark purple robes are usually decorated with gold stitching suggesting a particular <Link to="/ability/sorcerer_bloodlines">sorcerer bloodline</Link>, though some might indicate a family tree. When a sorcerer dons a robe of arcane heritage, the stitching pulls itself apart and reweaves to match her particular sorcerer bloodline. The wearer treats her sorcerer level as 4 higher than normal for the purpose of determining what bloodline powers she can use and their effects.</p>
<h3 id="magic-wondrous-robe_of_arcane_heritage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/speak_with_dead">speak with dead</Link>, creator must be a sorcerer; <strong>Cost</strong> 8,000 gp</p>
</>};
const _robe_of_blending = {title: "Robe of Blending", jsx: <><h2 id="magic-wondrous-robe_of_blending-robe-of-blending">Robe of Blending</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 216</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 527</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 8,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>Once per day this simple woolen robe allows you to assume the form of another humanoid creature, as if using <em>alter self.</em> This change lasts for 1 hour, although you can end it prematurely as a free action. While in this form, you also gain the ability to speak and understand the basic racial languages of your chosen form. For example, if you take the form of an orc, you can speak and understand Orc.</p>
<h3 id="magic-wondrous-robe_of_blending-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/tongues">tongues</Link>; <strong>Cost</strong> 4,200 gp</p>
</>};
const _robe_of_bones = {title: "Robe of Bones", jsx: <><h2 id="magic-wondrous-robe_of_bones-robe-of-bones">Robe of Bones</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 217</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 527</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 6th<br/><strong>Slot</strong> body; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>This sinister item functions much like a <Link to="/magic-wondrous/robe_of_useful_items">robe of useful items</Link>, but specifically for the serious necromancer. It appears to be an unremarkable robe, but a character who dons it notes that it is adorned with small embroidered figures representing undead creatures. Only the wearer of the robe can see the embroidery, recognize them as the creatures they become, and detach them. One figure can be detached each round. Detaching a figure causes it to become an actual undead creature (see the list below). The skeleton or zombie is not under the control of the wearer of the robe, but may be subsequently commanded, rebuked, turned, or destroyed. A newly created robe of bones always has two embroidered figures of each of the following undead:</p>
<ul>
<li>Human <Link to="/template/skeleton">skeleton</Link></li>
<li><Link to="/monster/wolf">Wolf</Link> skeleton</li>
<li><Link to="/monster/heavy_horse">Heavy horse</Link> skeleton</li>
<li>Tough<sup><InnerLink showBacklink="backlink-magic-wondrous-robe_of_bones-ref-T-1" id="magic-wondrous-robe_of_bones-ref-T-1" data-hash-target to="magic-wondrous-robe_of_bones-T">1</InnerLink></sup> human <Link to="/template/zombie">zombie</Link></li>
<li>Fast <Link to="/monster/goblin">goblin</Link> zombie</li>
<li>Plague <Link to="/monster/ogre">ogre</Link> zombie</li>
</ul>
<h3 id="magic-wondrous-robe_of_bones-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_dead">animate dead</Link>; <strong>Cost</strong> 1,200 gp</p>
<section data-footnotes>
<h3 id="magic-wondrous-robe_of_bones-label">Footnotes</h3>
<ol>
<li id="magic-wondrous-robe_of_bones-T">
<p>No such zombie (or human) type exists. According to someone at Paizo, this should just be the default human zombie. Source: <a href="https://paizo.com/threads/rzs2kuwd?Tough-Human-Zombie-Statblock-and-additional">paizo.com forums</a> <em>(link opens in outside browser)</em> <InnerLink id="backlink-magic-wondrous-robe_of_bones-ref-T-1" data-hash-target to="magic-wondrous-robe_of_bones-ref-T-1" aria-label="Back to reference T-1">↩</InnerLink></p>
</li>
</ol>
</section>
</>};
const _robe_of_components = {title: "Robe of Components", jsx: <><h2 id="magic-wondrous-robe_of_components-robe-of-components">Robe of Components</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 217</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> body; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The pockets of this simple blue robe always seem to carry just what the wearer needs whenever she casts a spell. The robe functions as a <Link to="/eq-misc/spell_component_pouch">spell component pouch</Link>, providing any spell components or focuses that are necessary for the wearer's spellcasting. The robe can even produce spell components or focuses with a specific cost, though it provides no more than 50 gp worth of such materials in any single day. The materials supplied by the robe are suitable only for spellcasting, and disappear if they leave the wearer's person or when the spell requiring them is cast.</p>
<h3 id="magic-wondrous-robe_of_components-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/minor_creation">minor creation</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _robe_of_eyes = {title: "Robe of Eyes", jsx: <><h2 id="magic-wondrous-robe_of_eyes-robe-of-eyes">Robe of Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 217</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 527</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> body; <strong>Price</strong> 120,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This valuable garment appears to be a normal robe until it is put on. Its wearer is able to see in all directions at the same moment due to scores of visible, magical eye-like patterns that adorn the robe. She also gains 120-foot darkvision.</p>
<p>The robe of eyes sees all forms of invisible or ethereal creatures or objects within 120 feet. The wearer of a robe of eyes gains a +10 competence bonus on Perception checks. She retains her Dexterity bonus to AC even when flat-footed, and can't be <Link to="/rule/flanked">flanked</Link>. She is not able to avert or close her eyes when confronted by a creature with a <Link to="/umr/gaze">gaze</Link> attack.</p>
<p>A <Link to="/spell/light">light</Link> or <Link to="/spell/continual_flame">continual flame</Link> spell cast directly on a robe of eyes causes the wearer to be <Link to="/misc/blinded">blinded</Link> for 1d3 minutes. A <Link to="/spell/daylight">daylight</Link> spell blinds the wearer for 2d4 minutes.</p>
<h3 id="magic-wondrous-robe_of_eyes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 60,000 gp</p>
</>};
const _robe_of_gates = {title: "Robe of Gates", jsx: <><h2 id="magic-wondrous-robe_of_gates-robe-of-gates">Robe of Gates</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 217</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> body; <strong>Price</strong> 64,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Silver circles and conjuring runes decorate this black robe. Three times per day when the wearer uses a summoning spell or spell-like ability to summon a variable number of creatures, he can choose to summon the maximum number of creatures possible. Creatures summoned in this way step from the shadowy folds of the robe, and appear adjacent to the wearer. If there isn't sufficient room for all the creatures to appear, the extra creatures are wasted and do not appear.</p>
<p>If the wearer is a <Link to="/class/summoner">summoner</Link>, he can call upon the robe to summon his eidolon as a standard action once per day. It must appear adjacent to the summoner when called this way.</p>
<h3 id="magic-wondrous-robe_of_gates-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/maximize_spell">Maximize Spell</Link>, <Link to="/spell/gate">gate</Link>, <Link to="/spell/summon_eidolon">summon eidolon</Link>; <strong>Cost</strong> 32,000 gp</p>
</>};
const _robe_of_infinite_twine = {title: "Robe of Infinite Twine", jsx: <><h2 id="magic-wondrous-robe_of_infinite_twine-robe-of-infinite-twine">Robe of Infinite Twine</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 217</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> body; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This coarse hempen robe seems made from a single strand of twine. The wearer can draw up to 30 feet of <Link to="/eq-misc/twine">twine</Link> or up to 10 feet of <Link to="/eq-misc/hemp_rope">hemp rope</Link> per round from the robe without harming it. As an immediate action, the wearer can draw up to 150 feet of twine or 50 feet of rope from the robe, but this gives the robe the <Link to="/misc/broken">broken</Link> condition and suppresses its powers until it is repaired. Twine or rope drawn from the robe remains connected until cut or torn, but is treated as common material rather than part of a magic item. Pieces removed become normal twine or rope.</p>
<h3 id="magic-wondrous-robe_of_infinite_twine-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/minor_creation">minor creation</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _robe_of_magma = {title: "Robe of Magma", jsx: <><h2 id="magic-wondrous-robe_of_magma-robe-of-magma">Robe of Magma</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 31</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> body; <strong>Price</strong> 112,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These striking black robes are lined with glowing cracks, and resemble flows of partially cooled magma. They allow the wearer not only to survive within areas of lava and magma, but also to conjure molten rock from the earth. The wearer gains fire resistance 20 and immunity to fire damage from lava and magma. Additionally, while submerged in lava or magma, the wearer can breathe normally, gains a +5 bonus on <Link to="/skill/swim">Swim</Link> checks, and can see through the substance as clearly as if it were water.</p>
<p>Once per day as a full-round action, the wearer of a robe of magma can conjure a great burst of magma from deep below the surface. This ability can be used only while the wearer is on the Material Plane, and only while on solid ground on a planetary body. The deeper beneath a planet's surface the wearer is, the sooner the magma arrives. If the wearer uses this ability while 8,000 feet (or more) below the surface, the magma arrives instantaneously. If she uses it between 2,000 and 8,000 feet below the surface, the magma arrives at the beginning of the wearer's next turn. If she uses it on the surface or down to 2,000 feet below the surface, the magma arrives in 1d4 rounds. Once the magma arrives, it bursts from the ground in a geyser that sprays up to 40 feet in height and showers a 20-foot radius centered on the location of the wearer when this ability was activated. This deals 20d6 points of fire damage to creatures in the area (Reflex DC 22 half) and creates a shallow pool of lava in the area of the burst. The magma geyser continues for 1d3 rounds. For each round that the geyser continues, the pool of lava expands its radius by 10 feet. Creatures that enter the pool of lava or begin their turn in this area take 2d6 points of fire damage. Once the magma geyser stops, this pool cools and hardens over the course of 1d3 rounds. The magma arrives through an extradimensional space and does not impact any features or terrain located under its point of conjuration.</p>
<h3 id="magic-wondrous-robe_of_magma-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/protection_from_energy">protection from energy</Link>, <Link to="/spell/wall_of_lava">wall of lava</Link>; <strong>Cost</strong> 56,000 gp</p>
</>};
const _robe_of_needles = {title: "Robe of Needles", jsx: <><h2 id="magic-wondrous-robe_of_needles-robe-of-needles">Robe of Needles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 217</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> body; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This dark, hooded robe has six long, silvery, razor-sharp needles protruding from the bottom of its loose sleeves, three on each side. The wearer can launch one needle as a ranged touch attack. The needle counts as a thrown weapon with a range increment of 10 feet. If the needle hits, it embeds itself in the target's flesh, dealing 1 point of piercing damage and 1 point of <Link to="/rule/bleed">bleed</Link> damage. A creature can pull out the needle as a full-round action, which ends the bleed effect. The needle is destroyed if an attack with it misses or when it is removed from a creature it was embedded in. The robe regrows all spent needles each morning.</p>
<h3 id="magic-wondrous-robe_of_needles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bleed">bleed</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _robe_of_powerlessness = {title: "Robe of Powerlessness", jsx: <><h2 id="magic-wondrous-robe_of_powerlessness-robe-of-powerlessness">Robe of Powerlessness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 350</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 542</Link></p>
<p><strong>Aura</strong> strong transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> body; <strong>Weight</strong> 1 lb.</p>
<p>A robe of powerlessness appears to be a magic robe of another sort. As soon as a character dons this garment, she takes a -10 penalty to Strength, as well as to Intelligence, Wisdom, or Charisma, forgetting spells and magic knowledge accordingly. If the character is a spellcaster, the robe targets the character's primary spellcasting score, otherwise it targets Intelligence. The robe can be removed easily, but in order to restore mind and body, the character must receive a <Link to="/spell/remove_curse">remove curse</Link> spell followed by <Link to="/spell/heal">heal</Link>.</p>
<h3 id="magic-wondrous-robe_of_powerlessness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/robe_of_blending">robe of blending</Link>, <Link to="/magic-wondrous/robe_of_bones">robe of bones</Link>, <Link to="/magic-wondrous/robe_of_eyes">robe of eyes</Link>, <Link to="/magic-wondrous/robe_of_scintillating_colors">robe of scintillating colors</Link>, <Link to="/magic-wondrous/robe_of_stars">robe of stars</Link>, <Link to="/magic-wondrous/robe_of_the_archmagi">robe of the archmagi</Link>, <Link to="/magic-wondrous/robe_of_useful_items">robe of useful items</Link>; <strong>Cost</strong> -</p>
</>};
const _robe_of_runes = {title: "Robe of Runes", jsx: <><h2 id="magic-wondrous-robe_of_runes-robe-of-runes">Robe of Runes</h2>
<p><strong>Sources</strong> <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 422</Link>, <Link to="/source/pathfinder_4_fortress_of_the_stone_giants">Pathfinder #4: Fortress of the Stone Giants pg. 50</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> body; <strong>Price</strong> 44,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This robe is made of crimson silk and emblazoned with dozens of spindly Thassilonian runes, each symbolizing a different type of magical effect or syllable of power. Though favored by wizards, this robe can provide some benefit to any spellcasting creature. While worn, it grants a +4 enhancement bonus to Intelligence and allows the wearer to recall, as a free action, up to four levels of spells per day that he had prepared and then cast. Each time a spell is recalled and prepared again in this manner, the sudden rush of magical energy infuses the wearer with power. For 1 round after recalling a spell, the wearer's spell save DCs and attack rolls made with spells gain a +2 enhancement bonus.</p>
<h3 id="magic-wondrous-robe_of_runes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/limited_wish">limited wish</Link>; <strong>Cost</strong> 22,000 gp</p>
</>};
const _robe_of_scintillating_colors = {title: "Robe of Scintillating Colors", jsx: <><h2 id="magic-wondrous-robe_of_scintillating_colors-robe-of-scintillating-colors">Robe of Scintillating Colors</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 218</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 528</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 11th<br/><strong>Slot</strong> body; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of this robe can cause the garment to display a shifting pattern of incredible hues, color after color cascading from the upper part of the robe to the hem in sparkling rainbows of dazzling light. The colors daze those near the wearer, conceal the wearer, and illuminate the surroundings. It takes 1 full round after the wearer speaks the command word for the colors to start flowing on the robe. The colors create the equivalent of a <Link to="/umr/gaze">gaze</Link> attack with a 30-foot range. Those who look at the wearer are <Link to="/misc/dazed">dazed</Link> for 1d4+1 rounds (Will DC 16 negates). This is a mind-affecting pattern effect.</p>
<p>Every round of continuous scintillation of the robe gives the wearer better <Link to="/rule/concealment">concealment</Link>. The miss chance on attacks against the wearer starts at 10% and increases by 10% each round until it reaches 50% (total concealment). Additionally the robe continuously illuminates a 30-foot radius. The effect can be used no more than a total of 10 rounds per day.</p>
<h3 id="magic-wondrous-robe_of_scintillating_colors-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blur">blur</Link>, <Link to="/spell/rainbow_pattern">rainbow pattern</Link>; <strong>Cost</strong> 13,500 gp</p>
</>};
const _robe_of_stars = {title: "Robe of Stars", jsx: <><h2 id="magic-wondrous-robe_of_stars-robe-of-stars">Robe of Stars</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 218</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 528</Link><br/><strong>Aura</strong> strong varied; <strong>CL</strong> 15th<br/><strong>Slot</strong> body; <strong>Price</strong> 58,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This garment is typically black or dark blue and embroidered with small white or silver stars. The robe has three magical powers.</p>
<p>It enables the wearer to travel physically to the Astral Plane, at will and on command as if using the <em>plane shift</em> spell. Once he has done so, the wearer can also return to his plane of origin on command, also as per the <em>plane shift</em> spell.</p>
<p>This robe also grants its wearer a +1 luck bonus on all saving throws.</p>
<p>Finally, the wearer can use up to six of the embroidered stars on the chest portion of the robe as +5 <Link to="/eq-weapon/shuriken">shuriken</Link>. The robe grants its wearer proficiency with such weapons. Each shuriken disappears after it is used. The stars are replenished once per month.</p>
<h3 id="magic-wondrous-robe_of_stars-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_missile">magic missile</Link>, <Link to="/spell/astral_projection">astral projection</Link> or <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 29,000 gp</p>
</>};
const _robe_of_the_archmagi = {title: "Robe of the Archmagi", jsx: <><h2 id="magic-wondrous-robe_of_the_archmagi-robe-of-the-archmagi">Robe of the Archmagi</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 218</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 527</Link><br/><strong>Aura</strong> strong varied; <strong>CL</strong> 14th<br/><strong>Slot</strong> body; <strong>Price</strong> 75,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This normal-appearing garment is attuned to one of three types of alignment. It can be white (01-45 on d%, good alignment), gray (46-75, neither good nor evil alignment), or black (76-100, evil alignment). To most wearers, the robe offers no powers or has no effects unless the wearer's alignment doesn't match that of the robe (see below). Only an arcane spellcaster can fully realize this potent magic item's powers once the robe is donned. These powers are as follows.</p>
<ul>
<li>+5 armor bonus to AC</li>
<li>Spell resistance 18</li>
<li>+4 resistance bonus on all saving throws</li>
<li>+2 enhancement bonus on caster level checks made to overcome spell resistance</li>
</ul>
<p>If a white robe is donned by an evil character, she immediately gains three permanent <Link to="/rule/negative_levels">negative levels</Link>. The same is true with respect to a black robe donned by a good character. An evil or good character who puts on a gray robe, or a neutral character who dons either a white or black robe, gains two permanent negative levels. These negative levels remain as long as the garment is worn and cannot be overcome in any way (including through restoration spells). Negative levels are immediately removed if the robe is removed from the wearer.</p>
<h3 id="magic-wondrous-robe_of_the_archmagi-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/antimagic_field">antimagic field</Link>, <Link to="/spell/mage_armor">mage armor</Link> or <Link to="/spell/shield_of_faith">shield of faith</Link>, creator must be of same alignment as robe; <strong>Cost</strong> 37,500 gp</p>
</>};
const _robe_of_the_master_of_masters = {title: "Robe of the Master of Masters", jsx: <><h2 id="magic-wondrous-robe_of_the_master_of_masters-robe-of-the-master-of-masters">Robe of the Master of Masters</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 268</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 59</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> body; <strong>Price</strong> 2,300 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This brightly colored robe is made of fine silk and cut in the Vudrani style. As a full-round action, the wearer can shift the original hue of the garment slightly (from red to pink or crimson, from blue to cyan or sapphire, and so on) or return it to its original color; the robe instantly reverts to its original color if the wearer removes the robe. The wearer gains a +2 competence bonus on <Link to="/skill/perform">Perform (dance)</Link> checks.</p>
<p>If <Link to="/faith/irori">Irori</Link> is the wearer's patron, once per day as a free action the wearer can touch a tiny button on the wrist of the robe, granting her the effects of <em>haste</em> for 1 round. Once per day, the wearer can also perform a healing dance that lasts 5 minutes. When she does so, up to 7 allies within 30 feet heal 1 hit point.</p>
<h3 id="magic-wondrous-robe_of_the_master_of_masters-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/haste">haste</Link>, creator must have 5 ranks in Perform (dance); <strong>Cost</strong> 1,150 gp</p>
</>};
const _robe_of_the_overmind = {title: "Robe of the Overmind", jsx: <><h2 id="magic-wondrous-robe_of_the_overmind-robe-of-the-overmind">Robe of the Overmind</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 9</Link><br/><strong>Aura</strong> strong abjuration and conjuration; <strong>CL</strong> 14th<br/><strong>Slot</strong> body; <strong>Price</strong> 75,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This regal-looking robe is trimmed with softly glowing sigils and attuned to one of three types of alignment. It can have geometric sigils (1-45 on d%, lawful alignment), smooth sigils (46-75 on d%, neither lawful nor chaotic alignment), or jagged sigils (76-100 on d%, chaotic alignment). To most wearers, the robe offers no powers and has no effects unless the wearer's alignment doesn't match that of the robe (see below). Only a psychic spellcaster can call upon this potent magic item's powers, which are as follows.</p>
<ul>
<li>The wearer gains DR 2/-.</li>
<li>The wearer gains spell resistance 18.</li>
<li>The wearer gains a +4 resistance bonus on all saving throws.</li>
<li>The save DCs of all spells with the mind-affecting descriptor cast by the wearer increase by 1.</li>
</ul>
<p>If a robe with geometric sigils is donned by a chaotic character, he immediately gains 3 permanent <Link to="/rule/negative_levels">negative levels</Link>. The same is true with respect to a robe with jagged sigils donned by a lawful character. A lawful or chaotic character who puts on a robe with smooth sigils, or a neutral character who dons a robe with geometric or jagged sigils, gains 2 permanent negative levels. These negative levels remain as long as the garment is worn and cannot be overcome in any way (including through restoration spells). Negative levels are immediately removed if the robe is removed from the wearer.</p>
<h3 id="magic-wondrous-robe_of_the_overmind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/antimagic_field">antimagic field</Link>, <Link to="/spell/mage_armor">mage armor</Link>, creator must be of same alignment as robe; <strong>Cost</strong> 37,500 gp</p>
</>};
const _robe_of_useful_items = {title: "Robe of Useful Items", jsx: <><h2 id="magic-wondrous-robe_of_useful_items-robe-of-useful-items">Robe of Useful Items</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 218</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 528</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> body; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>A character who dons this battered robe notes that its patches rearrange into the shapes of various helpful but mundane items. Only the wearer of the robe can see the true shapes of these patches, recognize them for what items they become, and detach them. One patch can be detached each round. Detaching a patch causes it to become an actual item, as indicated below. A newly created robe of useful items always has two each of the following patches:</p>
<ul>
<li><Link to="/eq-weapon/dagger">Dagger</Link></li>
<li><Link to="/eq-misc/bullseye_lantern">Bullseye lantern</Link> (full and lit)</li>
<li><Link to="/eq-misc/mirror">Mirror</Link> (a highly polished 2-foot-by-4-foot steel mirror)</li>
<li><Link to="/eq-misc/pole">Pole</Link> (10-foot length)</li>
<li><Link to="/eq-misc/hemp_rope">Hempen rope</Link> (50-foot coil)</li>
<li><Link to="/eq-misc/sack">Sack</Link></li>
</ul>
<p>In addition, the robe has several other patches. Roll 4d4 for the number of other patches and then roll for each patch on the table below to determine its nature.</p>
<ScrollContainer id="magic-wondrous-robe_of_useful_items--table-0"><table>
<thead>
<tr>
<th>d%</th>
<th>Result</th>
</tr>
</thead>
<tbody><tr>
<td>01-08</td>
<td>Bag of 100 gold pieces</td>
</tr>
<tr>
<td>09-15</td>
<td>Coffer, silver (6 in. by 6 in. by 1 ft.), 500 gp value</td>
</tr>
<tr>
<td>16-22</td>
<td>Door, iron (up to 10 ft. wide and 10 ft. high and barred on one side - must be placed upright, attaches and hinges itself)</td>
</tr>
<tr>
<td>23-30</td>
<td>Gems, 10 (100 gp value each)</td>
</tr>
<tr>
<td>31-44</td>
<td>Ladder, wooden (24 ft. long)</td>
</tr>
<tr>
<td>45-51</td>
<td><Link to="/eq-misc/mule">Mule</Link> (with <Link to="/eq-misc/saddlebags">saddlebags</Link>)</td>
</tr>
<tr>
<td>52-59</td>
<td>Pit, open (10 ft. by 10 ft. by 10 ft.)</td>
</tr>
<tr>
<td>60-68</td>
<td>Potion of <Link to="/spell/cure_serious_wounds">cure serious wounds</Link></td>
</tr>
<tr>
<td>69-75</td>
<td><Link to="/eq-misc/rowboat">Rowboat</Link> (12 ft. long)</td>
</tr>
<tr>
<td>76-83</td>
<td>Minor scroll of one randomly determined spell</td>
</tr>
<tr>
<td>84-90</td>
<td>War dogs, pair (treat as <Link to="/eq-misc/riding_dog">riding dogs</Link>)</td>
</tr>
<tr>
<td>91-96</td>
<td>Window (2 ft. by 4 ft., up to 2 ft. deep)</td>
</tr>
<tr>
<td>97-100</td>
<td><Link to="/eq-misc/portable_ram">Portable ram</Link></td>
</tr>
</tbody></table></ScrollContainer>
<p>Multiple items of the same kind are permissible. Once removed, a patch cannot be replaced.</p>
<h3 id="magic-wondrous-robe_of_useful_items-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fabricate">fabricate</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _robe_of_vermin = {title: "Robe of Vermin", jsx: <><h2 id="magic-wondrous-robe_of_vermin-robe-of-vermin">Robe of Vermin</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 350</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 542</Link></p>
<p><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> body; <strong>Weight</strong> 1 lb.</p>
<p>The wearer notices nothing unusual when the robe is donned, and it functions normally. However, as soon as he is in a situation requiring concentration and action against hostile opponents, the true nature of the garment is revealed: the wearer immediately suffers a multitude of bites from the insects that magically infest the garment. He must cease all other activities in order to scratch, shift the robe, and generally show signs of the extreme discomfort caused by the bites and movement of these pests.</p>
<p>The wearer takes a -5 penalty on initiative checks and a -2 penalty on all attack rolls, saves, and skill checks. If he tries to cast a spell, he must make a <Link to="/rule/concentration">concentration</Link> check (DC 20 + spell level) or lose the spell.</p>
<h3 id="magic-wondrous-robe_of_vermin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/robe_of_blending">robe of blending</Link>, <Link to="/magic-wondrous/robe_of_bones">robe of bones</Link>, <Link to="/magic-wondrous/robe_of_eyes">robe of eyes</Link>, <Link to="/magic-wondrous/robe_of_scintillating_colors">robe of scintillating colors</Link>, <Link to="/magic-wondrous/robe_of_stars">robe of stars</Link>, <Link to="/magic-wondrous/robe_of_the_archmagi">robe of the archmagi</Link>, <Link to="/magic-wondrous/robe_of_useful_items">robe of useful items</Link>; <strong>Cost</strong> -</p>
</>};
const _robes_of_xin_bakrakhan = {title: "Robes of Xin-Bakrakhan", jsx: <><h2 id="magic-wondrous-robes_of_xin_bakrakhan-robes-of-xin-bakrakhan">Robes of Xin-Bakrakhan</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_138_rise_of_new_thassilon">Pathfinder #138: Rise of New Thassilon pg. 70</Link><br/><strong>Aura</strong> strong abjuration and conjuration; <strong>CL</strong> 16th<br/><strong>Slot</strong> body; <strong>Price</strong> 198,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The traditional robes of the Runelord of Wrath are known as the robes of Xin-Bakrakhan. Woven of the finest of crimson silks and accented with precious gold, the robes are surprisingly light and easy to move in. The robes of Xin-Bakrakhan aid and accentuate their wearer's spellcasting ability. They grant a +5 shield bonus and spell resistance 24, and the wearer casts all spells at +1 caster level. Two of the robe's pockets function as <Link to="/magic-wondrous/handy_haversack">handy haversacks</Link>. The wearer of these robes is immune to the effects of <em>calm emotions</em> and can use all skills and abilities that require patience or concentration when under the effects of a <Link to="/spell/rage">rage</Link> spell or similar effect.</p>
<h3 id="magic-wondrous-robes_of_xin_bakrakhan-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/calm_emotions">calm emotions</Link>, <Link to="/spell/protection_from_spells">protection from spells</Link>, <Link to="/spell/shield">shield</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 99,000 gp</p>
</>};
const _robes_of_xin_edasseril = {title: "Robes of Xin-Edasseril", jsx: <><h2 id="magic-wondrous-robes_of_xin_edasseril-robes-of-xin-edasseril">Robes of Xin-Edasseril</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_137_the_city_outside_of_time">Pathfinder #137: The City Outside of Time pg. 56</Link><br/><strong>Aura</strong> strong abjuration and conjuration; <strong>CL</strong> 16th<br/><strong>Slot</strong> body; <strong>Price</strong> 164,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The robes of Xin-Edasseril grant a +5 armor bonus to AC and spell resistance 20, and they cause the wearer to cast all abjuration spells at +1 caster level. Two of the robe's pockets function as <Link to="/magic-wondrous/handy_haversack">handy haversacks</Link>. In addition, the robes protect the wearer with energy resistance 10 for an energy type of the wearer's choice - this energy resistance can be changed once per day as a standard action.</p>
<h3 id="magic-wondrous-robes_of_xin_edasseril-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mage_armor">mage armor</Link>, <Link to="/spell/protection_from_spells">protection from spells</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 82,000 gp</p>
</>};
const _robes_of_xin_shalast = {title: "Robes of Xin-Shalast", jsx: <><h2 id="magic-wondrous-robes_of_xin_shalast-robes-of-xin-shalast">Robes of Xin-Shalast</h2>
<p><strong>Sources</strong> <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 423</Link>, <Link to="/source/pathfinder_6_spires_of_xin_shalast">Pathfinder #6: Spires of Xin-Shalast pg. 65</Link><br/><strong>Aura</strong> strong abjuration and conjuration; <strong>CL</strong> 16th<br/><strong>Slot</strong> body; <strong>Price</strong> 198,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The traditional robes of the runelord of greed are known as the robes of Xin-Shalast. Rarely, a runelord would grant a favored apprentice a set of these robes. Woven of the finest of silks and accented with precious gemstones and gold, the robes are surprisingly light and easy to move in. Robes of Xin-Shalast aid and accentuate their wearer's spellcasting ability. They grant a +6 armor bonus and spell resistance 24, but also cause the wearer to cast all spells at +1 caster level. Two of the robe's pockets function as <Link to="/magic-wondrous/handy_haversack">handy haversacks</Link>. The wearer of these robes is immune to the effects of the occluding field that surrounds the Spires of Xin-Shalast, and can exist comfortably in all <Link to="/rule/high_altitude">high altitudes</Link>, including within the death zone at altitudes of 26,000 feet and higher.</p>
<h3 id="magic-wondrous-robes_of_xin_shalast-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/mage_armor">mage armor</Link>, <Link to="/spell/protection_from_spells">protection from spells</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 99,000 gp</p>
</>};
const _seamless_skin = {title: "Seamless Skin", jsx: <><h2 id="magic-wondrous-seamless_skin-seamless-skin">Seamless Skin</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 55</Link><br/><strong>Aura</strong> strong necromancy; <strong>CL</strong> 14th<br/><strong>Slot</strong> body; <strong>Price</strong> 70,000 gp; <strong>Weight</strong> 8 lbs.</p>
<p>This skin has been removed from a specific humanoid creature and magically preserved. Any creature no more than one size category different from the skinned creature can don the skin with 1 minute of effort, whereupon the wearer gains the physical appearance and size the skinned creature had while alive, and its abilities as defined in the spell <em>alter self,</em> but not its immunities, weapon proficiencies, weaknesses, or spell resistance. Otherwise, this effect functions like <em>recorporeal incarnation.</em></p>
<h3 id="magic-wondrous-seamless_skin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/recorporeal_incarnation">recorporeal incarnation</Link>; <strong>Cost</strong> 35,000 gp</p>
</>};
const _shimmering_kilt = {title: "Shimmering Kilt", jsx: <><h2 id="magic-wondrous-shimmering_kilt-shimmering-kilt">Shimmering Kilt</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_sea">Blood of the Sea pg. 20</Link><br/><strong>Aura</strong> moderate illusion and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 25,200 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This iridescent kilt seems stitched together from thousands of tiny scales. When an aquatic creature with a tail dons the shimmering kilt, her tail transforms into legs and feet, allowing her to walk on land. The wearer loses her swim speed but gains a base land speed of 30 feet (or 20 feet if the wearer is Small or smaller). This transformation lasts until the shimmering kilt is removed.</p>
<p>As a standard action, the wearer can cause the shimmering kilt to take on the appearance of any suitable garb that covers the legs, such as trousers or a long skirt. The shimmering kilt retains all its properties, including its weight, when so disguised. Only <Link to="/spell/true_seeing">true seeing</Link> or similar magic reveals the true nature of the shimmering kilt when it is disguised.</p>
<h3 id="magic-wondrous-shimmering_kilt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/fins_to_feet">fins to feet</Link>; <strong>Cost</strong> 12,600 gp</p>
</>};
const _shocking_robe = {title: "Shocking Robe", jsx: <><h2 id="magic-wondrous-shocking_robe-shocking-robe">Shocking Robe</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 219</Link><br/><strong>Aura</strong> moderate abjuration and evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This violet and yellow silk robe gives the impression of electricity crackling over its surface. The robe grants the wearer electricity resistance 5 and increases the wearer's caster level for all spells with the electricity descriptor by +1. Once per day on command, the wearer of the robe can emit a 20-foot-radius <Link to="/misc/burst">burst</Link> of electricity. Creatures other than the wearer within the area take 2d6 points of electricity damage (Reflex DC 16 half).</p>
<h3 id="magic-wondrous-shocking_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _shozoku_of_the_night_wind = {title: "Shozoku of the Night Wind", jsx: <><h2 id="magic-wondrous-shozoku_of_the_night_wind-shozoku-of-the-night-wind">Shozoku of the Night Wind</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_50_night_of_frozen_shadows">Pathfinder #50: Night of Frozen Shadows pg. 60</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 4th<br/><strong>Slot</strong> body; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This black bodysuit is of the type typically worn by ninjas and assassins, but it grants its wearer a +2 armor bonus and a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. In addition, if the wearer is in illumination of less than normal light, she can use <em>invisibility,</em> as the spell, once per day. If the wearer is a ninja with the <Link to="/ninjatrick/vanishing_trick">vanishing trick</Link> ninja trick, then the wearer can use that ability twice per day without the expenditure of any ki points and regardless of the surrounding light level.</p>
<h3 id="magic-wondrous-shozoku_of_the_night_wind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _slayers_robe = {title: "Slayer's Robe", jsx: <><h2 id="magic-wondrous-slayers_robe-slayers-robe">Slayer's Robe</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 235</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> body; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This ragged, brown robe could be mistaken for a monk's cassock, but the devotees who wear it are dedicated only to the art of killing. This robe grants the wearer a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks and <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to conceal a weapon, and a +1 resistance bonus on all saving throws. If worn by a <Link to="/class/slayer">slayer</Link>, the resistance bonus on saving throws increases to match the slayer's studied target bonus when he is facing a studied target.</p>
<p>On command, the robe's wearer is able to turn into a brown mist (as the <em>gaseous form</em> spell) for up to 5 minutes per day. This duration doesn't need to be continuous, but must be used in 1-minute increments. While the wearer is in this form, the bonus on Stealth checks increases to +10. The wearer can end this effect as a standard action.</p>
<h3 id="magic-wondrous-slayers_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gaseous_form">gaseous form</Link>, <Link to="/spell/guidance">guidance</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _smugglers_collapsible_robe = {title: "Smuggler's Collapsible Robe", jsx: <><h2 id="magic-wondrous-smugglers_collapsible_robe-smugglers-collapsible-robe">Smuggler's Collapsible Robe</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 219</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> body; <strong>Price</strong> 48,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Appearing to be nothing more than a ratty wool robe with a hood, this garment is an invaluable tool for spies, thieves, and smugglers. On command, the wearer and non-living objects up to her maximum load are sucked into an extradimensional space within the robe, leaving the robe to collapse where the wearer was standing. The robe appears to be merely a pile of discarded clothes, and does not detect as magical or function so long as the wearer is within the extradimensional space.</p>
<p>While inside the extradimensional space, the wearer cannot take most actions, but can breathe comfortably for up to 24 hours. The wearer can see the area around the robe, though special senses such as darkvision or <Link to="/umr/blindsense">blindsense</Link> do not function. The wearer may leave the extradimensional space with a thought as a free action - the only action he can make while inside the extradimensional space. He reappears wearing the robe once more. However, if there is not enough room for the wearer to reappear (for example, if the robe was placed inside a small box) then the wearer cannot leave the extradimensional space.</p>
<p>If the robe is destroyed or its magic suppressed while the wearer is within the extradimensional space, or if he spends 24 hours within it, he and all objects inside reappear instantaneously in the robe's space, and the wearer is <Link to="/misc/dazed">dazed</Link> for one round.</p>
<h3 id="magic-wondrous-smugglers_collapsible_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/secret_chest">secret chest</Link>, <Link to="/spell/magic_aura">magic aura</Link>, <Link to="/spell/arcane_eye">arcane eye</Link>; <strong>Cost</strong> 24,000 gp</p>
</>};
const _sorcerers_robe = {title: "Sorcerer's Robe", jsx: <><h2 id="magic-wondrous-sorcerers_robe-sorcerers-robe">Sorcerer's Robe</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 219</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This dapper robe enables a sorcerer to add the effects of her 1st-level <Link to="/ability/sorcerer_bloodlines">bloodline</Link> power to spells she casts. As a swift action before casting a spell, the wearer expends one use of her 1st-level bloodline power and selects one target of the spell to be affected by that bloodline power. If the spell allows a saving throw, a successful save against the spell means the bloodline power deals half damage (if it normally deals hit point damage) or is negated (if it does not). The robe can be used up to three times per day.</p>
<h3 id="magic-wondrous-sorcerers_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/quicken_spell_like_ability">Quicken Spell-Like Ability</Link>, creator must be a sorcerer; <strong>Cost</strong> 2,500 gp</p>
</>};
const _starfaring_robes = {title: "Starfaring Robes", jsx: <><h2 id="magic-wondrous-starfaring_robes-starfaring-robes">Starfaring Robes</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 270</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> body; <strong>Price</strong> 82,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This simple blue robe appears plain during the day but sparkles in starlight or moonlight. The wearer is constantly protected as if wearing a <Link to="/magic-wondrous/necklace_of_adaptation">necklace of adaptation</Link>. On command, the robe sprouts pale moth wings, allowing the wearer to fly as if using <Link to="/magic-wondrous/wings_of_flying">wings of flying</Link>. In the vacuum of space, the wearer can fly at an incredible speed. Although exact travel times vary, a trip within a single solar system normally takes 3d20 months, while a trip beyond should take 3d20 years (or more, at the GM's discretion), provided the wearer knows the way to its destination. While flying in this fashion, the wearer can enter a state of hibernation (similar to <em>temporal stasis</em>), waking instantly if attacked, upon reaching his destination, or after a set time period (such as a month or year).</p>
<h3 id="magic-wondrous-starfaring_robes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/fly">fly</Link>, <Link to="/spell/interplanetary_teleport">interplanetary teleport</Link>, <Link to="/spell/temporal_stasis">temporal stasis</Link>; <strong>Cost</strong> 41,000 gp</p>
</>};
const _summoners_robe = {title: "Summoner's Robe", jsx: <><h2 id="magic-wondrous-summoners_robe-summoners-robe">Summoner's Robe</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 21</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> body; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A summoner's robe is a finely crafted garment of silk the same color as the endless sky of the Astral Plane. Once per day when casting a <em>summon monster</em> or <em>summon nature's ally</em> spell, the wearer can have the robe absorb one of the creatures summoned rather than have it appear within the spell's range. When this occurs, the robe gains a defensive aura and takes on visual aspects of the absorbed creature (such as becoming red and spiked if absorbing a demon, or manifesting flame patterns if absorbing a fire elemental). The creature does not exist outside its effect as a defensive aura of the robe as detailed below, and cannot be damaged or targeted by most spells. It is still a magical effect, and any spell or ability that could <Link to="/spell/dispel">dispel</Link> or disrupt a creature summoned by <em>summon monster</em> can dispel or disrupt the defensive aura. The defensive aura is also dispelled if the robe enters an area a summoned creature could not enter, or at the end of the duration of the spell that summoned the absorbed creature. If the wearer takes an amount of damage equal to or greater than 5 hit points per level of the spell that summoned the absorbed creature, the defensive aura ends.</p>
<p>As long as the robe has a defensive aura, its wearer gains some of the absorbed creature's defenses and powers. These abilities are determined as if the wearer were using a transmutation <Link to="/spelldef/polymorph">(polymorph)</Link> spell to assume the absorbed creature's form. Unlike a normal polymorph effect, it does not grant her the appearance of the creature (or any bonus to <Link to="/skill/disguise">Disguise</Link>), any movement type, natural attacks (or proficiency with them), or size change. The wearer does not change form, gain any ability score modifiers, have her gear meld into her body, or lose any abilities based on her form. She is considered to be under the effects of a polymorph spell, and cannot be under the effects of another polymorph spell or size-altering magic for the duration of the defensive aura. The abilities the defensive aura grants are otherwise determined by the type of creature absorbed. If the creature is an elemental, the wearer gains the abilities listed in <Link to="/spell/elemental_body_iii">elemental body III</Link>; if it's a plant, the wearer gains the abilities listed in <Link to="/spell/plant_shape_ii">plant shape II</Link>; if it's an undead, the wearer gains the abilities listed in <Link to="/spell/undead_anatomy_iii">undead anatomy III</Link>. If the creature is of any other creature type, the wearer gains the abilities it possesses listed in <Link to="/spell/beast_shape_iv">beast shape IV</Link>.</p>
<h3 id="magic-wondrous-summoners_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/summon_monster_ix">summon monster IX</Link> or <Link to="/spell/summon_natures_ally_ix">summon nature's ally IX</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _travelers_wet_suit = {title: "Traveler's Wet Suit", jsx: <><h2 id="magic-wondrous-travelers_wet_suit-travelers-wet-suit">Traveler's Wet Suit</h2>
<p><strong>Sources</strong> <Link to="/source/aquatic_adventures">Aquatic Adventures pg. 63</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 2,750 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This wet suit protects against <Link to="/rule/cold">environmental cold damage and hypothermia</Link>. Anything stored in its waterproof pockets is kept magically separate from any surrounding water, even if the wearer opens the pocket underwater. Finally, the wearer gains a +2 competence bonus on <Link to="/skill/swim">Swim</Link> checks.</p>
<h3 id="magic-wondrous-travelers_wet_suit-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _unspeakable_ones_vestments = {title: "Unspeakable One's Vestments", jsx: <><h2 id="magic-wondrous-unspeakable_ones_vestments-unspeakable-ones-vestments">Unspeakable One's Vestments</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_113_what_grows_within">Pathfinder #113: What Grows Within pg. 33</Link><br/><strong>Aura</strong> strong varied; <strong>CL</strong> 15th<br/><strong>Slot</strong> body; <strong>Weight</strong> 1 lb.</p>
<p>This robe functions much as a robe of stars, granting its wearer the luck bonus on saving throws, astral travel, and ability to create shuriken made of magically hardened gold. In addition, the wearer gains a +4 armor bonus to his AC.</p>
<p>The robe's curse activates after 1 month of being worn regularly, or just as a creature whose patron is <Link to="/faith/hastur">Hastur</Link> or <Link to="/faith/xhamen_dor">Xhamen-Dor</Link> affects the wearer with a spell or special ability. The wearer loses his luck bonus on saving throws against such effects and instead takes a -4 penalty on those saves. While the curse persists, the wearer takes 1d4 points of <Link to="/rule/wisdom_drain">Wisdom drain</Link> every time he uses the robe to access the Astral Plane, and the shuriken created are +5 <Link to="/magic-enh/anarchic">anarchic</Link> shuriken. After another month of continuous use, the wearer permanently becomes chaotic evil and pursues increasingly delusional goals of domination, enrichment, or anarchy. Once donned, this robe can be removed only with a <Link to="/spell/remove_curse">remove curse</Link> spell.</p>
<h3 id="magic-wondrous-unspeakable_ones_vestments-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/robe_of_stars">robe of stars</Link>; <strong>Cost</strong> -</p>
</>};
const _untouchable_jacket = {title: "Untouchable Jacket", jsx: <><h2 id="magic-wondrous-untouchable_jacket-untouchable-jacket">Untouchable Jacket</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 20</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> body; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black jacket is marked with the insignia of the <Link to="/arc-fighter/druman_blackjacket">Blackjackets</Link>. Once per day, the wearer can speak a command word to gain spell resistance 20 for 3 rounds. This spell resistance ends if the wearer successfully resists a spell as a result of it failing to penetrate his spell resistance. The first time each day that a spell has no effect on the wearer because of spell resistance or a successful saving throw, the jacket becomes charged with abjuration magic and its insignia glows faintly. The wearer can touch the glowing insignia as a standard action to cast <em>dispel magic</em> from the jacket, expending the charge. The charge fades with no effect if unused for 1 hour.</p>
<h3 id="magic-wondrous-untouchable_jacket-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/spell_resistance">spell resistance</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _vestments_of_false_faith = {title: "Vestments of False Faith", jsx: <><h2 id="magic-wondrous-vestments_of_false_faith-vestments-of-false-faith">Vestments of False Faith</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 251</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 8th<br/><strong>Slot</strong> body; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This priestly garment can be commanded to alter its appearance as a standard action, able to reshape itself into ceremonial garb or the everyday habit of a religious functionary of any faith. Vestments of false faith are always emblazoned with the holy symbol and colors of the faith chosen by the wearer, and she can disguise an object held in a hand as a holy symbol, censer, candle, or similar item of religious paraphernalia. This change is a visual illusion (glamer) effect akin to <em>disguise self.</em></p>
<p>The wearer of vestments of false faith gains a +10 bonus on Disguise checks to impersonate a member of the faith she has chosen (this doesn't stack with disguise self and similar effects). She also gains a +5 competence bonus on <Link to="/skill/use_magic_device">Use Magic Device</Link> checks to activate items that duplicate divine spells or emulate a specific religion or alignment, provided they fit the religion she's imitating. If she uses a magic item to produce the effect of a divine spell, she can make it appear to observers as though she were casting the spell, though a <Link to="/skill/spellcraft">Spellcraft</Link> check to identify the spell being cast can identify it as coming from a magic item if the result exceeds the DC by 5 or more.</p>
<p>The wearer's alignment is disguised while wearing vestments of false faith, so that it appears identical to that of the deity whose holy symbol she bears, and her aura is as strong as if she had a number of <Link to="/class/cleric">cleric</Link> levels equal to her Hit Dice. This primarily affects alignment detection; however, once per day as an immediate action, she can function as if she actually had that alignment when she would normally be affected by an alignment-based effect, such as <Link to="/spell/blasphemy">blasphemy</Link>, <Link to="/spell/chaos_hammer">chaos hammer</Link>, <Link to="/spell/forbiddance">forbiddance</Link>, or an <Link to="/magic-enh/unholy">unholy</Link> magic weapon. This effect persists until the end of the wearer's next turn, after which any non-instantaneous effects (such as smite evil) suddenly revert to having the effects they would normally have on a creature of her true alignment.</p>
<h3 id="magic-wondrous-vestments_of_false_faith-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bless">bless</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/misdirection">misdirection</Link>; <strong>Cost</strong> 13,500 gp</p>
</>};
const _vestments_of_war = {title: "Vestments of War", jsx: <><h2 id="magic-wondrous-vestments_of_war-vestments-of-war">Vestments of War</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> body; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> -</p>
<p>These sturdy leather robes are edged in fine linen embroidered with runes and holy symbols. If worn by a creature capable of casting divination spells who worships a specific deity, the embroidery shifts to depict symbols and icons appropriate to the wearer's faith. The robes act as a divine focus for such wearers, allowing spells requiring a divine focus to be cast without the need to hold any other holy symbol. Additionally, if the wearer can <Link to="/ability/channel_energy">channel energy</Link>, she can do so one additional time per day. If the wearer can <Link to="/ability/lay_on_hands">lay on hands</Link>, she instead gains two additional uses of that ability per day. If the wearer has the fervor class feature, she instead gains two additional uses of fervor per day.</p>
<h3 id="magic-wondrous-vestments_of_war-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divine_favor">divine favor</Link>, <Link to="/spell/righteous_might">righteous might</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _voidfrost_robe = {title: "Voidfrost Robe", jsx: <><h2 id="magic-wondrous-voidfrost_robe-voidfrost-robe">Voidfrost Robe</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 219</Link><br/><strong>Aura</strong> moderate abjuration and evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> body; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This blue and white silk robe gives the impression of ice and frozen fog forming over its surface. The robe grants the wearer cold resistance 5 and increases the wearer's caster level for all spells with the cold descriptor by +1. Once per day on command, the wearer of the robe can emit a 20-foot-radius <Link to="/misc/burst">burst</Link> of cold. Creatures other than the wearer within the area take 2d6 points of cold damage (Reflex DC 16 half).</p>
<h3 id="magic-wondrous-voidfrost_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/cone_of_cold">cone of cold</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _witching_gown = {title: "Witching Gown", jsx: <><h2 id="magic-wondrous-witching_gown-witching-gown">Witching Gown</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_47_ashes_at_dawn">Pathfinder #47: Ashes at Dawn pg. 51</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> body; <strong>Price</strong> 35,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Spun from combed cotton, this simple, unassuming gown bears a strong aura of witchcraft. These magical garments are highly sought after by witches, for though anyone may wear a witching gown, only a witch may realize its full potential. A witching gown grants its wearer a +2 resistance bonus on all saving throws and a +2 competence bonus on all Bluff, Diplomacy, and Intimidate skill checks. When worn by a <Link to="/class/witch">witch</Link>, these bonuses double.</p>
<p>In addition, a witch may change the appearance and style of the gown to match her whims (as the <Link to="/magic-enh/glamered">glamered</Link> armor special ability) and adopt virtually any disguise, gaining a +10 bonus on Disguise checks that incorporate the gown's appearance. Only a <Link to="/spell/true_seeing">true seeing</Link> spell or similar magic can pierce this effect.</p>
<p>Lastly, a witch may cast a single touch range spell of 4th level or lower into the gown. Thereafter, the gown holds the magic for up to 24 hours, functioning as a <em>spite</em> spell against the next foe to strike the witch with a successful melee attack or combat maneuver. The gown's spite spell counts as an active spite effect for the witch wearing the gown.</p>
<h3 id="magic-wondrous-witching_gown-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/spite">spite</Link>; <strong>Cost</strong> 17,750 gp</p>
</>};
const _xorn_robe = {title: "Xorn Robe", jsx: <><h2 id="magic-wondrous-xorn_robe-xorn-robe">Xorn Robe</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 219</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> body; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This brown and gray robe is always dirty, and the chest and the back of each shoulder is decorated with a gem-like eye pattern. The wearer gains a +5 bonus on Perception checks, and can use <Link to="/umr/earth_glide">earth glide</Link> to pass through up to 20 feet of natural or worked stone per day. The distance traveled with earth glide does not need to be consecutive, but it must be used in 5-foot increments. The wearer is able to safely chew, swallow, digest, and derive nutrition from gems, precious metals, and metallic ore, with 100 gp worth of these materials sustaining him for 1 full day. If the wearer removes the robe after such a meal, he is <Link to="/misc/sickened">sickened</Link> until 24 hours have passed since the last meal of this kind. Wearing the robe again immediately negates this penalty.</p>
<h3 id="magic-wondrous-xorn_robe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/passwall">passwall</Link>, <Link to="/spell/purify_food_and_drink">purify food and drink</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _all_tools_vest = {title: "All Tools Vest", jsx: <><h2 id="magic-wondrous-all_tools_vest-all-tools-vest">All Tools Vest</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 220</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 300</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> chest; <strong>Price</strong> 1,800 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This well-made leather vest bears numerous shiny metal buttons, which stud a number of bulging pockets. Once per day, as a standard action, the wearer can speak the vest's command word and order it to bring forth all the standard tools required to make checks for any one <Link to="/skill/craft">Craft</Link> skill. These tools appear in the countless pockets of the vest or, if too heavy, on the floor, on a nearby shelf, on a workbench, or in a toolbox or cupboard that appears nearby. Once summoned, they remain for 24 hours or until another creature touches them, whichever comes first.</p>
<h3 id="magic-wondrous-all_tools_vest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/summon_instrument">summon instrument</Link>; <strong>Cost</strong> 900 gp</p>
</>};
const _apron_of_the_careful_chemist = {title: "Apron of the Careful Chemist", jsx: <><h2 id="magic-wondrous-apron_of_the_careful_chemist-apron-of-the-careful-chemist">Apron of the Careful Chemist</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 30</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> chest; <strong>Price</strong> 5,200 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This leather apron is made from several layers of thick hide from common beasts of burden and is reinforced with steel rivets. The apron grants its wearer a +2 enhancement bonus to Dexterity. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the apron is worn. In addition, the wearer gains a +2 competence bonus on Craft (alchemy) checks. When the wearer uses an item on himself or another character that grants an alchemical bonus on saving throws, that bonus increases by 1.</p>
<h3 id="magic-wondrous-apron_of_the_careful_chemist-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, creator must have 2 ranks in Craft (alchemy); <strong>Cost</strong> 2,250 gp</p>
</>};
const _baldric_of_magical_stability_garundi = {title: "Baldric of Magical Stability (Garundi)", jsx: <><h2 id="magic-wondrous-baldric_of_magical_stability_garundi-baldric-of-magical-stability-garundi">Baldric of Magical Stability (Garundi)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 228</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> chest; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This rugged leather baldric can hold one weapon in its sheath and has pockets sufficient to hold one of the following (or gear of an equivalent volume): two cases of bolts, one quiver of arrows, or 40 bullets or firearm cartridges. The wearer, as well as each item held in the baldric, gains a +2 insight bonus on saving throws against the effects of <Link to="/rule/primal_magic">primal magic</Link>. When a Garundi wearer attempts a <Link to="/rule/concentration">concentration</Link> check to prevent a primal magic event from triggering, she gains a +2 competence bonus on the check; she can attempt the check even if she is not a spellcaster, treating her effective caster level as 5 and applying the highest of her Intelligence, Wisdom, and Charisma modifiers.</p>
<h3 id="magic-wondrous-baldric_of_magical_stability_garundi-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/antimagic_field">antimagic field</Link>, creator must be a Garundi; <strong>Cost</strong> 7,000 gp</p>
</>};
const _bandages_of_rapid_recovery = {title: "Bandages of Rapid Recovery", jsx: <><h2 id="magic-wondrous-bandages_of_rapid_recovery-bandages-of-rapid-recovery">Bandages of Rapid Recovery</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 220</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 300</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> chest; <strong>Price</strong> 200 gp; <strong>Weight</strong> 1 lb.</p>
<p>These linen bandages have the same color and softness as the feathers of a dove, but their antiseptic smell suggests a less natural origin. Any creature wrapped in these bandages recovers from wounds and <Link to="/rule/ability_damage">ability damage</Link> each day as if receiving complete <Link to="/rule/bed_rest">bed rest</Link>, regardless of activity. A creature actually receiving long-term care (from the <Link to="/skill/heal">Heal</Link> skill) or complete bed rest while wearing the bandages gains a +4 bonus to its effective level or Hit Dice when determining how many hit points it recovers each day. The bandages are destroyed once removed or when the wearer recovers all hit points and ability damage, whichever comes first.</p>
<h3 id="magic-wondrous-bandages_of_rapid_recovery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>, <Link to="/spell/stabilize">stabilize</Link>; <strong>Cost</strong> 100 gp</p>
</>};
const _bane_baldric = {title: "Bane Baldric", jsx: <><h2 id="magic-wondrous-bane_baldric-bane-baldric">Bane Baldric</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 220</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> chest; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This ornate sash of embroidered velvet stretches across the chest from shoulder to waist. If the wearer is an <Link to="/class/inquisitor">inquisitor</Link>, she is treated as five levels higher when using her bane and greater bane abilities. If the wearer is not an inquisitor, she gains the bane ability of a 5th-level inquisitor, but must first attune a light or one-handed melee weapon to the baldric by hanging it from the cloth for 24 hours, and can only use the bane ability with the attuned weapon. Attuning a new weapon to the baldric ends the attunement for the previous weapon.</p>
<h3 id="magic-wondrous-bane_baldric-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>, creator must be an inquisitor; <strong>Cost</strong> 5,000 gp</p>
</>};
const _blouse_of_the_boastful_bastard = {title: "Blouse of the Boastful Bastard", jsx: <><h2 id="magic-wondrous-blouse_of_the_boastful_bastard-blouse-of-the-boastful-bastard">Blouse of the Boastful Bastard</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 227</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>This stylish, purple silk shirt trimmed with designs embroidered in golden thread brings out reckless behavior in even the most conservative <Link to="/class/swashbuckler">swashbucklers</Link>. If the wearer has the panache class feature, when she takes damage from a successful critical hit, she regains 1 panache point. This shirt has no effect on someone who is not a panache user.</p>
<h3 id="magic-wondrous-blouse_of_the_boastful_bastard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _cackling_hags_blouse = {title: "Cackling Hag's Blouse", jsx: <><h2 id="magic-wondrous-cackling_hags_blouse-cackling-hags-blouse">Cackling Hag's Blouse</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 220</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This loose-fitting blouse is adorned with grotesque fetishes and trophies, granting the wearer a +2 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks. If the wearer is a <Link to="/class/witch">witch</Link>, she gains the <Link to="/hex/cackle">cackle</Link> hex. If the wearer already has the cackle hex, twice per day she can use her cackle ability as a swift action instead of a move action.</p>
<h3 id="magic-wondrous-cackling_hags_blouse-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hideous_laughter">hideous laughter</Link> or the cackle hex, creator must have 5 ranks in Intimidate; <strong>Cost</strong> 3,000 gp</p>
</>};
const _coat_of_mist = {title: "Coat of Mist", jsx: <><h2 id="magic-wondrous-coat_of_mist-coat-of-mist">Coat of Mist</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 251</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 8,400 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This gossamer jacket of gray-and-white silk allows the wearer to blend into mist and become almost invisible. She gains a +5 bonus on <Link to="/skill/stealth">Stealth</Link> checks in areas of fog, mist, smoke, or even heavy spray (such as from a waterfall or crashing surf). As a standard action, the wearer can gain total <Link to="/rule/concealment">concealment</Link> in such conditions, regardless of the distance between her and observers. Attacking does not end this total concealment, though the wearer must remain within or adjacent to the misty area to retain total concealment. The wearer can use the total concealment ability for a total of 5 rounds per day; these rounds need not be continuous.</p>
<p>Once per day, the wearer of a coat of mist can turn into mist, as per <em>gaseous form,</em> for up to 5 rounds.</p>
<h3 id="magic-wondrous-coat_of_mist-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gaseous_form">gaseous form</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>; <strong>Cost</strong> 4,200 gp</p>
</>};
const _coat_of_pockets = {title: "Coat of Pockets", jsx: <><h2 id="magic-wondrous-coat_of_pockets-coat-of-pockets">Coat of Pockets</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 244</Link>, <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 24</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> chest; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 7 lbs.</p>
<p>This black-and-gray wool coat sports over a dozen pockets on its front alone and even more line the insides. Interdimensional magic causes anything placed in one pocket to immediately appear in another randomly determined pocket. A character wearing this coat gains a +5 circumstance bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to hide a small object on her body. However, if a character wearing a coat of pockets places anything in one of the coat's pockets, she must spend a standard action to retrieve it (rather than a move action).</p>
<h3 id="magic-wondrous-coat_of_pockets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _coat_of_the_undercity = {title: "Coat of the Undercity", jsx: <><h2 id="magic-wondrous-coat_of_the_undercity-coat-of-the-undercity">Coat of the Undercity</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 244-245</Link><br/><strong>Aura</strong> faint transmutation (normal), moderate transmtuation (greater); <strong>CL</strong> 5th (normal), 9th (greater)<br/><strong>Slot</strong> chest; <strong>Price</strong> 7,500 gp (normal), 37,500 gp (greater); <strong>Weight</strong> 5 lbs.</p>
<p>This dirty, tattered-looking gray coat would not look out of place wrapped around a drifter or vagrant. When the wearer speaks the command word, the coat of the undercity shifts into a wave of clacking chitin, transforming the wearer into a <Link to="/monster/giant_cockroach">giant cockroach</Link> as <em>vermin shape I.</em> This transformation can occur only in an urban environment. The wearer can remain transformed for up to 5 minutes per day. This duration doesn't need to be consecutive, but must be used in 1-minute increments.</p>
<h3 id="magic-wondrous-coat_of_the_undercity-greater-coat-of-the-undercity">Greater Coat of the Undercity</h3>
<p>This coat functions much like the <em>coat of the undercity</em>, except the wearer can transform into a <Link to="/monster/venomroach">venomroach</Link> as if using <em>vermin shape II.</em></p>
<p>Alternatively, the wearer can take the form of a giant cockroach swarm. This swarm of Tiny vermin has a number of hit points equal to the wearer, uses the wearer's mental ability scores, skills, and saving throws, and gains a +2 resistance bonus on saving throws against mind-affecting effects instead of being immune to them. The swarm otherwise has the same movement, Armor Class, swarm traits, swarm damage, distraction and disease abilities as a typical <Link to="/monster/rat_swarm">rat swarm</Link> (including the abilities having a DC of 12). While in swarm form, the wearer can't use any of her activated abilities (extraordinary, supernatural, spell-like, or otherwise), cast spells, or use items, although she can end the effect as a standard action.</p>
<p>Either of these transformations can occur only in an urban environment. The wearer can remain transformed for up to 9 minutes per day. This duration doesn't need to be consecutive, but must be used in 1-minute increments.</p>
<h3 id="magic-wondrous-coat_of_the_undercity-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/vermin_shape_i">vermin shape I</Link> (normal) or <Link to="/spell/vermin_shape_ii">vermin shape II</Link> (greater); <strong>Cost</strong> 3,750 gp (normal), 18,750 gp (greater)</p>
</>};
const _corset_of_delicate_moves = {title: "Corset of Delicate Moves", jsx: <><h2 id="magic-wondrous-corset_of_delicate_moves-corset-of-delicate-moves">Corset of Delicate Moves</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 28</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>This tight-fitting garment of fine silk has thin bone ribbing sewn into it. Once per day as a move action, the wearer can take an additional swift action. This swift action can't be used to cast a spell or spell-like ability. The shirt must be worn for 24 hours before this ability can be used.</p>
<h3 id="magic-wondrous-corset_of_delicate_moves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _deadshot_vest = {title: "Deadshot Vest", jsx: <><h2 id="magic-wondrous-deadshot_vest-deadshot-vest">Deadshot Vest</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 220</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This rough vest of black snakeskin is decorated with a fringe of rawhide tassels, each knotted around a bit of bone or a small animal skull. A gunslinger with the <Link to="/deed/deadeye">deadeye</Link> deed reduces the grit point cost to use that deed by 1 (minimum 1 grit).</p>
<p>In addition, once per day when the wearer reduces a creature to 0 or fewer hit points with a firearm she can use <em>death knell</em> (Will DC 13 negates) against that target as a swift action. She does not have to touch the target to activate this ability, but her range increment penalty for shooting the target also applies to the saving throw DC of the <em>death knell</em> (for example, if the range increment penalty is -2, the DC is 11).</p>
<h3 id="magic-wondrous-deadshot_vest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_knell">death knell</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _death_wardens_bandolier = {title: "Death Warden's Bandolier", jsx: <><h2 id="magic-wondrous-death_wardens_bandolier-death-wardens-bandolier">Death Warden's Bandolier</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 150</Link><br/><strong>Aura</strong> moderate necromancy [good]; <strong>CL</strong> 11th<br/><strong>Slot</strong> chest; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This black leather bandolier is adorned with three brass bells of various sizes and shapes. Each bell can be rung to produce its own effect, or all can be rung at once to create a <em>death ward.</em> The death warden's bandolier can be used three times per day. A mythic creature can expend one use mythic power to use the bandolier without expending one of the item's daily uses.</p>
<p><strong className="hl">Undead Ward Bell:</strong> This long, thin bell produces a high-pitched, piercing ring. When it is rung as a standard action, it creates a 30-foot-burst aura that keeps out undead creatures. An undead creature can't enter the aura unless it succeeds at a DC 16 Will save. Undead within the aura take a -2 penalty on all attack rolls, combat maneuver checks, skill checks, and ability checks. The aura lasts for 5 rounds, but can be extended to 1 minute by expending one use of mythic power.</p>
<p><strong className="hl">Channeling Bell:</strong> This large, bulbous bell creates a rich, reverberating tone. When it's rung as part of the action to <Link to="/ability/channel_positive_energy">channel positive energy</Link> to harm undead, it can take the place of the holy symbol needed for channeling. When it's used in such a manner, undead creatures within the area take an additional 2 points of damage per each die of the channelled energy. The undead take this extra damage even if they succeed at their Will saving throws.</p>
<p><strong className="hl">Dirge Bell:</strong> The final, largest bell is cone-shaped. It creates a deep, bass chime. When rung, this bell creates an aura in a 30-foot-radius <Link to="/misc/burst">burst</Link> that causes incorporeal undead within it to become semi-physical for a period of time. While within the aura, undead take half damage from nonmagical attacks and full damage from magical attacks. The aura last for 5 rounds, but can be extended to 1 minute by expending one use of mythic power.</p>
<p><strong className="hl">All Bells At Once:</strong> When all the bells are rung at once, the wearer and all of her allies within 30 feet are protected as if they were subject to a <em>death ward</em> spell (CL 11th). By expending one use of mythic power, the wearer can increase the duration of this effect to 24 hours.</p>
<h3 id="magic-wondrous-death_wardens_bandolier-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/death_ward">death ward</Link>, <Link to="/spell/ghostbane_dirge">ghostbane dirge</Link>, <Link to="/spell/holy_smite">holy smite</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _endless_bandolier = {title: "Endless Bandolier", jsx: <><h2 id="magic-wondrous-endless_bandolier-endless-bandolier">Endless Bandolier</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 220</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> chest; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Small loops sewn into this bandolier look like they can hold twenty <Link to="/eq-weapon/alchemical_cartridge">alchemical cartridges</Link> (ammunition for a firearm), but due to a subtle bending of space can actually hold up to 60 cartridges. Additionally, the six thin pockets on the bandolier are extradimensional spaces meant to hold extra guns and gear. The four small pockets can each hold a one-handed firearm, 1 pound of ammunition, a <Link to="/eq-misc/powder_horn">powder horn</Link>, or a similarly sized object. The two large pockets are large enough to hold a two-handed firearm or a similarly sized object. The wearer can draw an item stored in the bandolier as easily as if from an ordinary ammunition pouch or holster. The bandolier weighs the same no matter what is placed inside it.</p>
<h3 id="magic-wondrous-endless_bandolier-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _jinx_eaters_shirt_tengu = {title: "Jinx Eater's Shirt (Tengu)", jsx: <><h2 id="magic-wondrous-jinx_eaters_shirt_tengu-jinx-eaters-shirt-tengu">Jinx Eater's Shirt (Tengu)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 232</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 8th<br/><strong>Slot</strong> chest; <strong>Price</strong> 22,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This shirt is stitched with dozens of symbols meant to attract bad luck, including bloodshot eyes and tengu skulls. Whenever an ally within 60 feet is subject to a curse, hex, jinx, or effect that would force her to roll multiple times for the same check and take the worse result, a <Link to="/race/tengu">tengu</Link> wearer can attempt to eat the effect as an immediate action. The wearer of the shirt attempts a caster level check with a DC of 11 + the effect originator's caster level (or HD for an ability that has no caster level). If the attempt is successful, the wearer suffers the effect instead of the original target, and the wearer gains a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to the effect's caster level or the target's HD, whichever is lower. These temporary hit points last for 1 minute. A jinx eater's shirt can successfully redirect an effect originating from a given creature only once each day, but otherwise it has no limitation on usage.</p>
<h3 id="magic-wondrous-jinx_eaters_shirt_tengu-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/remove_curse">remove curse</Link>, creator must be a tengu; <strong>Cost</strong> 11,300 gp</p>
</>};
const _manteau_of_the_mouse = {title: "Manteau of the Mouse", jsx: <><h2 id="magic-wondrous-manteau_of_the_mouse-manteau-of-the-mouse">Manteau of the Mouse</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 29</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> chest; <strong>Price</strong> 12,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This soft fur vest comes in a variety of shades of brown, black, and white. Any creature larger than the wearer takes a -1, -2, -4, or -8 penalty on Perception checks to notice the wearer, depending on whether it is one, two, three, or four or more size categories larger than the wearer, respectively. In addition, the wearer can use <em>beast shape III</em> once per day to transform into a <Link to="/monster/mouse">mouse</Link>.</p>
<h3 id="magic-wondrous-manteau_of_the_mouse-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_iii">beast shape III</Link>; <strong>Cost</strong> 6,250 gp</p>
</>};
const _mantle_of_faith = {title: "Mantle of Faith", jsx: <><h2 id="magic-wondrous-mantle_of_faith-mantle-of-faith">Mantle of Faith</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 221</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 522</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 20th<br/><strong>Slot</strong> chest; <strong>Price</strong> 76,000 gp; <strong>Weight</strong> -</p>
<p>This holy garment bears the varied religious icons and favored colors of a specific faith. When worn over normal clothing, grants damage reduction 5/evil to the character wearing it.</p>
<h3 id="magic-wondrous-mantle_of_faith-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Cost</strong> 38,000 gp</p>
</>};
const _mantle_of_immortality = {title: "Mantle of Immortality", jsx: <><h2 id="magic-wondrous-mantle_of_immortality-mantle-of-immortality">Mantle of Immortality</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 221</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> chest; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This elegant cape, trimmed in gold in a pattern resembling an ancient maze, forestalls the negative effects of aging. The wearer no longer suffers penalties to Strength, Dexterity, and Constitution from being of <Link to="/rule/age">middle age or older</Link>. The penalties return if the robe is removed (or its powers suppressed), and the sudden weight of years is so traumatic that the wearer must make a DC 20 Fortitude save or be <Link to="/misc/exhausted">exhausted</Link> for 24 hours. Donning the robe again removes the age penalties, but does not remove this exhaustion, which must pass on its own or be remedied with magic.</p>
<h3 id="magic-wondrous-mantle_of_immortality-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_age_resistance">greater age resistance</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _mantle_of_spell_resistance = {title: "Mantle of Spell Resistance", jsx: <><h2 id="magic-wondrous-mantle_of_spell_resistance-mantle-of-spell-resistance">Mantle of Spell Resistance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 221</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 522</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> chest; <strong>Price</strong> 90,000 gp; <strong>Weight</strong> -</p>
<p>This light mantle bears a variety of mysterious symbols. When worn over normal clothing or armor, this magical garment grants the wearer spell resistance 21.</p>
<h3 id="magic-wondrous-mantle_of_spell_resistance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spell_resistance">spell resistance</Link>; <strong>Cost</strong> 45,000 gp</p>
</>};
const _mantle_of_the_crusader_host = {title: "Mantle of the Crusader Host", jsx: <><h2 id="magic-wondrous-mantle_of_the_crusader_host-mantle-of-the-crusader-host">Mantle of the Crusader Host</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 62</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 20th<br/><strong>Slot</strong> chest; <strong>Price</strong> 95,000 gp; <strong>Weight</strong> -</p>
<p>This holy shroud is inscribed with hundreds of sacred passages in homage to the gods of good. It grants damage reduction 5/evil to the character wearing it. Against the attacks of creatures with the demon subtype, the damage reduction becomes 5/-. If the wearer is a <Link to="/class/paladin">paladin</Link>, the damage reduction changes to 5/- against the target of her smite class feature.</p>
<h3 id="magic-wondrous-mantle_of_the_crusader_host-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/stoneskin">stoneskin</Link>, creator must be good-aligned; <strong>Cost</strong> 47,500 gp</p>
</>};
const _mantle_of_the_faithful_vessel = {title: "Mantle of the Faithful Vessel", jsx: <><h2 id="magic-wondrous-mantle_of_the_faithful_vessel-mantle-of-the-faithful-vessel">Mantle of the Faithful Vessel</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 153</Link><br/><strong>Aura</strong> faint enchantment and necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This simple robe automatically shifts color and style to match the signature colors, fabrics, and symbols of the wearer's faith (if any) when she dons it.</p>
<p>When the wearer <Link to="/ability/channel_energy">channels energy</Link>, any creatures healed by the energy gain the benefits of <em>bless</em> for 1 minute, and any creatures harmed by the energy are subjected to <Link to="/spell/bane">bane</Link> (Will DC 11 negates) for 1 minute. The wearer adds her mythic tier to the damage dealt or healed when she channels energy.</p>
<h3 id="magic-wondrous-mantle_of_the_faithful_vessel-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/bless">bless</Link>, channel energy class feature; <strong>Cost</strong> 5,000 gp</p>
</>};
const _merciful_baldric = {title: "Merciful Baldric", jsx: <><h2 id="magic-wondrous-merciful_baldric-merciful-baldric">Merciful Baldric</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 221</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> chest; <strong>Price</strong> 60,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This sash of white silk embroidered with golden suns never tears, fades, or soils. Once per day, a paladin wearing this baldric can select three extra <Link to="/ability/mercies">mercies</Link> of her level or lower she does not already know and add them to the list of mercies she can use for the day. She has access to these mercies for 24 hours. When the wearer uses a mercy to remove a condition caused by a curse, disease, or poison, the mercy actually cures the source curse, disease, or poison rather than merely suppressing it for 1 hour.</p>
<h3 id="magic-wondrous-merciful_baldric-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/extra_mercy">Extra Mercy</Link>, <Link to="/spell/remove_disease">remove disease</Link>, <Link to="/spell/remove_curse">remove curse</Link>, creator must be lawful good; <strong>Cost</strong> 30,000 gp</p>
</>};
const _pickpockets_bandolier = {title: "Pickpocket's Bandolier", jsx: <><h2 id="magic-wondrous-pickpockets_bandolier-pickpockets-bandolier">Pickpocket's Bandolier</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 15</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 12,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Carefully embroidered black leather makes up this stylish bandolier, which can hold as many as 12 <Link to="/eq-weapon/dagger">daggers</Link>, <Link to="/eq-misc/vial">vials</Link>, or similarly shaped items. The wearer of a pickpocket's bandolier opposes <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks attempt against her with her own Sleight of Hand checks (instead of Perception). Additionally, as a swift action after succeeding at a Sleight of Hand check, the wearer can stuff stolen goods (of size Tiny or smaller) into one of the slots on the pickpocket's bandolier, making the purloined object appear to be a simple dagger. Only a careful examination of the bandolier reveals the true nature of items concealed in this manner.</p>
<h3 id="magic-wondrous-pickpockets_bandolier-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shrink_item">shrink item</Link>; <strong>Cost</strong> 6,250 gp</p>
</>};
const _poisoners_jacket_lesser = {title: "Poisoner's Jacket (Lesser)", jsx: <><h2 id="magic-wondrous-poisoners_jacket_lesser-poisoners-jacket-lesser">Poisoner's Jacket (Lesser)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 221, 222</Link><br/><strong>Aura</strong> faint conjuration and necromancy (lesser), strong conjuration and necromancy (greater); <strong>CL</strong> 5th (lesser), 15th (greater)<br/><strong>Slot</strong> chest; <strong>Price</strong> 12,000 gp (lesser), 58,000 gp (greater); <strong>Weight</strong> 3 lbs. (lesser) 4 lbs. (greater)</p>
<p><strong className="hl">Lesser:</strong> Three times per day, the wearer of this dark jacket can create a vial containing one dose of any poison from the Core Rulebook that costs 300 gp or less. The jacket's poison always looks like a murky amber fluid. This poison becomes inert after 1 hour.</p>
<p><strong className="hl">Greater:</strong> This jacket has the abilities of a <em>lesser poisoner's jacket,</em> and once per day the wearer can create a vial that reproduces the effect of any poison in the Core Rulebook that costs 4,000 gp or less. The jacket's poison always looks like a murky lime fluid. This poison becomes inert after 1 hour.</p>
<h3 id="magic-wondrous-poisoners_jacket_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/poison">poison</Link>, <Link to="/spell/minor_creation">minor creation</Link> (lesser) or <Link to="/spell/major_creation">major creation</Link> (greater); <strong>Cost</strong> 6,000 gp (lesser), 29,000 gp (greater)</p>
</>};
const _praenomen = {title: "Praenomen", jsx: <><h2 id="magic-wondrous-praenomen-praenomen">Praenomen</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 48</Link><br/><strong>Aura</strong> strong abjuration and enchantment; <strong>CL</strong> 11th<br/><strong>Slot</strong> chest; <strong>Price</strong> 64,200 gp; <strong>Weight</strong> 4 lbs.</p>
<p>The Praenomen is a two-part amulet, comprising an oval plate that covers the wearer's chest and a counterweight that hangs down the wearer's back, joined by chains. The front plate is inscribed with the cartouche of the pharaoh who is the Praenomen's master; the counterweight is shaped like a cobra to honor <Link to="/faith/wadjet">Wadjet</Link>, protector of Osirion and Osirion's pharaohs. The Praenomen was traditionally worn by a pharaoh's royal envoy to signify that the envoy acted in the pharaoh's name and was under her protection. It grants its benefits only to loyal subjects of its master - the pharaoh whose cartouche is inscribed upon it.</p>
<p>The Praenomen grants its wearer a +4 bonus on <Link to="/skill/diplomacy">Diplomacy</Link> and <Link to="/skill/intimidate">Intimidate</Link> checks. Once per day, the wearer can impose a <em>geas</em> on another creature, compelling the target to undertake a mission for the Praenomen's master. The Praenomen also shields its wearer and other faithful subjects of the pharaoh from the pharaoh's enemies. Its wearer gains a +2 deflection bonus to Armor Class, and three times per day, the wearer can activate the Praenomen to grant the benefits of <em>heroism</em> to all loyal subjects of its master within 30 feet.</p>
<p>The Praenomen can be rededicated to a new master by replacing the front plate and engraving the name of its new master on the cartouche, requiring a successful DC 21 <Link to="/skill/craft">Craft (jewelry)</Link> check.</p>
<h3 id="magic-wondrous-praenomen-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/geas_quest">geas/quest</Link>, <Link to="/spell/heroism">heroism</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>; <strong>Cost</strong> 32,100 gp</p>
</>};
const _prophets_pectoral = {title: "Prophet's Pectoral", jsx: <><h2 id="magic-wondrous-prophets_pectoral-prophets-pectoral">Prophet's Pectoral</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 222</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The sacred stones, graven star-patterns, and wisdom-writings of the ancients on this chestplate increase the wearer's chance of success with <Link to="/spell/augury">augury</Link>, <em>divination,</em> and <Link to="/spell/contact_other_plane">contact other plane</Link>. The wearer adds 1d6 to the d% roll each time she uses such a spell. When casting <Link to="/spell/commune">commune</Link> or <Link to="/spell/commune_with_nature">commune with nature</Link>, the wearer may ask one additional question or gain one additional piece of information.</p>
<h3 id="magic-wondrous-prophets_pectoral-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divination">divination</Link>, <Link to="/spell/guidance">guidance</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _quick_runners_shirt = {title: "Quick Runner's Shirt", jsx: <><h2 id="magic-wondrous-quick_runners_shirt-quick-runners-shirt">Quick Runner's Shirt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 222</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This shirt is made of light, gossamer-thin fabric embroidered with arrangements of winged feet. Once per day as a swift action, the wearer can take an additional move action to move and then immediately end his turn, losing any unspent actions. A character must wear this shirt continuously for 24 hours before he can activate this ability.</p>
<h3 id="magic-wondrous-quick_runners_shirt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _resplendent_uniform_coat = {title: "Resplendent Uniform Coat", jsx: <><h2 id="magic-wondrous-resplendent_uniform_coat-resplendent-uniform-coat">Resplendent Uniform Coat</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 222</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This woolen long coat is typically worn over light armor by military commanders. A <Link to="/class/cavalier">cavalier</Link> with the tactician ability may use that ability one additional time per day, and his tactician ability affects allies within 60 feet instead of 30 feet.</p>
<h3 id="magic-wondrous-resplendent_uniform_coat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/heroism">heroism</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _saddle_of_the_sky_river = {title: "Saddle of the Sky-River", jsx: <><h2 id="magic-wondrous-saddle_of_the_sky_river-saddle-of-the-sky-river">Saddle of the Sky-River</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 26</Link><br/><strong>Aura</strong> moderate evocation [water] and transmutation [air, water]; <strong>CL</strong> 7th<br/><strong>Slot</strong> chest; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This nacreous saddle is carved from giant mollusk shells, lashed with braided kelp, and designed to be worn by aquatic mounts. On command, an arcing torrent of water rises up from an existing body of water, allowing the mount to use its swim speed to move through the air. This functions as <em>air walk</em> and can be used a total of 7 minutes per day, usable in 1-minute increments. The arc of water trails behind the mount and rider and can be used by other swimming creatures to move through the air (Swim DC 15). When the effect ends, the suspended water disappears with a negligible amount of water falling on creatures underneath the path of the arc.</p>
<p>The sky-river created by the saddle does not harm creatures, though it does extinguish nonmagical fires in areas it overlaps with them. As a standard action, the rider can expend 2 minutes of the sky-river's duration to produce a <em>hydraulic torrent</em> with a CMB of +9.</p>
<h3 id="magic-wondrous-saddle_of_the_sky_river-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/air_walk">air walk</Link>, <Link to="/spell/hydraulic_torrent">hydraulic torrent</Link>, <Link to="/spell/water_walk">water walk</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _sash_of_the_war_champion = {title: "Sash of the War Champion", jsx: <><h2 id="magic-wondrous-sash_of_the_war_champion-sash-of-the-war-champion">Sash of the War Champion</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 222</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 309</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> chest; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This bright red strip of cloth, stitched with images of a cheering crowd throwing garlands toward a chariot, fits across the wearer's shoulders and then diagonally down his chest to reach his opposite hip. The wearer treats his fighter level as 4 higher than normal for the purpose of the armor training and bravery class features.</p>
<h3 id="magic-wondrous-sash_of_the_war_champion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _scaled_sash = {title: "Scaled Sash", jsx: <><h2 id="magic-wondrous-scaled_sash-scaled-sash">Scaled Sash</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 31</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> chest; <strong>Price</strong> 73,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Glittering with every movement, this sash is associated with a specific type of chromatic dragon. Three times per day, the wearer may convert all the damage dealt by a single attack with a melee, ranged, or natural weapon into the matching dragon's breath weapon damage type. The amount of damage dealt remains unaffected. The sash may be used after the attack's results are known, but must be declared before damage has been rolled. Attacks dealing any type of energy damage cannot be converted in this manner unless the energy type of the original damage is the same as that granted by the scaled sash. If the original attack would be affected by damage reduction, the converted damage is reduced as if it did not bypass the damage reduction, even if the target has no special defenses against the converted energy type.</p>
<p>For example, an archer wearing a black scaled sash makes a successful attack against a target with his longbow. Before rolling damage on the hit, he opts to use his sash to convert the damage dealt to acid damage. Damage is rolled normally, but deals acid damage instead of piercing damage. This includes damage dealt from additional effects such as <Link to="/ability/sneak_attack">sneak attack</Link>, <Link to="/ability/favored_enemy">favored enemy</Link>, and the <Link to="/magic-enh/bane">bane</Link> special weapon property.</p>
<h3 id="magic-wondrous-scaled_sash-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/form_of_the_dragon_i">form of the dragon I</Link>; <strong>Cost</strong> 36,500 gp</p>
</>};
const _scarves_of_the_stinging_dancer = {title: "Scarves of the Stinging Dancer", jsx: <><h2 id="magic-wondrous-scarves_of_the_stinging_dancer-scarves-of-the-stinging-dancer">Scarves of the Stinging Dancer</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 22</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>Made to enhance the most seductive Varisian dances, this collection of silken scarves is patterned in yellow and black. Varisian worshipers of <Link to="/faith/calistria">Calistria</Link> weave these scarves in the shadow of the Irespan, drawing upon the ancient evocation magic they call ragario to imbue the silk with vengeful energies. Scarves of the stinging dancer grant a +2 circumstance bonus on <Link to="/skill/perform">Perform (dance)</Link> checks, similar to that granted by <Link to="/eq-misc/masterwork_musical_instrument">masterwork musical instruments</Link>; this effect is nonmagical and cannot be dispelled.</p>
<p>To activate the scarves' magic, the wearer must succeed at a DC 20 Perform (dance) check. This check can be attempted as part of a move action in which the wearer moves no more than half his speed (including when he uses the <Link to="/skill/acrobatics">Acrobatics</Link> skill to avoid enemies) or as part of an attack action or full attack in which the wearer uses only a <Link to="/eq-weapon/bladed_scarf">bladed scarf</Link> to attack. Once activated, the scarves' magic lasts until the beginning of the wearer's next turn.</p>
<p>While the scarves' magic is active, whenever the wearer is successfully targeted by a harmful spell, hit by a melee or ranged attack, or touched against his will, the scarves lash out at the source of the attack (a creature if it's a spellcaster or an individual holding a magic item, or an object if the source is a trap or otherwise unattended) with a <em>magic missile</em> (CL 3rd). This <em>missile</em> takes the form of an angrily buzzing wasp. The scarves can be deactivated as a free action.</p>
<p>The scarves of the stinging dancer can create 50 missiles before losing their magic. At this point, the scarves can no longer cast <em>magic missile,</em> but they still provide the +2 bonus on Perform (dance) checks.</p>
<h3 id="magic-wondrous-scarves_of_the_stinging_dancer-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_missile">magic missile</Link>, creator must worship Calistria; <strong>Cost</strong> 4,500 gp</p>
</>};
const _shadow_jumpers_tunic = {title: "Shadow Jumper's Tunic", jsx: <><h2 id="magic-wondrous-shadow_jumpers_tunic-shadow-jumpers-tunic">Shadow Jumper's Tunic</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 27</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 16,200 gp; <strong>Weight</strong> -</p>
<p>This dark-gray tunic allows a character to make a single jump of up to 40 feet per day, or four jumps of 10 feet each per day. All jumps must begin and end in an area that has at least some <Link to="/rule/dim_light">dim light</Link>. If the wearer has at least 4 levels in the <Link to="/pclass/shadowdancer">shadowdancer</Link> prestige class, the tunic instead adds 40 feet to the total number of feet he can shadow jump in 1 day.</p>
<h3 id="magic-wondrous-shadow_jumpers_tunic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimension_door">dimension door</Link>; <strong>Cost</strong> 8,100 gp</p>
</>};
const _shadowbond_tunic = {title: "Shadowbond Tunic", jsx: <><h2 id="magic-wondrous-shadowbond_tunic-shadowbond-tunic">Shadowbond Tunic</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 26</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This black linen tunic has simple brass buttons. Once per day, the wielder can attune the garment to one ally by standing for 1 minute in a position in which both the wielder's and his ally's shadows overlap. For the next 24 hours, whenever the wielder is adjacent to that ally and that ally takes damage, the wielder can sacrifice up to 10 hit points to prevent an equal amount of damage done to the ally. This damage cannot be reduced or redirected, and if the wielder is incapable of sacrificing hit points, the damage to the ally cannot be prevented. If the vest is removed before its duration ends, the connection between the wielder and ally is lost and the vest is powerless until 24 hours have passed since its last attunement.</p>
<h3 id="magic-wondrous-shadowbond_tunic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield_other">shield other</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _shirt_of_immolation = {title: "Shirt of Immolation", jsx: <><h2 id="magic-wondrous-shirt_of_immolation-shirt-of-immolation">Shirt of Immolation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 222</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> chest; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Whenever the wearer is <Link to="/rule/grappling">grappling</Link> (whether on the offense or defense), this shirt automatically bursts into flame, dealing 1d6+10 points of fire damage every round to anyone grappling the wearer. The flames do not harm the wearer and last one round (though it continues to burn if the wearer is still grappling after one round). The shirt burns for a maximum of 10 rounds per day. These rounds do not need to be consecutive.</p>
<h3 id="magic-wondrous-shirt_of_immolation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fire_shield">fire shield</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _shirt_of_inconspicuousness_halfling = {title: "Shirt of Inconspicuousness (Halfling)", jsx: <><h2 id="magic-wondrous-shirt_of_inconspicuousness_halfling-shirt-of-inconspicuousness-halfling">Shirt of Inconspicuousness (Halfling)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 234</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> chest; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This drab shirt helps its wearer blend in with the background even while accomplishing important things, the better to avoid any trouble that results. The wearer is visible, but easy to overlook, and observers explain away or forget her presence. An observer must succeed at a DC 11 Will save to notice the wearer; a success renders that observer immune to the shirt's effect for 24 hours. An observer automatically notices the wearer if the wearer attacks that observer or an ally of that observer.</p>
<h3 id="magic-wondrous-shirt_of_inconspicuousness_halfling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/overlook">overlook</Link>, creator must be a <Link to="/race/halfling">halfling</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _silent_blade_vest = {title: "Silent Blade Vest", jsx: <><h2 id="magic-wondrous-silent_blade_vest-silent-blade-vest">Silent Blade Vest</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 269</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 4,300 gp; <strong>Weight</strong> -</p>
<p>This dapper, halfling-sized gray vest has dull black buttons and several hidden pockets. Concealed under the vest's lapel is a symbol of a black dagger with a white circle on the blade near the hilt. Followers of Thamir Gixx use this kind of vest or similar garments to discreetly indicate their allegiance to other members of the Silent Blade's church. The wearer gains a +5 competence bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks. When adjacent to an ally using <Link to="/skill/stealth">Stealth</Link>, the wearer gains a +5 competence bonus on Stealth checks.</p>
<h3 id="magic-wondrous-silent_blade_vest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>, creator must have 5 ranks in Sleight of Hand; <strong>Cost</strong> 2,150 gp</p>
</>};
const _sipping_jacket = {title: "Sipping Jacket", jsx: <><h2 id="magic-wondrous-sipping_jacket-sipping-jacket">Sipping Jacket</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 222</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> chest; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Absorbent fibers line this heavy canvas coat. Once per day as a standard action, the wearer can pour a potion onto this lining, suffusing it into the coat. If the potion has an instantaneous duration, the wearer can activate the coat as a swift action to consume the potion. If the potion's duration is measured in rounds, the wearer can activate the coat as a swift action to gain the potion's benefits for 1 round, repeating as desired each round until the potion's entire duration has been used. These rounds do not need to be consecutive. The coat absorbs only potions with instantaneous or round-based durations, and only those which affect creatures (for example, it does not work on oils). Once the coat absorbs a potion, the potion cannot be retrieved from it, only used as described above. The absorbed potion loses its powers after 24 hours, even if unused.</p>
<h3 id="magic-wondrous-sipping_jacket-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/amplify_elixir">amplify elixir</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _snakeskin_tunic = {title: "Snakeskin Tunic", jsx: <><h2 id="magic-wondrous-snakeskin_tunic-snakeskin-tunic">Snakeskin Tunic</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 222</Link>, <Link to="/source/pathfinder_2_the_skinsaw_murders">Pathfinder #2: The Skinsaw Murders pg. 54</Link>, <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 426</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> chest; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A snakeskin tunic is a tight, form-fitting shirt crafted from the scales of a giant snake. When worn, it grants a +1 armor bonus to AC, a +2 enhancement bonus to Dexterity, and a +2 resistance bonus on saving throws against poison.</p>
<h3 id="magic-wondrous-snakeskin_tunic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/delay_poison">delay poison</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _spectral_shroud = {title: "Spectral Shroud", jsx: <><h2 id="magic-wondrous-spectral_shroud-spectral-shroud">Spectral Shroud</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 222</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 26,000 gp; <strong>Weight</strong> -</p>
<p>This thin, bleached cloth covers the wearer's entire torso. Some also cover the wearer's face, but don't interfere with the wearer's vision. The morbid burial shroud grants the wearer some affinity with the spectral dead. The wearer can discern invisible or ethereal creatures as though using <em>see invisibility.</em> Once per day, the wearer can become incorporeal for 10 rounds and gain a fly speed equal to half his base speed with perfect maneuverability. The wearer can't attack while incorporeal, but can dismiss the effect as a move action.</p>
<h3 id="magic-wondrous-spectral_shroud-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hide_from_undead">hide from undead</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 13,000 gp</p>
</>};
const _swordmasters_shirt = {title: "Swordmaster's Shirt", jsx: <><h2 id="magic-wondrous-swordmasters_shirt-swordmasters-shirt">Swordmaster's Shirt</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This stylish silk shirt has a loose and flowing fit except for the sleeves, which cling snugly to the wearer's arms from elbow to wrist. The sleeves guide the wearer's attacks to take advantage of brief gaps in a foe's defenses. Five times per day, the wearer can make a lunging melee maneuver and extend his reach by 5 feet for a single melee attack. If the wearer has the <Link to="/feat/lunge">Lunge</Link> feat, he can instead use that feat five times per day without taking the normal -2 penalty.</p>
<h3 id="magic-wondrous-swordmasters_shirt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, Lunge, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _tunic_of_careful_casting = {title: "Tunic of Careful Casting", jsx: <><h2 id="magic-wondrous-tunic_of_careful_casting-tunic-of-careful-casting">Tunic of Careful Casting</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 223</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This woolen garment is decorated with a pattern of linked chains embroidered in silver and black thread. It assists the wearer with maintaining focus during spellcasting, granting a +2 bonus on <Link to="/rule/concentration">concentration</Link> checks.</p>
<h3 id="magic-wondrous-tunic_of_careful_casting-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/combat_casting">Combat Casting</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _tunic_of_deadly_might = {title: "Tunic of Deadly Might", jsx: <><h2 id="magic-wondrous-tunic_of_deadly_might-tunic-of-deadly-might">Tunic of Deadly Might</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 223</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This tunic is crafted from golden thread, and has silver-hemmed sleeves. The wearer gains a +2 bonus to Combat Maneuver Defense against <Link to="/rule/disarm">disarm</Link> and <Link to="/rule/sunder">sunder</Link> combat maneuvers. If the wearer is a <Link to="/class/samurai">samurai</Link>, twice per day as a swift action he can apply the effects of the <Link to="/magic-enh/thundering">thundering</Link> weapon special ability to a successful critical hit against the target of his challenge.</p>
<h3 id="magic-wondrous-tunic_of_deadly_might-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blindness_deafness">blindness/deafness</Link>, <Link to="/spell/mage_armor">mage armor</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _unfettered_shirt = {title: "Unfettered Shirt", jsx: <><h2 id="magic-wondrous-unfettered_shirt-unfettered-shirt">Unfettered Shirt</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 223</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> chest; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This loose, often ruffled, shirt is cut in a style designed to avoid hindering its wearer's movement.</p>
<p>Once per day on command, the wearer can gain the benefits of <em>freedom of movement</em> for 10 minutes.</p>
<h3 id="magic-wondrous-unfettered_shirt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _versatile_vest = {title: "Versatile Vest", jsx: <><h2 id="magic-wondrous-versatile_vest-versatile-vest">Versatile Vest</h2>
<p><strong>Sources</strong> <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 56</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> chest; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This sturdy vest stays dry and spotless in the worst of conditions. You can secure up to six objects (weighing up to 1 pound each) to the vest by holding them to it and speaking a command word. You can retrieve any of these items as a move action.</p>
<p>In addition, the vest has four large pockets, each capable of holding as much as 1/2 cubic foot in volume or 5 pounds in weight, and weighing only 1 pound when full. When closed, the pockets are proof against water and the elements. The first pocket contains 1 day's worth of <Link to="/eq-misc/trail_rations">trail rations</Link>, a quart of water in a <Link to="/eq-misc/waterskin">waterskin</Link>, two <Link to="/eq-misc/candle">candles</Link>, and a <Link to="/eq-misc/tindertwig">tindertwig</Link>. The vest recreates these items if the first pocket is left empty for 3 days.</p>
<h3 id="magic-wondrous-versatile_vest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_food_and_water">create food and water</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _vest_of_escape = {title: "Vest of Escape", jsx: <><h2 id="magic-wondrous-vest_of_escape-vest-of-escape">Vest of Escape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 223</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 532</Link><br/><strong>Aura</strong> faint conjuration and transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> chest; <strong>Price</strong> 5,200 gp; <strong>Weight</strong> -</p>
<p>This simple silk vest looks nondescript, but is actually studded with numerous secret pockets sewn into its lining. Hidden inside these are magic lockpicks that provide a +4 competence bonus on <Link to="/skill/disable_device">Disable Device</Link> checks. The vest also grants its wearer a +6 competence bonus on <Link to="/skill/escape_artist">Escape Artist</Link> checks.</p>
<h3 id="magic-wondrous-vest_of_escape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/knock">knock</Link>, <Link to="/spell/grease">grease</Link>; <strong>Cost</strong> 2,600 gp</p>
</>};
const _vest_of_resonating_foritude = {title: "Vest of Resonating Foritude", jsx: <><h2 id="magic-wondrous-vest_of_resonating_foritude-vest-of-resonating-foritude">Vest of Resonating Foritude</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 31</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> chest; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> -</p>
<p>This magical cloth vest is made from rich green cloth that is typically a blend of silk and cotton. It has a high collar that is stitched with gold thread forming elaborate, overlapping geometric patterns. This vest reduces the potency of poisons that affect the wearer. As a swift action when the wearer is exposed to a poison, she can tap the vest, expending 1 charge, to gain a +2 bonus on her next Fortitude saving throw against the poison. Additionally, if the wearer is affected with a poison that requires two saves to cure, she can tap the vest a second time, expending another charge, to use her next successful saving throw result as the result for the second save as well. The vest contains 5 charges that recharge daily.</p>
<h3 id="magic-wondrous-vest_of_resonating_foritude-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/delay_poison">delay poison</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _vest_of_shed_servitude = {title: "Vest of Shed Servitude", jsx: <><h2 id="magic-wondrous-vest_of_shed_servitude-vest-of-shed-servitude">Vest of Shed Servitude</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 31</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> chest; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This pale leather vest's surface is decorated with a web of vein-like ridges. Once per day as an immediate action when you are struck by a critical hit or <Link to="/ability/sneak_attack">sneak attack</Link>, your shed blood or flesh coagulates into a short-lived guardian that appears in any adjacent square and follows your commands. This guardian has all the abilities of a <Link to="/monster/homunculus">homunculus</Link>, except that its type is undead. If the triggering attack inflicted <Link to="/rule/bleed">bleed</Link> damage, the homunculus also gains the <Link to="/template/giant">giant</Link> simple template. This homunculus lasts for 7 rounds before melting, and it doesn't deal damage to you when it's destroyed.</p>
<h3 id="magic-wondrous-vest_of_shed_servitude-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_dead">animate dead</Link>, <Link to="/spell/mirror_image">mirror image</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _vest_of_stable_mutation = {title: "Vest of Stable Mutation", jsx: <><h2 id="magic-wondrous-vest_of_stable_mutation-vest-of-stable-mutation">Vest of Stable Mutation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 223</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 8th<br/><strong>Slot</strong> chest; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This leather vest is fitted with a number of pockets that are useful for storing the ingredients necessary for alchemical tinkering. The main ability of this vest, however, is to lessen the debilitating effects of an <Link to="/class/alchemist">alchemist's</Link> mutagen. While under the effect of any type of mutagen, the wearer takes no penalty to mental ability scores from that mutagen.</p>
<h3 id="magic-wondrous-vest_of_stable_mutation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>, creator must be an alchemist; <strong>Cost</strong> 10,000 gp</p>
</>};
const _vest_of_surgery = {title: "Vest of Surgery", jsx: <><h2 id="magic-wondrous-vest_of_surgery-vest-of-surgery">Vest of Surgery</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 223</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This emerald vest has four prominent and bulging pockets along its front. The wearer is always treated as if using a <Link to="/eq-misc/healers_kit">healer's kit</Link> when making <Link to="/skill/heal">Heal</Link> checks. Once per day, the wearer can make a DC 20 Heal check as if attempting to treat deadly wounds. If the check is successful, it cures 1d4 points of <Link to="/rule/ability_damage">ability damage</Link> instead of hit point damage.</p>
<h3 id="magic-wondrous-vest_of_surgery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>, creator must have 5 ranks in Heal; <strong>Cost</strong> 1,500 gp</p>
</>};
const _vest_of_the_cockroach = {title: "Vest of the Cockroach", jsx: <><h2 id="magic-wondrous-vest_of_the_cockroach-vest-of-the-cockroach">Vest of the Cockroach</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 223</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> chest; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This padded and slightly bulky vest, made from red-brown cloth, causes its wearer to feel vaguely uncomfortable whenever she is lying <Link to="/rule/prone">prone</Link>. If the wearer is a rogue, she gains the <Link to="/talent/resiliency">resiliency</Link> rogue talent. If she already has this talent, activating the talent grants her 2 hit points per rogue level instead of 1.</p>
<h3 id="magic-wondrous-vest_of_the_cockroach-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/false_life">false life</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _vest_of_the_deep = {title: "Vest of the Deep", jsx: <><h2 id="magic-wondrous-vest_of_the_deep-vest-of-the-deep">Vest of the Deep</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_99_dance_of_the_damned">Pathfinder #99: Dance of the Damned pg. 16</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> chest; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>A vest of the deep creates a constant shell of magical energy that protects the wearer from extreme environmental pressure, such as that <Link to="/rule/water_dangers">inflicted by water</Link> at a depth of over 100 feet. It does not provide any protection from constriction or other forms of direct crushing damage, nor does it grant water breathing.</p>
<h3 id="magic-wondrous-vest_of_the_deep-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/life_bubble">life bubble</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _vest_of_the_vengeful_tracker = {title: "Vest of the Vengeful Tracker", jsx: <><h2 id="magic-wondrous-vest_of_the_vengeful_tracker-vest-of-the-vengeful-tracker">Vest of the Vengeful Tracker</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 223</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> chest; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This green-and-brown vest has pockets sewn along its length, each with a tiny lodestone button. The wearer feels a surge of heroism when she tracks down prey. She gains a +1 morale bonus on the first attack and damage rolls made with weapons against creatures she has successfully tracked within the previous 24 hours. If her target is <Link to="/rule/flat_footed">flat-footed</Link>, this bonus increases to +2. If her target is also her <Link to="/ability/favored_enemy">favored enemy</Link>, she gains a +4 bonus on critical hit confirmation rolls against the target.</p>
<h3 id="magic-wondrous-vest_of_the_vengeful_tracker-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/commune_with_nature">commune with nature</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
